/* AUTO-GENERATED — Kansas Special Requirements bank (lazy-loaded by the CDL app). */
window.STATE_SPECIAL = window.STATE_SPECIAL || {};
window.STATE_SPECIAL["KS"] = {"code":"KS","name":"Kansas","agency":"Kansas DOR","agencyShort":"DOR","handbook":"https://www.ksrevenue.gov/pdf/cdlhandbook.pdf","links":{},"en":[{"q":"On Kansas highways, what is the maximum total outside width of a vehicle or its load without a permit?","options":["8 feet (96 inches)","8 1/2 feet (102 inches)","9 feet (108 inches)","10 feet (120 inches)"],"answer":1,"explanation":"K.S.A. 8-1902 limits the total outside width of any vehicle or its load to 8 1/2 feet (102 inches). The Kansas CDL handbook and Kansas Highway Patrol state the same standard width limit.","handbook":"","hbref":""},{"q":"What is the general maximum height of a vehicle, including its load, on Kansas highways?","options":["13 feet 6 inches","14 feet","14 feet 6 inches","15 feet"],"answer":1,"explanation":"K.S.A. 8-1904 sets the maximum vehicle height (including load) at 14 feet. The Kansas Highway Patrol confirms 14 feet as the legal height limit.","handbook":"","hbref":""},{"q":"Kansas allows one type of load to exceed the 14-foot height limit and be secured up to 14 1/2 feet. Which load is it?","options":["Baled cotton","Cylindrically shaped hay bales","Construction steel beams","Shipping containers"],"answer":1,"explanation":"K.S.A. 8-1904 permits a vehicle transporting cylindrically shaped hay bales to be loaded up to 14 1/2 feet; the operator is liable for any damage if the load strikes an overpass.","handbook":"","hbref":""},{"q":"What is the maximum length of a single motor vehicle (such as a straight truck), including its load, on Kansas highways?","options":["40 feet","45 feet","48 feet","53 feet"],"answer":1,"explanation":"K.S.A. 8-1904 limits a single motor vehicle, including the load, to 45 feet extreme overall dimension.","handbook":"","hbref":""},{"q":"In a truck-tractor and semitrailer combination, what is the maximum length of the semitrailer permitted in Kansas?","options":["48 feet","53 feet","57 feet","59 1/2 feet"],"answer":3,"explanation":"K.S.A. 8-1904 provides that a semitrailer operated in combination with a truck-tractor shall not exceed 59 1/2 feet in length.","handbook":"","hbref":""},{"q":"What is the maximum gross weight allowed on any single axle of a vehicle on Kansas highways without a permit?","options":["18,000 pounds","20,000 pounds","22,000 pounds","24,000 pounds"],"answer":1,"explanation":"K.S.A. 8-1908 limits the gross weight on any one axle to 20,000 pounds (and any one wheel to 10,000 pounds).","handbook":"","hbref":""},{"q":"What is the maximum gross weight allowed on a tandem axle group in Kansas without a permit?","options":["32,000 pounds","34,000 pounds","36,000 pounds","40,000 pounds"],"answer":1,"explanation":"K.S.A. 8-1908 limits the gross weight on tandem axles to 34,000 pounds, matching the federal standard.","handbook":"","hbref":""},{"q":"What is the maximum gross weight upon any single wheel of a vehicle under Kansas law?","options":["8,000 pounds","10,000 pounds","12,000 pounds","17,000 pounds"],"answer":1,"explanation":"K.S.A. 8-1908 states the gross weight upon any wheel of a vehicle shall not exceed 10,000 pounds.","handbook":"","hbref":""},{"q":"On the Interstate highway system in Kansas, what is the maximum gross vehicle weight allowed without a permit?","options":["73,280 pounds","80,000 pounds","85,500 pounds","90,000 pounds"],"answer":1,"explanation":"Under K.S.A. 8-1909, the axle-spacing weight table may not authorize more than 80,000 pounds gross on the Interstate system, consistent with federal law.","handbook":"","hbref":""},{"q":"On Kansas state and U.S. highways NOT part of the Interstate system, the axle-spacing table can allow a gross weight up to what maximum?","options":["80,000 pounds","85,500 pounds","90,000 pounds","94,000 pounds"],"answer":1,"explanation":"K.S.A. 8-1909's axle-spacing table allows up to 85,500 pounds gross on Kansas and U.S. (non-Interstate) highways, higher than the 80,000-pound Interstate cap.","handbook":"","hbref":""},{"q":"Kansas determines the maximum gross weight on a group of two or more consecutive axles primarily by using what method?","options":["A flat per-trailer weight cap","An axle-spacing weight table (the bridge formula)","The number of tires only","The registered weight of the truck only"],"answer":1,"explanation":"K.S.A. 8-1909 uses an axle-spacing weight table based on the distance between axles and number of axles, the Kansas form of the federal bridge formula, to set the maximum weight on a group of consecutive axles.","handbook":"","hbref":""},{"q":"Under the Kansas bridge/axle-spacing concept, how can a vehicle legally carry more total weight on a group of axles?","options":["By increasing tire pressure","By spreading the axles farther apart and adding axles","By reducing the trailer length","By lowering the trailer floor height"],"answer":1,"explanation":"The K.S.A. 8-1909 axle-spacing table (bridge formula) allows greater total weight as the distance between axles increases and the number of axles grows, to protect bridges.","handbook":"","hbref":""},{"q":"A load that exceeds Kansas legal size or weight limits and CANNOT be reduced (a nondivisible load) requires what before it may travel?","options":["Nothing, if traveling in daylight","An oversize/overweight permit from KDOT","A note from the shipper","A federal DOT waiver only"],"answer":1,"explanation":"Kansas DOT requires an oversize/overweight permit for nondivisible loads exceeding legal limits; permits are obtained through KDOT's K-TRIPS system.","handbook":"","hbref":""},{"q":"Which Kansas system is used to apply for and obtain oversize/overweight permits?","options":["IRP Online","K-TRIPS (Kansas Truck Routing and Intelligent Permitting System)","IFTA Web","CDLIS"],"answer":1,"explanation":"KDOT issues oversize/overweight permits through K-TRIPS (Kansas Truck Routing and Intelligent Permitting System); applicants register and submit vehicle, load, and route details online.","handbook":"","hbref":""},{"q":"A standard single-trip Kansas oversize/overweight permit is generally valid for how long?","options":["24 hours","3 days","7 days","30 days"],"answer":2,"explanation":"KDOT single-trip oversize/overweight permits are generally valid for seven days from the issue date.","handbook":"","hbref":""},{"q":"Movement of an oversize permitted load in Kansas is generally restricted to what time of day?","options":["Any time, day or night","One-half hour before sunrise to one-half hour after sunset","Only between midnight and 6 a.m.","Only on weekdays during business hours"],"answer":1,"explanation":"KDOT permit conditions generally restrict oversize load movement to one-half hour before sunrise to one-half hour after sunset, including weekends and holidays, with exceptions noted on the permit.","handbook":"","hbref":""},{"q":"At what width does a vehicle or load become 'oversize' in Kansas, requiring a permit?","options":["Over 8 feet","Over 8 feet 6 inches","Over 10 feet","Over 12 feet"],"answer":1,"explanation":"Because K.S.A. 8-1902 sets the legal width at 8 1/2 feet (8 feet 6 inches), any vehicle or load wider than 8 feet 6 inches is oversize and requires a KDOT permit.","handbook":"","hbref":""},{"q":"Under a routine Kansas overweight permit (KAR 36-1-37), what is the maximum permitted weight on a single axle?","options":["20,000 pounds","22,000 pounds","24,000 pounds","26,000 pounds"],"answer":1,"explanation":"Kansas overweight permit limits under KAR 36-1-37 raise the single non-drive axle maximum to 22,000 pounds (and tandem axles to 45,000 pounds), above the 20,000-pound legal limit.","handbook":"","hbref":""},{"q":"Kansas offers a special annual overweight DIVISIBLE-load permit for agricultural commodities, supplies, and biofuels. What is its maximum gross weight, and where is it NOT allowed?","options":["80,000 pounds; not on county roads","90,000 pounds; not on the Interstate system","100,000 pounds; not within cities","85,500 pounds; not on bridges"],"answer":1,"explanation":"Kansas allows an annual overweight divisible-load permit for agricultural inputs, commodities, livestock, and biofuels up to 90,000 pounds with at least six axles, and such vehicles may not operate on the Interstate system.","handbook":"","hbref":""},{"q":"In Kansas, a vehicle operating in excess of 85,500 pounds is prohibited from traveling under what condition?","options":["When it is raining","When the highway surface has ice, snowpack, or drifting snow","During the harvest season","Within 50 miles of a city"],"answer":1,"explanation":"K.S.A. 8-1919 prohibits vehicles operating in excess of 85,500 pounds from traveling when the highway surface has ice, snowpack, or drifting snow.","handbook":"","hbref":""},{"q":"In Kansas, which CDL class is required to operate a single vehicle with a gross vehicle weight rating of 26,001 pounds or more, where any towed unit does NOT exceed 10,000 pounds GVWR?","options":["Class A","Class B","Class C","Class D"],"answer":1,"explanation":"Kansas defines a Class B CDL as any single vehicle with a GVWR of 26,001 lbs or more, or such a vehicle towing a unit that does not exceed 10,000 lbs GVWR. Source: Kansas CDL Manual (KDOR) and K.S.A. 8-2,128.","handbook":"","hbref":""},{"q":"What is the minimum gross combination weight rating that defines a Kansas Class A CDL when the towed unit exceeds 10,000 pounds?","options":["18,000 pounds","26,001 pounds","33,000 pounds","10,001 pounds"],"answer":1,"explanation":"A Kansas Class A CDL covers any combination of vehicles with a GCWR of 26,001 lbs or more, provided the towed unit(s) has a GVWR of more than 10,000 lbs. Source: Kansas CDL Manual (KDOR); K.S.A. 8-2,128.","handbook":"","hbref":""},{"q":"A driver hauls a placardable quantity of hazardous materials in a van with a GVWR under 26,001 pounds. Which Kansas CDL class and endorsement combination applies?","options":["Class A with no endorsement","Class B with N endorsement","Class C with H endorsement","Class D with P endorsement"],"answer":2,"explanation":"If a vehicle does not meet the Class A or B weight definitions but transports hazardous materials in placardable quantities (or carries 16+ passengers), Kansas requires a Class C CDL, plus the H endorsement for hazmat. Source: Kansas CDL Manual (KDOR); 49 CFR 383.91.","handbook":"","hbref":""},{"q":"On a Kansas CDL, what does the 'N' endorsement authorize the driver to do?","options":["Operate tank vehicles","Transport hazardous materials","Tow double and triple trailers","Drive a school bus"],"answer":0,"explanation":"In Kansas the 'N' endorsement permits operation of tank vehicles. Source: K.S.A. 8-2,135; Kansas CDL Manual (KDOR).","handbook":"","hbref":""},{"q":"Which endorsement code on a Kansas CDL is required to pull double and triple trailers?","options":["P","H","T","S"],"answer":2,"explanation":"The 'T' endorsement authorizes towing double and triple trailers; it is obtained by passing a knowledge test only (no separate skills test). Source: K.S.A. 8-2,135; Kansas CDL Manual (KDOR).","handbook":"","hbref":""},{"q":"A vehicle is designed to transport 16 or more people, including the driver. Which Kansas CDL endorsement is required (absent the school bus exception)?","options":["N (tanker)","P (passenger)","T (doubles/triples)","H (hazmat)"],"answer":1,"explanation":"The 'P' (passenger) endorsement is required for vehicles designed to carry 16 or more people including the driver, and requires both a knowledge and a skills test. Source: Kansas CDL Manual (KDOR); 49 CFR 383.93.","handbook":"","hbref":""},{"q":"To obtain the School Bus (S) endorsement in Kansas, which other endorsement must the driver also hold?","options":["H (hazardous materials)","N (tank vehicle)","P (passenger)","T (doubles/triples)"],"answer":2,"explanation":"Kansas requires drivers to first hold the 'P' (passenger) endorsement before adding the 'S' (school bus) endorsement, which also requires passing additional knowledge and skills tests. Source: Kansas CDL Manual (KDOR); 49 CFR 383.93.","handbook":"","hbref":""},{"q":"Before Kansas can issue the Hazardous Materials (H) endorsement, the applicant must complete which additional federal requirement?","options":["A TSA security threat assessment (background check)","A vision waiver from FMCSA","A 30-day road apprenticeship","An air brake skills retest"],"answer":0,"explanation":"The H (hazmat) endorsement requires passing a knowledge test AND a TSA Security Threat Assessment, which includes fingerprinting and a background check, before Kansas will issue it. Source: Kansas CDL Manual (KDOR); 49 CFR 383.71/1572.","handbook":"","hbref":""},{"q":"What is the minimum age to obtain a Kansas CDL restricted to intrastate (within-Kansas) driving only?","options":["16 years old","17 years old","18 years old","21 years old"],"answer":2,"explanation":"Kansas requires a driver to be at least 18 years old to obtain a CDL for intrastate operation only. Source: Kansas CDL Manual (KDOR); K.S.A. 8-2,129.","handbook":"","hbref":""},{"q":"What is the minimum age to obtain a Kansas CDL for interstate driving (across state lines) or to transport hazardous materials?","options":["18 years old","19 years old","20 years old","21 years old"],"answer":3,"explanation":"A driver must be at least 21 years old to drive a CMV in interstate commerce, transport hazardous materials, or transport passengers across state lines. Source: Kansas CDL Manual (KDOR); 49 CFR 391.11.","handbook":"","hbref":""},{"q":"After a Commercial Learner's Permit (CLP) is first issued in Kansas, how long must the applicant hold it before being eligible to take the CDL skills test?","options":["At least 7 days","At least 14 days","At least 30 days","At least 60 days"],"answer":1,"explanation":"Federal rule adopted by Kansas: a CLP holder is not eligible to take the CDL skills test until the permit has been held for a minimum of 14 days. Source: Kansas CDL Manual (KDOR); 49 CFR 383.25.","handbook":"","hbref":""},{"q":"What must a Kansas CLP holder do while driving a commercial motor vehicle for practice?","options":["Drive only between sunrise and sunset","Be accompanied by a CDL holder seated in the front seat beside them","Limit driving to a 25-mile radius of home","Carry no cargo of any kind"],"answer":1,"explanation":"A Kansas CLP holder may operate a CMV only when accompanied by a person who holds a valid CDL for the vehicle type, who must be seated in the front seat next to the driver. Source: Kansas CDL Manual (KDOR); 49 CFR 383.25.","handbook":"","hbref":""},{"q":"Under federal standards adopted by Kansas, a Commercial Learner's Permit must NOT be valid for more than what maximum period without re-testing?","options":["90 days","6 months","1 year","5 years"],"answer":2,"explanation":"A CLP may be issued for no more than one year from initial issuance without requiring the applicant to retake the knowledge tests. Source: Kansas CDL Manual (KDOR); 49 CFR 383.25.","handbook":"","hbref":""},{"q":"Which set of documents must a Kansas CDL applicant present to the Division of Vehicles when applying?","options":["Proof of identity, Social Security number, Kansas residency, and lawful presence","Only a Social Security card and a birth certificate","A passport and a vehicle registration","Proof of employment and a hazmat permit"],"answer":0,"explanation":"The Kansas Department of Revenue, Division of Vehicles requires applicants to prove identity, provide their Social Security number, and show proof of Kansas residency and lawful (legal) presence. Source: Kansas Department of Revenue, Division of Vehicles (ksrevenue.gov).","handbook":"","hbref":""},{"q":"Entry-Level Driver Training (ELDT) required by Kansas for first-time Class A/B applicants must be provided by a training entity that is:","options":["Approved by the local school district","Listed on the FMCSA Training Provider Registry","Certified by the Kansas Highway Patrol","Accredited by the U.S. Department of Education"],"answer":1,"explanation":"Since February 7, 2022, ELDT must be completed through a provider listed on the FMCSA Training Provider Registry (TPR) before Kansas allows certain skills/knowledge tests. Source: Kansas Department of Revenue (dovcdlentry.html); 49 CFR Part 380.","handbook":"","hbref":""},{"q":"Which of the following first-time actions does NOT trigger the federal ELDT requirement in Kansas?","options":["Obtaining a Class A CDL for the first time","Upgrading a Class B CDL to a Class A CDL","Obtaining the Hazardous Materials (H) endorsement for the first time","Renewing an existing Class A CDL with no new endorsements"],"answer":3,"explanation":"ELDT applies to first-time Class A/B issuance, a Class B-to-A upgrade, and first-time H, P, or S endorsements. A routine renewal of an existing CDL with no upgrade or new endorsement does not require ELDT. Source: Kansas Department of Revenue (dovcdlentry.html); 49 CFR Part 380.","handbook":"","hbref":""},{"q":"A Kansas CDL driver who operates only within Kansas and is not exempt from medical requirements should self-certify as which category?","options":["Non-excepted interstate","Excepted interstate","Non-excepted intrastate","Excepted intrastate"],"answer":2,"explanation":"A driver operating solely within Kansas who is subject to the medical certificate requirement self-certifies as 'Non-excepted intrastate' and must maintain a current Medical Examiner's Certificate. Source: Kansas Department of Revenue, Medical Certification (ksrevenue.gov); 49 CFR 383.71.","handbook":"","hbref":""},{"q":"Which Kansas CDL self-certification category requires the driver to maintain and submit a current federal Medical Examiner's Certificate?","options":["Excepted interstate","Excepted intrastate","Non-excepted interstate","Restricted farm operator"],"answer":2,"explanation":"Drivers certifying as Non-excepted interstate (and non-excepted intrastate) must maintain a current Medical Examiner's Certificate; excepted drivers do not submit medical documents. Source: Kansas Department of Revenue, Medical Certification (ksrevenue.gov); 49 CFR 383.71.","handbook":"","hbref":""},{"q":"Under Kansas/federal rules, a 'tank vehicle' for the N endorsement is generally one designed to carry a liquid or gas in a permanently or temporarily attached tank with a rated capacity of at least:","options":["100 gallons","500 gallons","1,000 gallons","5,000 gallons"],"answer":2,"explanation":"The N (tank) endorsement applies to vehicles carrying liquid or gaseous materials in tanks with an aggregate rated capacity of 1,000 gallons or more (individual tanks of 119 gallons or more). Source: Kansas CDL Manual (KDOR); 49 CFR 383.5.","handbook":"","hbref":""},{"q":"A driver wants to combine the Hazardous Materials and Tank endorsements on a Kansas CDL. Which single endorsement code represents that combination?","options":["X","T","P","L"],"answer":0,"explanation":"Kansas uses the 'X' endorsement code to represent the combination of the Hazardous Materials (H) and Tank (N) endorsements. Source: K.S.A. 8-2,135; Kansas CDL Manual (KDOR).","handbook":"","hbref":""},{"q":"In Kansas, what is the maximum blood alcohol concentration (BAC) at which a person may legally operate a commercial motor vehicle (CMV)?","options":["0.08% or higher is the limit","Any BAC below 0.04%","Any BAC below 0.10%","Any BAC below 0.02%"],"answer":1,"explanation":"Kansas prohibits operating a CMV with a BAC of 0.04% or more; the legal limit for CMV drivers is below 0.04%, half the 0.08% limit for ordinary drivers. Source: Kansas CDL Manual, Section 1 (Driver Disqualifications); 49 CFR 383.51 as adopted in Kansas.","handbook":"","hbref":""},{"q":"How long is a Kansas CDL holder disqualified for a FIRST major offense, such as a DUI in a CMV, when NOT transporting placarded hazardous materials?","options":["60 days","1 year","3 years","6 months"],"answer":1,"explanation":"A first major offense (DUI, refusing a test, leaving the scene, using a CMV in a felony, etc.) results in a 1-year disqualification in Kansas. Source: K.S.A. 8-2,142; Kansas CDL Manual; 49 CFR 383.51.","handbook":"","hbref":""},{"q":"If a Kansas driver commits a first major offense WHILE transporting hazardous materials required to be placarded, how long is the disqualification?","options":["1 year","3 years","Lifetime","120 days"],"answer":1,"explanation":"A first major offense while operating a CMV transporting placarded hazardous materials results in a 3-year disqualification in Kansas, rather than the standard 1 year. Source: K.S.A. 8-2,142; Kansas CDL Manual; 49 CFR 383.51.","handbook":"","hbref":""},{"q":"What is the disqualification period in Kansas for a SECOND major offense committed in a CMV?","options":["3 years","10 years","Lifetime","5 years"],"answer":2,"explanation":"A second major offense results in a lifetime disqualification of the CDL in Kansas. Source: K.S.A. 8-2,142; Kansas CDL Manual; 49 CFR 383.51(b).","handbook":"","hbref":""},{"q":"Under Kansas implied-consent rules, a CDL holder who REFUSES a chemical test of breath or blood is treated as having committed what?","options":["A serious traffic violation","A major offense","An out-of-service violation","A non-reportable offense"],"answer":1,"explanation":"Refusing a lawfully requested chemical test is classified as a major offense, carrying the same 1-year (or 3-year HazMat) disqualification as a DUI. Source: K.S.A. 8-2,142; Kansas CDL Manual, Section 1.","handbook":"","hbref":""},{"q":"How long is a Kansas CDL holder disqualified for refusing a chemical test while driving a CMV NOT carrying placarded hazardous materials?","options":["90 days","1 year","3 years","Lifetime"],"answer":1,"explanation":"A first test refusal in a CMV results in a 1-year CDL disqualification (3 years if transporting placarded HazMat). Source: K.S.A. 8-2,142; 49 CFR 383.51.","handbook":"","hbref":""},{"q":"When a Kansas CDL driver accumulates TWO serious traffic violations within a 3-year period (in a CMV), the minimum disqualification is:","options":["30 days","60 days","120 days","1 year"],"answer":1,"explanation":"Two serious traffic violations within 3 years result in a minimum 60-day disqualification in Kansas. Source: Kansas CDL Manual, Section 1; 49 CFR 383.51(c).","handbook":"","hbref":""},{"q":"When a Kansas CDL driver accumulates THREE serious traffic violations within a 3-year period (in a CMV), the minimum disqualification is:","options":["60 days","90 days","120 days","180 days"],"answer":2,"explanation":"Three serious traffic violations within 3 years result in a minimum 120-day disqualification in Kansas. Source: Kansas CDL Manual, Section 1; 49 CFR 383.51(c).","handbook":"","hbref":""},{"q":"Which of the following counts as a 'serious traffic violation' for a Kansas CDL holder?","options":["Driving 15 mph or more over the speed limit","Driving 5 mph over the speed limit","A parking violation","An expired registration sticker"],"answer":0,"explanation":"Serious traffic violations include speeding 15 mph or more over the limit, reckless driving, improper or erratic lane changes, following too closely, and traffic offenses connected with a fatal accident. Source: Kansas CDL Manual, Section 1; 49 CFR 383.51(c).","handbook":"","hbref":""},{"q":"Under Kansas/federal CDL rules, driving a CMV while TEXTING is classified as which type of offense?","options":["A major offense","A serious traffic violation","An out-of-service violation","A railroad-crossing violation"],"answer":1,"explanation":"Texting while driving a CMV, and using a hand-held mobile phone while driving a CMV, are serious traffic violations that count toward the 2-in-3-years (60-day) and 3-in-3-years (120-day) disqualifications. Source: Kansas CDL Manual; 49 CFR 383.51(c) and 392.80/392.82.","handbook":"","hbref":""},{"q":"For a Kansas CDL driver, using a HAND-HELD mobile telephone while operating a CMV is treated as:","options":["A non-reportable infraction","A serious traffic violation","A major offense","An automatic lifetime ban"],"answer":1,"explanation":"Driving a CMV while using a hand-held phone violates 49 CFR 392.82 and is a serious traffic violation; the driver faces a federal civil penalty (up to $2,750) and the violation counts toward serious-violation disqualifications. Source: Kansas CDL Manual; 49 CFR 392.82, 383.51(c).","handbook":"","hbref":""},{"q":"What is the disqualification period for a Kansas CDL holder's FIRST conviction of a railroad-highway grade crossing violation?","options":["No less than 30 days","No less than 60 days","No less than 120 days","No less than 180 days"],"answer":1,"explanation":"A first railroad-highway grade crossing violation results in a disqualification of no less than 60 days in Kansas. Source: Kansas CDL Manual, Section 1; 49 CFR 383.51(d).","handbook":"","hbref":""},{"q":"A Kansas CDL holder commits a SECOND railroad-highway grade crossing violation within a 3-year period. The minimum disqualification is:","options":["60 days","90 days","120 days","1 year"],"answer":2,"explanation":"A second railroad-crossing violation within 3 years results in a disqualification of no less than 120 days. Source: Kansas CDL Manual, Section 1; 49 CFR 383.51(d).","handbook":"","hbref":""},{"q":"A Kansas CDL holder commits a THIRD railroad-highway grade crossing violation within a 3-year period. The minimum disqualification is:","options":["120 days","180 days","No less than 1 year","2 years"],"answer":2,"explanation":"A third railroad-crossing violation within 3 years results in a disqualification of no less than 1 year. Source: Kansas CDL Manual, Section 1; 49 CFR 383.51(d).","handbook":"","hbref":""},{"q":"What is the minimum disqualification for a Kansas CDL driver's FIRST violation of an out-of-service order (non-HazMat, non-passenger)?","options":["No less than 60 days","No less than 90 days","No less than 180 days","No less than 1 year"],"answer":2,"explanation":"A first out-of-service order violation results in a disqualification of no less than 180 days (and not more than 1 year) in Kansas. Source: Kansas CDL Manual, Section 1; 49 CFR 383.51(e).","handbook":"","hbref":""},{"q":"What is the disqualification range for a SECOND out-of-service order violation within 10 years for a Kansas CDL driver (non-HazMat, non-passenger)?","options":["180 days to 1 year","1 to 3 years","2 to 5 years","3 to 5 years"],"answer":2,"explanation":"A second out-of-service order violation within 10 years results in a disqualification of no less than 2 years and no more than 5 years. Source: Kansas CDL Manual, Section 1; 49 CFR 383.51(e).","handbook":"","hbref":""},{"q":"A Kansas CDL driver commits a FIRST out-of-service order violation while transporting placarded hazardous materials or carrying passengers. The disqualification is:","options":["No less than 60 days","No less than 180 days, up to 2 years","No less than 90 days, up to 1 year","Lifetime"],"answer":1,"explanation":"A first out-of-service order violation while hauling placarded HazMat or carrying passengers results in a disqualification of no less than 180 days and no more than 2 years (versus up to 1 year for ordinary loads). Source: Kansas CDL Manual; 49 CFR 383.51(e).","handbook":"","hbref":""},{"q":"In Kansas, a CMV driver found with ANY detectable amount of alcohol in their system (even under 0.04%) while on duty is subject to what?","options":["Immediate lifetime disqualification","Being placed out of service for 24 hours","A 1-year disqualification","A 60-day disqualification"],"answer":1,"explanation":"A CMV driver with any measurable or detectable alcohol (below 0.04%) is placed out of service for 24 hours; a BAC of 0.04% or more becomes a major offense (1-year disqualification). Source: Kansas CDL Manual, Section 1; 49 CFR 392.5.","handbook":"","hbref":""},{"q":"Besides disqualification, what additional penalty can a Kansas/federal civil penalty impose on a TRUCKING COMPANY that knowingly allows a driver to operate during an out-of-service order?","options":["A fine of $2,750 to $11,000","A flat $500 fine","Loss of the company's operating authority for 60 days","No penalty applies to the company"],"answer":0,"explanation":"An employer who knowingly allows or requires a driver to violate an out-of-service order is subject to a civil penalty of $2,750 to $11,000, in addition to the driver's disqualification and fine. Source: Kansas CDL Manual; 49 CFR 383.53(b).","handbook":"","hbref":""},{"q":"A Kansas CDL holder is convicted of a major offense and later, years afterward, is convicted of a second major offense. After a lifetime disqualification, reinstatement may be possible only:","options":["After 1 year","After 5 years","After a minimum of 10 years, if conditions are met","It is never possible"],"answer":2,"explanation":"A lifetime disqualification for two major offenses may, under FMCSA-adopted rules, be reduced to a minimum of 10 years if the driver completes prescribed conditions; some lifetime bans (e.g., using a CMV to manufacture/distribute drugs) are permanent. Source: Kansas CDL Manual; 49 CFR 383.51(b).","handbook":"","hbref":""},{"q":"In Kansas, when a school bus carrying passengers approaches a railroad grade crossing, how far from the nearest rail must the driver stop?","options":["Within 50 feet but not less than 15 feet from the nearest rail","Within 25 feet but not less than 5 feet from the nearest rail","Within 75 feet but not less than 25 feet from the nearest rail","Within 100 feet but not less than 50 feet from the nearest rail"],"answer":0,"explanation":"Kansas requires certain vehicles to stop within 50 feet but not less than 15 feet from the nearest rail and to look and listen before crossing. Source: K.S.A. 8-1551; Kansas CDL Manual (KDOR).","handbook":"","hbref":""},{"q":"Under Kansas law, a commercial vehicle displaying hazardous-materials placards that requires a stop at a railroad crossing must come to a complete stop within what distance of the nearest rail?","options":["No closer than 10 feet and no farther than 30 feet","No closer than 15 feet and no farther than 50 feet","No closer than 20 feet and no farther than 60 feet","No closer than 5 feet and no farther than 25 feet"],"answer":1,"explanation":"Placarded HazMat vehicles must stop within 50 feet but not less than 15 feet from the nearest rail and proceed only when safe. Source: K.S.A. 8-1551; Kansas CDL Manual (KDOR).","handbook":"","hbref":""},{"q":"Kansas's 'Move Over' law was expanded effective July 1, 2025. What does the current law require a driver approaching a stopped vehicle to do?","options":["Move over only for police, fire, and ambulance vehicles","Move over only for emergency vehicles and tow trucks","Move over for ANY stationary vehicle displaying flashing or hazard lights, not just emergency vehicles","Move over only when an officer is standing outside the vehicle"],"answer":2,"explanation":"Senate Bill 8 (effective July 1, 2025) expanded K.S.A. 8-1530 so drivers must move over or slow down for any stationary vehicle displaying flashing/hazard lights. Source: K.S.A. 8-1530; Kansas SB 8 (2025).","handbook":"","hbref":""},{"q":"On a Kansas highway with two or more lanes in the driver's direction, what does the Move Over law require when passing a stationary vehicle with active warning lights?","options":["Always stop completely until the vehicle leaves","Sound the horn continuously while passing","Maintain normal speed but turn on hazard lights","Change into a lane not adjacent to the stopped vehicle if it can be done safely"],"answer":3,"explanation":"K.S.A. 8-1530(b) requires drivers on multilane roads to change into a non-adjacent lane if safe; if not possible, slow down and proceed with due caution. Source: K.S.A. 8-1530; Kansas CDL Manual (KDOR).","handbook":"","hbref":""},{"q":"Under the Kansas Move Over law, if changing lanes away from a stopped warning-light vehicle is unsafe or impossible, what must the driver do?","options":["Stop in the travel lane and wait","Reduce speed and maintain a safe speed for road, weather, and traffic conditions","Continue at the posted speed limit","Pull onto the shoulder and stop"],"answer":1,"explanation":"When a lane change is not possible or unsafe, K.S.A. 8-1530(b) requires the driver to proceed with due caution, reduce speed, and maintain a safe speed. Source: K.S.A. 8-1530.","handbook":"","hbref":""},{"q":"What is the maximum posted speed limit on a separated multilane (interstate) highway in Kansas, as set by the Secretary of Transportation?","options":["70 mph","65 mph","75 mph","80 mph"],"answer":2,"explanation":"Kansas sets the maximum on separated multilane highways at 75 mph as designated and posted by the Secretary of Transportation. Source: K.S.A. 8-1558.","handbook":"","hbref":""},{"q":"Does Kansas set a separate, lower statewide maximum speed limit for trucks/CMVs than for cars on its interstates?","options":["Yes - trucks are limited to 65 mph statewide while cars may go 75 mph","Yes - trucks are limited to 60 mph on all interstates","Yes - trucks are limited to 55 mph at night statewide","No - the same maximum posted limit applies to trucks and cars in Kansas"],"answer":3,"explanation":"Kansas does not impose a separate statewide truck speed limit; the same posted maximum applies to all vehicles unless signs say otherwise. Source: K.S.A. 8-1558; KDOT.","handbook":"","hbref":""},{"q":"Under K.S.A. 8-1558, what is the maximum lawful speed limit on a Kansas county or township highway?","options":["55 mph","45 mph","65 mph","60 mph"],"answer":0,"explanation":"Kansas sets the maximum on county or township highways at 55 mph, on other (non-multilane) highways at 65 mph, and 30 mph in urban districts. Source: K.S.A. 8-1558.","handbook":"","hbref":""},{"q":"Under K.S.A. 8-1558, what is the maximum lawful speed limit in an urban district in Kansas unless otherwise posted?","options":["25 mph","35 mph","30 mph","20 mph"],"answer":2,"explanation":"The statutory maximum in an urban district is 30 mph unless a different limit is posted. Source: K.S.A. 8-1558.","handbook":"","hbref":""},{"q":"On a Kansas two-lane (undivided) road, what must a driver meeting a stopped school bus with flashing red lights do?","options":["Slow to 20 mph and pass with caution","Move to the far lane and continue past the bus","Stop only if children are visibly crossing","Stop before reaching the bus and not proceed until the red lights stop flashing or the bus moves"],"answer":3,"explanation":"Drivers meeting or overtaking a school bus with flashing red lights must stop before reaching it and remain stopped until the lights stop or the bus moves. Source: K.S.A. 8-1556.","handbook":"","hbref":""},{"q":"On a Kansas divided highway with separate roadways, what is the exception to stopping for a school bus loading children?","options":["A driver on a different roadway than the bus need not stop","A driver in the lane nearest the bus need not stop","No exception applies; all drivers must always stop","A driver may proceed if the bus is more than 100 feet away"],"answer":0,"explanation":"K.S.A. 8-1556 provides that a driver on a highway with separate roadways need not stop for a school bus on a DIFFERENT roadway (or in a controlled-access loading zone where pedestrians cannot cross). Source: K.S.A. 8-1556.","handbook":"","hbref":""},{"q":"Under the Kansas school-bus separate-roadway exception, which scenario still REQUIRES every direction of traffic to stop?","options":["A divided highway where the bus is on the opposite roadway across a median","An undivided two-lane road with no physical separation between directions","A controlled-access highway where the bus is in a loading zone and pedestrians cannot cross","Two roadways physically separated by a barrier"],"answer":1,"explanation":"The exception applies only where there are SEPARATE roadways. On an undivided road with no separation, traffic in both directions must stop. Source: K.S.A. 8-1556.","handbook":"","hbref":""},{"q":"In Kansas, the base fine for unlawfully passing a stopped school bus with its red lights flashing is which of the following?","options":["$75, with no escalation","$150, doubled only in school zones","$500 flat for every offense","$315, with escalating fines for repeat offenses"],"answer":3,"explanation":"Kansas's uniform fine schedule sets a $315 base fine for unlawfully passing a school bus, with escalating fines for subsequent violations. Source: K.S.A. 8-2118.","handbook":"","hbref":""},{"q":"When a Kansas CDL driver stops a commercial vehicle on the shoulder of a divided highway, where should the rear-most reflective warning triangle be placed?","options":["About 200 feet behind the vehicle toward approaching traffic","About 50 feet behind the vehicle","About 500 feet behind the vehicle","About 150 feet behind the vehicle"],"answer":0,"explanation":"On a divided/one-way highway, triangles go at 10 feet, 100 feet, and 200 feet toward approaching traffic. Source: Kansas CDL Manual (KDOR); 49 CFR 392.22.","handbook":"","hbref":""},{"q":"A Kansas CDL driver stops on a one-way or divided highway. What is the correct placement of all three reflective triangles toward approaching traffic?","options":["10 feet, 50 feet, and 150 feet to the rear","10 feet, 100 feet, and 200 feet to the rear","25 feet, 100 feet, and 250 feet to the rear","5 feet, 75 feet, and 175 feet to the rear"],"answer":1,"explanation":"On divided/one-way roads, place triangles at 10, 100, and 200 feet toward approaching traffic. Source: Kansas CDL Manual (KDOR); 49 CFR 392.22.","handbook":"","hbref":""},{"q":"After stopping a CMV on a Kansas two-lane, two-way road, how soon must a driver put out the required emergency warning devices?","options":["Within 30 minutes of stopping","Within 1 hour of stopping","Within 10 minutes of stopping","Only if stopped longer than 2 hours"],"answer":2,"explanation":"Emergency warning devices must be placed within 10 minutes of stopping on a highway or shoulder. Source: Kansas CDL Manual (KDOR); 49 CFR 392.22.","handbook":"","hbref":""},{"q":"On a Kansas two-lane, two-way road, where should a CMV driver place the three warning triangles after stopping?","options":["One within 10 feet of the rear, one about 100 feet behind, and one about 100 feet ahead of the vehicle","All three within 10 feet of the rear of the vehicle","One at 200 feet behind and two ahead of the vehicle","One at 50 feet behind and two at the sides of the vehicle"],"answer":0,"explanation":"On a two-way road, place one triangle 10 feet to the rear, one about 100 feet to the rear, and one about 100 feet to the front. Source: Kansas CDL Manual (KDOR); 49 CFR 392.22.","handbook":"","hbref":""},{"q":"When a Kansas CDL bus driver crosses railroad tracks at a crossing, what should the driver NOT do while any part of the bus is on the tracks?","options":["Keep the bus in a low gear","Look and listen before entering","Change gears (shift) while crossing the tracks","Keep the door closed"],"answer":2,"explanation":"Drivers must cross railroad tracks in a gear that will not require shifting, and must not change gears while any part of the vehicle is on the tracks. Source: Kansas CDL Manual (KDOR).","handbook":"","hbref":""},{"q":"Which routing fact is genuinely distinctive to commercial operations in Kansas?","options":["All Kansas interstates are toll-free with no commercial routes","Much of I-35, I-335, I-470, and I-70 forms the toll Kansas Turnpike, where twin 53-foot trailers are permitted","Kansas bans all trucks over 40 feet from every interstate","Kansas requires all trucks to use only US (non-interstate) highways"],"answer":1,"explanation":"The Kansas Turnpike (KTA), about 236 miles along I-35/I-335/I-470/I-70, is a toll road that permits twin 53-foot trailers. Source: KDOT; Kansas Turnpike Authority.","handbook":"","hbref":""},{"q":"Which Kansas agency issues oversize/overweight permits and approves truck routing through the K-TRIPS system?","options":["Kansas Department of Revenue (KDOR)","Kansas Highway Patrol licensing division","The Federal Motor Carrier Safety Administration","Kansas Department of Transportation (KDOT)"],"answer":3,"explanation":"KDOT administers oversize/overweight permits and routing through the Kansas Truck Routing and Intelligent Permitting System (K-TRIPS). Source: KDOT Commercial Vehicle Information.","handbook":"","hbref":""},{"q":"Which Kansas state agency issues Commercial Driver's Licenses (CDLs)?","options":["The Federal Motor Carrier Safety Administration","The Kansas Department of Transportation (KDOT)","The Kansas Department of Revenue, Division of Vehicles","The Kansas Highway Patrol"],"answer":2,"explanation":"In Kansas the CDL is issued by the Kansas Department of Revenue (KDOR), Division of Vehicles, which also publishes the Kansas CDL manual. KDOT handles roads and permits but not driver licensing. Source: Kansas DOR Division of Vehicles CDL page (ksrevenue.gov/dovcdl.html).","handbook":"","hbref":""},{"q":"Before a Kansas applicant can take the CDL skills test, both knowledge and skills tests must be passed. What two general types of tests does the Kansas CDL manual say you must pass to get a CDL or CLP?","options":["A written test and a vision test only","A medical exam and a background check only","A road sign test and a defensive-driving course","Knowledge tests and skills tests"],"answer":3,"explanation":"The Kansas CDL manual states: 'To get a CDL or CLP, you must pass knowledge and skills tests.' Vision and medical certification are separate requirements. Source: Kansas CDL Manual, Section 1.1, 'Commercial Driver License Tests.'","handbook":"","hbref":""},{"q":"The Kansas CDL skills test consists of three segments that must be taken in a set order. Which sequence is correct?","options":["On-road driving, then vehicle inspection, then basic vehicle control","Vehicle inspection, then basic vehicle control, then on-road driving","Vehicle inspection, then on-road driving, then basic vehicle control","Basic vehicle control, then on-road driving, then vehicle inspection"],"answer":1,"explanation":"The Kansas CDL manual states the skills test has three segments-vehicle inspection, basic vehicle control, and on-road driving-and you must take them in that order and pass each before moving to the next. Source: Kansas CDL Manual, Section 1.1.2, 'Skills Tests.'","handbook":"","hbref":""},{"q":"How many self-certification categories must a Kansas CDL applicant choose from when declaring the type of commerce they operate in?","options":["Five","Three","Four","Two"],"answer":2,"explanation":"Kansas requires CDL applicants/holders to self-certify to one of four categories of commerce. Source: Kansas CDL Manual, Section 1.2 ('the four types of commerce you must self-certify') and Kansas DOR Medical Certification Information page.","handbook":"","hbref":""},{"q":"Which of the following is one of the four Kansas CDL self-certification categories?","options":["Provisional Intrastate","Non-excepted Interstate","Restricted Interstate","Exempt Federal"],"answer":1,"explanation":"The four Kansas self-certification categories are Non-excepted Interstate, Excepted Interstate, Non-excepted Intrastate, and Excepted Intrastate. 'Restricted,' 'Provisional,' and 'Exempt Federal' are not categories. Source: Kansas DOR Medical Certification Information page; Kansas CDL Manual Section 1.2.","handbook":"","hbref":""},{"q":"A Kansas driver who self-certifies as 'Non-excepted Interstate' must do what to keep a 'certified' medical status?","options":["Carry a paper copy of their physical in the cab at all times","Pass an additional air brakes knowledge test annually","Maintain a current medical examiner's certificate (DOT medical card)","Renew their CDL every year instead of every four years"],"answer":2,"explanation":"Non-excepted interstate drivers must provide and keep current a federal medical examiner's certificate (49 CFR 391.45), or they become 'not-certified' and may lose the CDL. Source: Kansas CDL Manual, Section 1.2, Medical Documentation Requirements.","handbook":"","hbref":""},{"q":"Effective June 2, 2025, how must a Kansas CDL holder's medical examiner's certificate (MEC) reach the Division of Vehicles?","options":["Mailed by the driver to the KDOR P.O. Box in Topeka","Faxed by the driver's employer to KDOR","Hand-delivered by the driver to any license exam station","Electronically from the National Registry of Certified Medical Examiners"],"answer":3,"explanation":"Effective 6/2/2025, Kansas no longer accepts MECs submitted by the driver and can no longer manually enter them; the certified data must come electronically from the National Registry of Certified Medical Examiners (the examiner enters it). Source: Kansas DOR Medical Certification Information page (ksrevenue.gov/dovmedcertfaq.html).","handbook":"","hbref":""},{"q":"Under the June 2025 Kansas process, how long does a certified medical examiner have to enter a new MEC into the National Registry?","options":["Immediately, before the driver leaves the office","Until midnight of the next calendar day","Within 10 business days of the exam","Within 30 days of the exam"],"answer":1,"explanation":"Kansas notes the medical examiner has until the next day at midnight to enter the MEC into the National Registry, from which Kansas then receives it electronically. Source: Kansas DOR Medical Certification Information page.","handbook":"","hbref":""},{"q":"For first-time CDL applicants in Kansas, the federal Entry-Level Driver Training (ELDT) requirement must be completed when?","options":["Within 30 days after the CDL is issued","Only after a first moving violation","Before taking the CDL skills test","Before renewing the CDL the first time"],"answer":2,"explanation":"ELDT (effective Feb. 7, 2022) requires theory and behind-the-wheel training from an FMCSA-registered provider, completed before the applicant may take the CDL skills test. This federal standard applies in Kansas. Source: FMCSA ELDT rule (49 CFR Part 380, Subpart F); FMCSA Training Provider Registry.","handbook":"","hbref":""},{"q":"An entry-level Kansas CDL applicant must obtain required ELDT training from a provider that is listed where?","options":["On the Kansas DOR approved-schools list","On the Kansas Highway Patrol carrier roster","On the National Registry of Certified Medical Examiners","On the FMCSA Training Provider Registry (TPR)"],"answer":3,"explanation":"ELDT must be provided by a school listed on the FMCSA Training Provider Registry (TPR); completion is reported electronically to FMCSA before the state allows skills testing. Source: FMCSA Entry-Level Driver Training, Training Provider Registry.","handbook":"","hbref":""},{"q":"Obtaining which of the following endorsements for the first time triggers the ELDT training requirement before testing?","options":["Air brakes clearance only","Passenger (P), School Bus (S), or Hazardous Materials (H)","Doubles/Triples (T) only","Tank (N) only"],"answer":1,"explanation":"ELDT applies to first-time CDL applicants, Class B-to-A upgrades, and first-time P, S, or H endorsements. Doubles/Triples and Tank endorsements are not ELDT-triggering on their own. Source: FMCSA ELDT applicability (49 CFR Part 380, Subpart F).","handbook":"","hbref":""},{"q":"Upgrading an existing Class B CDL to a Class A CDL in Kansas requires what additional step under the federal ELDT rule?","options":["Nothing additional; the upgrade is automatic","Holding the Class B CDL for at least five years first","Retaking only the general knowledge test","Completing Class A upgrade ELDT before the skills test"],"answer":3,"explanation":"A Class B-to-Class A upgrade is one of the operations covered by ELDT, so the driver must complete the upgrade training program from a TPR-listed provider before taking the Class A skills test. Source: FMCSA ELDT rule (49 CFR Part 380, Subpart F).","handbook":"","hbref":""},{"q":"After a Kansas applicant is issued a CLP, how long must they wait before they are eligible to take the CDL skills test?","options":["At least 30 days","At least 60 days","At least 14 days","At least 7 days"],"answer":2,"explanation":"A CLP holder must hold the permit for at least 14 days before taking the CDL skills test. This federal requirement is enforced in Kansas. Source: 49 CFR 383.25; Kansas CDL applicant guidance.","handbook":"","hbref":""},{"q":"How often must a standard Kansas CDL be renewed?","options":["Every 6 years","Every 8 years","Every 2 years","Every 4 years"],"answer":3,"explanation":"Kansas CDLs are issued on a 4-year cycle and must be renewed every four years, regardless of the 6-year cycle used for some non-commercial Kansas licenses. Source: Kansas DOR Division of Vehicles licensing information.","handbook":"","hbref":""},{"q":"What is the minimum age to obtain a Kansas CDL for intrastate (within-Kansas only) operation?","options":["18 years old","19 years old","21 years old","16 years old"],"answer":0,"explanation":"A Kansas CDL for intrastate operation may be issued at age 18; interstate operation (and hazmat) requires age 21. Source: Kansas CDL Manual; FMCSA driver-qualification rules (49 CFR 391.11).","handbook":"","hbref":""},{"q":"What is the minimum age to operate a commercial motor vehicle in interstate commerce with a Kansas CDL?","options":["25 years old","21 years old","18 years old","23 years old"],"answer":1,"explanation":"Interstate CMV operation, and hauling hazardous materials, requires a driver to be at least 21. Drivers 18-20 are limited to intrastate operation. Source: FMCSA driver-qualification rules (49 CFR 391.11); Kansas CDL guidance.","handbook":"","hbref":""},{"q":"Which set of documents best reflects what a Kansas applicant must provide to apply for a CLP/CDL?","options":["A passport only, with no proof of residency required","Proof of identity/date of birth, Social Security number, lawful presence, and two proofs of Kansas residency","A high-school diploma and an employer reference letter","Only a current Kansas non-commercial license and a photo"],"answer":1,"explanation":"Kansas requires proof of identity/date of birth, proof of Social Security number, proof of lawful presence, and two documents proving Kansas residency (physical address); applicants must also already hold a Kansas non-commercial driver's license. Source: Kansas DOR Division of Vehicles application requirements.","handbook":"","hbref":""},{"q":"A Kansas process question on fees: which statement about CDL fees is accurate to teach applicants?","options":["The CDL fee is permanently fixed by Kansas statute and never changes","Kansas charges no fee for a CDL or its endorsements","CDL fees are set federally by FMCSA and are identical in every state","CDL and endorsement fees are set by Kansas and can change, so applicants should confirm current amounts with KDOR"],"answer":3,"explanation":"CDL, endorsement, and CLP fees are established by the state and are subject to change; applicants should verify current amounts with the Kansas DOR rather than rely on a fixed figure. Fees are state-set, not federally uniform. Source: Kansas DOR Division of Vehicles fee schedule guidance.","handbook":"","hbref":""}],"ru":{"0":{"q":"Какова максимальная общая внешняя ширина транспортного средства или его груза на дорогах Канзаса без специального разрешения?","options":["8 футов (96 дюймов)","8 1/2 футов (102 дюйма)","9 футов (108 дюймов)","10 футов (120 дюймов)"],"explanation":"K.S.A. 8-1902 ограничивает общую внешнюю ширину любого транспортного средства или его груза до 8 1/2 футов (102 дюйма). Руководство по CDL Канзаса и Дорожный патруль Канзаса указывают тот же стандартный предел ширины."},"1":{"q":"Какова общая максимальная высота транспортного средства, включая его груз, на дорогах Канзаса?","options":["13 футов 6 дюймов","14 футов","14 футов 6 дюймов","15 футов"],"explanation":"K.S.A. 8-1904 устанавливает максимальную высоту транспортного средства (включая груз) в 14 футов. Дорожный патруль Канзаса подтверждает, что 14 футов — это законный предел высоты."},"2":{"q":"Канзас разрешает одному типу груза превышать предел высоты в 14 футов и быть закреплённым на высоте до 14 1/2 футов. Что это за груз?","options":["Тюки хлопка","Цилиндрические тюки сена","Стальные балки для строительства","Морские контейнеры"],"explanation":"K.S.A. 8-1904 разрешает транспортному средству, перевозящему цилиндрические тюки сена, быть загруженным на высоту до 14 1/2 футов; водитель несёт ответственность за любой ущерб, если груз заденет путепровод."},"3":{"q":"Какова максимальная длина одиночного транспортного средства (например, грузовика без прицепа), включая его груз, на дорогах Канзаса?","options":["40 футов","45 футов","48 футов","53 фута"],"explanation":"K.S.A. 8-1904 ограничивает одиночное транспортное средство, включая груз, до 45 футов крайнего габаритного размера."},"4":{"q":"В сцепке из седельного тягача и полуприцепа какова максимальная длина полуприцепа, разрешённая в Канзасе?","options":["48 футов","53 фута","57 футов","59 1/2 футов"],"explanation":"K.S.A. 8-1904 предусматривает, что полуприцеп, эксплуатируемый в сцепке с седельным тягачом, не должен превышать 59 1/2 футов в длину."},"5":{"q":"Какова максимальная полная нагрузка на любую одиночную ось транспортного средства на дорогах Канзаса без специального разрешения?","options":["18 000 фунтов","20 000 фунтов","22 000 фунта","24 000 фунта"],"explanation":"K.S.A. 8-1908 ограничивает полную нагрузку на любую одну ось до 20 000 фунтов (и на любое одно колесо до 10 000 фунтов)."},"6":{"q":"Какова максимальная полная нагрузка на сдвоенную группу осей в Канзасе без специального разрешения?","options":["32 000 фунта","34 000 фунта","36 000 фунтов","40 000 фунтов"],"explanation":"K.S.A. 8-1908 ограничивает полную нагрузку на сдвоенные оси до 34 000 фунтов, что соответствует федеральному стандарту."},"7":{"q":"Какова максимальная полная нагрузка на любое одиночное колесо транспортного средства по закону Канзаса?","options":["8 000 фунтов","10 000 фунтов","12 000 фунтов","17 000 фунтов"],"explanation":"K.S.A. 8-1908 устанавливает, что полная нагрузка на любое колесо транспортного средства не должна превышать 10 000 фунтов."},"8":{"q":"На системе межштатных автомагистралей в Канзасе какова максимальная полная масса транспортного средства, разрешённая без специального разрешения?","options":["73 280 фунтов","80 000 фунтов","85 500 фунтов","90 000 фунтов"],"explanation":"Согласно K.S.A. 8-1909, таблица весов по расстоянию между осями не может допускать более 80 000 фунтов полной массы на системе межштатных автомагистралей, что соответствует федеральному закону."},"9":{"q":"На автомагистралях штата Канзас и США, НЕ входящих в систему межштатных автомагистралей, таблица весов по расстоянию между осями может допускать полную массу до какого максимума?","options":["80 000 фунтов","85 500 фунтов","90 000 фунтов","94 000 фунта"],"explanation":"Таблица весов по расстоянию между осями в K.S.A. 8-1909 допускает до 85 500 фунтов полной массы на автомагистралях Канзаса и США (не межштатных), что выше, чем предел в 80 000 фунтов для межштатных автомагистралей."},"10":{"q":"Канзас определяет максимальную полную массу на группе из двух или более последовательных осей преимущественно с помощью какого метода?","options":["Фиксированного предела массы на прицеп","Таблицы весов по расстоянию между осями (мостовой формулы)","Только количества шин","Только зарегистрированной массы грузовика"],"explanation":"K.S.A. 8-1909 использует таблицу весов по расстоянию между осями, основанную на расстоянии между осями и их количестве, — канзасскую форму федеральной мостовой формулы, — чтобы установить максимальную массу на группе последовательных осей."},"11":{"q":"Согласно концепции мостовой формулы / расстояния между осями в Канзасе, как транспортное средство может законно перевозить большую общую массу на группе осей?","options":["Увеличив давление в шинах","Раздвинув оси дальше друг от друга и добавив оси","Уменьшив длину прицепа","Понизив высоту пола прицепа"],"explanation":"Таблица весов по расстоянию между осями в K.S.A. 8-1909 (мостовая формула) допускает большую общую массу по мере увеличения расстояния между осями и их количества, чтобы защитить мосты."},"12":{"q":"Груз, который превышает законные пределы размера или массы в Канзасе и НЕ может быть уменьшен (неделимый груз), требует чего, прежде чем он может перемещаться?","options":["Ничего, если перемещение происходит в светлое время суток","Разрешения на негабарит/перевес от KDOT","Записки от грузоотправителя","Только федерального исключения DOT"],"explanation":"Kansas DOR требует разрешение на негабарит/перевес для неделимых грузов, превышающих законные пределы; разрешения оформляются через систему K-TRIPS от KDOT."},"13":{"q":"Какая система Канзаса используется для подачи заявки и получения разрешений на негабарит/перевес?","options":["IRP Online","K-TRIPS (Kansas Truck Routing and Intelligent Permitting System)","IFTA Web","CDLIS"],"explanation":"KDOT выдаёт разрешения на негабарит/перевес через K-TRIPS (Kansas Truck Routing and Intelligent Permitting System); заявители регистрируются и подают данные о транспортном средстве, грузе и маршруте онлайн."},"14":{"q":"Стандартное разрешение Канзаса на негабарит/перевес для одной поездки обычно действительно в течение какого срока?","options":["24 часа","3 дня","7 дней","30 дней"],"explanation":"Разрешения KDOT на негабарит/перевес для одной поездки обычно действительны в течение семи дней с даты выдачи."},"15":{"q":"Перемещение негабаритного груза по разрешению в Канзасе обычно ограничено каким временем суток?","options":["В любое время, днём или ночью","С получаса до восхода солнца до получаса после захода солнца","Только с полуночи до 6 часов утра","Только по будням в рабочее время"],"explanation":"Условия разрешений KDOT обычно ограничивают перемещение негабаритных грузов периодом с получаса до восхода солнца до получаса после захода солнца, включая выходные и праздничные дни, с исключениями, указанными в разрешении."},"16":{"q":"При какой ширине транспортное средство или груз становится «негабаритным» в Канзасе, требуя разрешения?","options":["Более 8 футов","Более 8 футов 6 дюймов","Более 10 футов","Более 12 футов"],"explanation":"Поскольку K.S.A. 8-1902 устанавливает законную ширину в 8 1/2 футов (8 футов 6 дюймов), любое транспортное средство или груз шире 8 футов 6 дюймов является негабаритным и требует разрешения KDOT."},"17":{"q":"По стандартному разрешению Канзаса на перевес (KAR 36-1-37), какова максимальная разрешённая масса на одиночной оси?","options":["20 000 фунтов","22 000 фунта","24 000 фунта","26 000 фунтов"],"explanation":"Пределы разрешений на перевес в Канзасе согласно KAR 36-1-37 повышают максимум для одиночной неведущей оси до 22 000 фунтов (а для сдвоенных осей до 45 000 фунтов), что выше законного предела в 20 000 фунтов."},"18":{"q":"Канзас предлагает специальное годовое разрешение на перевес для ДЕЛИМЫХ грузов для сельскохозяйственной продукции, ресурсов и биотоплива. Какова его максимальная полная масса и где оно НЕ разрешено?","options":["80 000 фунтов; не на дорогах округа","90 000 фунтов; не на системе межштатных автомагистралей","100 000 фунтов; не в пределах городов","85 500 фунтов; не на мостах"],"explanation":"Канзас допускает годовое разрешение на перевес для делимых грузов для сельскохозяйственных ресурсов, продукции, скота и биотоплива до 90 000 фунтов при наличии не менее шести осей, и такие транспортные средства не могут эксплуатироваться на системе межштатных автомагистралей."},"19":{"q":"В Канзасе транспортному средству, эксплуатируемому с превышением 85 500 фунтов, запрещено перемещаться при каком условии?","options":["Когда идёт дождь","Когда поверхность дороги покрыта льдом, утрамбованным снегом или метелевым снегом","В сезон сбора урожая","В пределах 50 миль от города"],"explanation":"K.S.A. 8-1919 запрещает транспортным средствам, эксплуатируемым с превышением 85 500 фунтов, перемещаться, когда поверхность дороги покрыта льдом, утрамбованным снегом или метелевым снегом."},"20":{"q":"В Канзасе какой класс CDL требуется для управления одиночным транспортным средством с полной разрешённой массой 26 001 фунт или более, где любой буксируемый прицеп НЕ превышает 10 000 фунтов полной разрешённой массы (GVWR)?","options":["Класс A","Класс B","Класс C","Класс D"],"explanation":"Канзас определяет CDL класса B как любое одиночное транспортное средство с GVWR 26 001 фунт или более, либо такое транспортное средство, буксирующее прицеп, не превышающий 10 000 фунтов GVWR. Источник: Руководство по CDL Канзаса (KDOR) и K.S.A. 8-2,128."},"21":{"q":"Какова минимальная полная разрешённая масса сцепки (GCWR), определяющая CDL класса A в Канзасе, когда буксируемый прицеп превышает 10 000 фунтов?","options":["18 000 фунтов","26 001 фунт","33 000 фунта","10 001 фунт"],"explanation":"CDL класса A в Канзасе охватывает любую сцепку транспортных средств с GCWR 26 001 фунт или более при условии, что буксируемый прицеп (прицепы) имеет GVWR более 10 000 фунтов. Источник: Руководство по CDL Канзаса (KDOR); K.S.A. 8-2,128."},"22":{"q":"Водитель перевозит подлежащее размещению табличек количество опасных материалов в фургоне с GVWR менее 26 001 фунта. Какая комбинация класса CDL и подтверждения (endorsement) в Канзасе применяется?","options":["Класс A без подтверждения","Класс B с подтверждением N","Класс C с подтверждением H","Класс D с подтверждением P"],"explanation":"Если транспортное средство не соответствует весовым определениям класса A или B, но перевозит опасные материалы в количествах, требующих размещения табличек (или перевозит 16+ пассажиров), Канзас требует CDL класса C плюс подтверждение H для опасных материалов (HazMat). Источник: Руководство по CDL Канзаса (KDOR); 49 CFR 383.91."},"23":{"q":"Что разрешает водителю подтверждение «N» на CDL Канзаса?","options":["Управлять цистернами","Перевозить опасные материалы","Буксировать двойные и тройные прицепы","Управлять школьным автобусом"],"explanation":"В Канзасе подтверждение «N» разрешает управление цистернами. Источник: K.S.A. 8-2,135; Руководство по CDL Канзаса (KDOR)."},"24":{"q":"Какой код подтверждения на CDL Канзаса требуется для буксировки двойных и тройных прицепов?","options":["P","H","T","S"],"explanation":"Подтверждение «T» разрешает буксировку двойных и тройных прицепов; оно получается только путём сдачи теоретического теста (без отдельного теста на навыки). Источник: K.S.A. 8-2,135; Руководство по CDL Канзаса (KDOR)."},"25":{"q":"Транспортное средство предназначено для перевозки 16 или более человек, включая водителя. Какое подтверждение CDL Канзаса требуется (за исключением случая школьного автобуса)?","options":["N (цистерна)","P (пассажирское)","T (двойные/тройные)","H (опасные материалы)"],"explanation":"Подтверждение «P» (пассажирское) требуется для транспортных средств, предназначенных для перевозки 16 или более человек, включая водителя, и требует как теоретического теста, так и теста на навыки. Источник: Руководство по CDL Канзаса (KDOR); 49 CFR 383.93."},"26":{"q":"Чтобы получить подтверждение «Школьный автобус» (S) в Канзасе, какое другое подтверждение водитель также должен иметь?","options":["H (опасные материалы)","N (цистерна)","P (пассажирское)","T (двойные/тройные)"],"explanation":"Канзас требует, чтобы водители сначала имели подтверждение «P» (пассажирское), прежде чем добавить подтверждение «S» (школьный автобус), что также требует сдачи дополнительных теоретических тестов и тестов на навыки. Источник: Руководство по CDL Канзаса (KDOR); 49 CFR 383.93."},"27":{"q":"Прежде чем Канзас сможет выдать подтверждение «Опасные материалы» (H), заявитель должен выполнить какое дополнительное федеральное требование?","options":["Оценку угрозы безопасности TSA (проверку биографии)","Отказ по зрению от FMCSA","30-дневную дорожную стажировку","Повторный тест на навыки по пневматическим тормозам"],"explanation":"Подтверждение H (опасные материалы) требует сдачи теоретического теста И прохождения оценки угрозы безопасности TSA (Security Threat Assessment), которая включает снятие отпечатков пальцев и проверку биографии, прежде чем Канзас его выдаст. Источник: Руководство по CDL Канзаса (KDOR); 49 CFR 383.71/1572."},"28":{"q":"Каков минимальный возраст для получения CDL Канзаса с ограничением только на вождение внутри штата (внутри Канзаса)?","options":["16 лет","17 лет","18 лет","21 год"],"explanation":"Канзас требует, чтобы водителю было не менее 18 лет для получения CDL только для внутриштатной эксплуатации. Источник: Руководство по CDL Канзаса (KDOR); K.S.A. 8-2,129."},"29":{"q":"Каков минимальный возраст для получения CDL Канзаса для межштатного вождения (через границы штатов) или для перевозки опасных материалов?","options":["18 лет","19 лет","20 лет","21 год"],"explanation":"Водителю должно быть не менее 21 года, чтобы управлять коммерческим транспортным средством (CMV) в межштатной коммерции, перевозить опасные материалы или перевозить пассажиров через границы штатов. Источник: Руководство по CDL Канзаса (KDOR); 49 CFR 391.11."},"30":{"q":"После первой выдачи коммерческого ученического разрешения (CLP) в Канзасе, как долго заявитель должен владеть им, прежде чем получит право сдавать тест на навыки CDL?","options":["Не менее 7 дней","Не менее 14 дней","Не менее 30 дней","Не менее 60 дней"],"explanation":"Федеральное правило, принятое Канзасом: владелец CLP не имеет права сдавать тест на навыки CDL, пока разрешение не находится у него не менее 14 дней. Источник: Руководство по CDL Канзаса (KDOR); 49 CFR 383.25."},"31":{"q":"Что должен делать владелец CLP в Канзасе во время управления коммерческим транспортным средством для практики?","options":["Управлять только с восхода до захода солнца","Находиться в сопровождении владельца CDL, сидящего на переднем сиденье рядом с ним","Ограничивать вождение радиусом 25 миль от дома","Не перевозить никакого груза"],"explanation":"Владелец CLP в Канзасе может управлять CMV только в сопровождении лица, имеющего действительный CDL для данного типа транспортного средства, которое должно сидеть на переднем сиденье рядом с водителем. Источник: Руководство по CDL Канзаса (KDOR); 49 CFR 383.25."},"32":{"q":"Согласно федеральным стандартам, принятым Канзасом, коммерческое ученическое разрешение НЕ должно быть действительным более какого максимального срока без повторного тестирования?","options":["90 дней","6 месяцев","1 год","5 лет"],"explanation":"CLP может быть выдано на срок не более одного года с первоначальной выдачи, не требуя от заявителя повторной сдачи теоретических тестов. Источник: Руководство по CDL Канзаса (KDOR); 49 CFR 383.25."},"33":{"q":"Какой набор документов должен предъявить заявитель на CDL Канзаса в Отдел транспортных средств (Division of Vehicles) при подаче заявки?","options":["Подтверждение личности, номер социального страхования, проживание в Канзасе и законное присутствие","Только карту социального страхования и свидетельство о рождении","Паспорт и регистрацию транспортного средства","Подтверждение трудоустройства и разрешение на опасные материалы"],"explanation":"Департамент доходов Канзаса (Kansas DOR), Отдел транспортных средств требует, чтобы заявители подтвердили личность, предоставили номер социального страхования и показали подтверждение проживания в Канзасе и законного (легального) присутствия. Источник: Kansas DOR, Division of Vehicles (ksrevenue.gov)."},"34":{"q":"Обучение водителей начального уровня (ELDT), требуемое Канзасом для впервые подающих заявку на класс A/B, должно предоставляться обучающей организацией, которая:","options":["Утверждена местным школьным округом","Внесена в Реестр поставщиков обучения FMCSA (Training Provider Registry)","Сертифицирована Дорожным патрулём Канзаса","Аккредитована Министерством образования США"],"explanation":"С 7 февраля 2022 года ELDT должно быть пройдено через поставщика, внесённого в Реестр поставщиков обучения FMCSA (TPR), прежде чем Канзас разрешит определённые тесты на навыки/знания. Источник: Kansas DOR (dovcdlentry.html); 49 CFR Part 380."},"35":{"q":"Какое из следующих действий, совершаемых впервые, НЕ влечёт за собой федеральное требование ELDT в Канзасе?","options":["Получение CDL класса A впервые","Повышение CDL класса B до CDL класса A","Получение подтверждения «Опасные материалы» (H) впервые","Продление существующего CDL класса A без новых подтверждений"],"explanation":"ELDT применяется к первичной выдаче класса A/B, повышению класса B до A и первичным подтверждениям H, P или S. Обычное продление существующего CDL без повышения или нового подтверждения не требует ELDT. Источник: Kansas DOR (dovcdlentry.html); 49 CFR Part 380."},"36":{"q":"Водитель с CDL Канзаса, который работает только внутри Канзаса и не освобождён от медицинских требований, должен самостоятельно сертифицироваться как какая категория?","options":["Неосвобождённый межштатный (Non-excepted interstate)","Освобождённый межштатный (Excepted interstate)","Неосвобождённый внутриштатный (Non-excepted intrastate)","Освобождённый внутриштатный (Excepted intrastate)"],"explanation":"Водитель, работающий исключительно внутри Канзаса и подпадающий под требование о медицинской справке, самостоятельно сертифицируется как «Non-excepted intrastate» и должен иметь действующую справку медицинского эксперта (Medical Examiner's Certificate). Источник: Kansas DOR, Medical Certification (ksrevenue.gov); 49 CFR 383.71."},"37":{"q":"Какая категория самостоятельной сертификации CDL Канзаса требует, чтобы водитель имел и предоставлял действующую федеральную справку медицинского эксперта (Medical Examiner's Certificate)?","options":["Освобождённый межштатный (Excepted interstate)","Освобождённый внутриштатный (Excepted intrastate)","Неосвобождённый межштатный (Non-excepted interstate)","Ограниченный фермерский оператор (Restricted farm operator)"],"explanation":"Водители, сертифицирующиеся как Non-excepted interstate (и non-excepted intrastate), должны иметь действующую справку медицинского эксперта; освобождённые водители не предоставляют медицинские документы. Источник: Kansas DOR, Medical Certification (ksrevenue.gov); 49 CFR 383.71."},"38":{"q":"Согласно правилам Канзаса/федеральным правилам, «цистерна» (tank vehicle) для подтверждения N — это, как правило, транспортное средство, предназначенное для перевозки жидкости или газа в постоянно или временно прикреплённом баке с расчётной вместимостью не менее:","options":["100 галлонов","500 галлонов","1 000 галлонов","5 000 галлонов"],"explanation":"Подтверждение N (цистерна) применяется к транспортным средствам, перевозящим жидкие или газообразные материалы в баках с суммарной расчётной вместимостью 1 000 галлонов или более (отдельные баки по 119 галлонов или более). Источник: Руководство по CDL Канзаса (KDOR); 49 CFR 383.5."},"39":{"q":"Водитель хочет объединить подтверждения «Опасные материалы» и «Цистерна» на CDL Канзаса. Какой единый код подтверждения представляет эту комбинацию?","options":["X","T","P","L"],"explanation":"Канзас использует код подтверждения «X» для обозначения комбинации подтверждений «Опасные материалы» (H) и «Цистерна» (N). Источник: K.S.A. 8-2,135; Руководство по CDL Канзаса (KDOR)."},"40":{"q":"В Канзасе какова максимальная концентрация алкоголя в крови (BAC), при которой лицо может законно управлять коммерческим транспортным средством (CMV)?","options":["0.08% или выше — это предел","Любой BAC ниже 0.04%","Любой BAC ниже 0.10%","Любой BAC ниже 0.02%"],"explanation":"Канзас запрещает управление CMV с BAC 0.04% или более; законный предел для водителей CMV — ниже 0.04%, что вдвое меньше предела 0.08% для обычных водителей. Источник: Руководство по CDL Канзаса, Раздел 1 (Дисквалификации водителей); 49 CFR 383.51 в редакции, принятой в Канзасе."},"41":{"q":"На какой срок дисквалифицируется владелец CDL Канзаса за ПЕРВОЕ серьёзное нарушение, такое как вождение в нетрезвом виде (DUI) на CMV, когда НЕ перевозятся опасные материалы с табличками?","options":["60 дней","1 год","3 года","6 месяцев"],"explanation":"Первое серьёзное нарушение (DUI, отказ от теста, оставление места происшествия, использование CMV в совершении тяжкого преступления и т. д.) влечёт за собой дисквалификацию на 1 год в Канзасе. Источник: K.S.A. 8-2,142; Руководство по CDL Канзаса; 49 CFR 383.51."},"42":{"q":"Если водитель в Канзасе совершает первое серьёзное нарушение ВО ВРЕМЯ перевозки опасных материалов, требующих размещения табличек, на какой срок наступает дисквалификация?","options":["1 год","3 года","Пожизненно","120 дней"],"explanation":"Первое серьёзное нарушение во время управления CMV, перевозящим опасные материалы с табличками, влечёт за собой дисквалификацию на 3 года в Канзасе, а не стандартный 1 год. Источник: K.S.A. 8-2,142; Руководство по CDL Канзаса; 49 CFR 383.51."},"43":{"q":"Каков срок дисквалификации в Канзасе за ВТОРОЕ серьёзное нарушение, совершённое на CMV?","options":["3 года","10 лет","Пожизненно","5 лет"],"explanation":"Второе серьёзное нарушение влечёт за собой пожизненную дисквалификацию CDL в Канзасе. Источник: K.S.A. 8-2,142; Руководство по CDL Канзаса; 49 CFR 383.51(b)."},"44":{"q":"Согласно правилам подразумеваемого согласия в Канзасе, владелец CDL, который ОТКАЗЫВАЕТСЯ от химического теста дыхания или крови, рассматривается как совершивший что?","options":["Серьёзное нарушение правил дорожного движения","Серьёзное правонарушение (major offense)","Нарушение приказа о выводе из эксплуатации (out-of-service)","Не подлежащее регистрации правонарушение"],"explanation":"Отказ от законно запрошенного химического теста классифицируется как серьёзное правонарушение (major offense), влекущее ту же дисквалификацию на 1 год (или 3 года для HazMat), что и DUI. Источник: K.S.A. 8-2,142; Руководство по CDL Канзаса, Раздел 1."},"45":{"q":"На какой срок дисквалифицируется владелец CDL Канзаса за отказ от химического теста во время управления CMV, НЕ перевозящим опасные материалы с табличками?","options":["90 дней","1 год","3 года","Пожизненно"],"explanation":"Первый отказ от теста на CMV влечёт за собой дисквалификацию CDL на 1 год (3 года при перевозке опасных материалов с табличками — HazMat). Источник: K.S.A. 8-2,142; 49 CFR 383.51."},"46":{"q":"Когда водитель с CDL Канзаса набирает ДВА серьёзных нарушения правил дорожного движения в течение 3-летнего периода (на CMV), минимальная дисквалификация составляет:","options":["30 дней","60 дней","120 дней","1 год"],"explanation":"Два серьёзных нарушения правил дорожного движения в течение 3 лет влекут за собой минимальную дисквалификацию на 60 дней в Канзасе. Источник: Руководство по CDL Канзаса, Раздел 1; 49 CFR 383.51(c)."},"47":{"q":"Когда водитель с CDL Канзаса набирает ТРИ серьёзных нарушения правил дорожного движения в течение 3-летнего периода (на CMV), минимальная дисквалификация составляет:","options":["60 дней","90 дней","120 дней","180 дней"],"explanation":"Три серьёзных нарушения правил дорожного движения в течение 3 лет влекут за собой минимальную дисквалификацию на 120 дней в Канзасе. Источник: Руководство по CDL Канзаса, Раздел 1; 49 CFR 383.51(c)."},"48":{"q":"Что из следующего считается «серьёзным нарушением правил дорожного движения» для владельца CDL Канзаса?","options":["Превышение скорости на 15 миль/ч или более","Превышение скорости на 5 миль/ч","Нарушение правил парковки","Просроченная наклейка о регистрации"],"explanation":"Серьёзные нарушения правил дорожного движения включают превышение скорости на 15 миль/ч или более, безрассудное вождение, неправильное или беспорядочное перестроение, слишком близкое следование и нарушения, связанные с дорожно-транспортным происшествием со смертельным исходом. Источник: Руководство по CDL Канзаса, Раздел 1; 49 CFR 383.51(c)."},"49":{"q":"Согласно правилам CDL Канзаса/федеральным правилам, управление CMV во время НАБОРА ТЕКСТОВЫХ СООБЩЕНИЙ классифицируется как какой тип правонарушения?","options":["Серьёзное правонарушение (major offense)","Серьёзное нарушение правил дорожного движения","Нарушение приказа о выводе из эксплуатации (out-of-service)","Нарушение на железнодорожном переезде"],"explanation":"Набор текстовых сообщений во время управления CMV и использование мобильного телефона в руке во время управления CMV являются серьёзными нарушениями правил дорожного движения, которые учитываются при дисквалификациях 2-в-3-года (60 дней) и 3-в-3-года (120 дней). Источник: Руководство по CDL Канзаса; 49 CFR 383.51(c) и 392.80/392.82."},"50":{"q":"Для водителя с CDL Канзаса использование мобильного телефона В РУКЕ во время управления CMV рассматривается как:","options":["Не подлежащее регистрации правонарушение","Серьёзное нарушение правил дорожного движения","Серьёзное правонарушение (major offense)","Автоматический пожизненный запрет"],"explanation":"Управление CMV с использованием телефона в руке нарушает 49 CFR 392.82 и является серьёзным нарушением правил дорожного движения; водителю грозит федеральный гражданский штраф (до $2,750), и нарушение учитывается при дисквалификациях за серьёзные нарушения. Источник: Руководство по CDL Канзаса; 49 CFR 392.82, 383.51(c)."},"51":{"q":"Каков срок дисквалификации для владельца CDL Канзаса за ПЕРВОЕ осуждение за нарушение на железнодорожно-автомобильном переезде?","options":["Не менее 30 дней","Не менее 60 дней","Не менее 120 дней","Не менее 180 дней"],"explanation":"Первое нарушение на железнодорожно-автомобильном переезде влечёт за собой дисквалификацию не менее чем на 60 дней в Канзасе. Источник: Руководство по CDL Канзаса, Раздел 1; 49 CFR 383.51(d)."},"52":{"q":"Владелец CDL Канзаса совершает ВТОРОЕ нарушение на железнодорожно-автомобильном переезде в течение 3-летнего периода. Минимальная дисквалификация составляет:","options":["60 дней","90 дней","120 дней","1 год"],"explanation":"Второе нарушение на железнодорожном переезде в течение 3 лет влечёт за собой дисквалификацию не менее чем на 120 дней. Источник: Руководство по CDL Канзаса, Раздел 1; 49 CFR 383.51(d)."},"53":{"q":"Владелец CDL Канзаса совершает ТРЕТЬЕ нарушение на железнодорожно-автомобильном переезде в течение 3-летнего периода. Минимальная дисквалификация составляет:","options":["120 дней","180 дней","Не менее 1 года","2 года"],"explanation":"Третье нарушение на железнодорожном переезде в течение 3 лет влечёт за собой дисквалификацию не менее чем на 1 год. Источник: Руководство по CDL Канзаса, Раздел 1; 49 CFR 383.51(d)."},"54":{"q":"Какова минимальная дисквалификация для водителя с CDL Канзаса за ПЕРВОЕ нарушение приказа о выводе из эксплуатации (out-of-service) (не HazMat, не пассажирское)?","options":["Не менее 60 дней","Не менее 90 дней","Не менее 180 дней","Не менее 1 года"],"explanation":"Первое нарушение приказа о выводе из эксплуатации влечёт за собой дисквалификацию не менее чем на 180 дней (и не более 1 года) в Канзасе. Источник: Руководство по CDL Канзаса, Раздел 1; 49 CFR 383.51(e)."},"55":{"q":"Каков диапазон дисквалификации за ВТОРОЕ нарушение приказа о выводе из эксплуатации (out-of-service) в течение 10 лет для водителя с CDL Канзаса (не HazMat, не пассажирское)?","options":["От 180 дней до 1 года","От 1 до 3 лет","От 2 до 5 лет","От 3 до 5 лет"],"explanation":"Второе нарушение приказа о выводе из эксплуатации в течение 10 лет влечёт за собой дисквалификацию не менее чем на 2 года и не более чем на 5 лет. Источник: Руководство по CDL Канзаса, Раздел 1; 49 CFR 383.51(e)."},"56":{"q":"Водитель с CDL Канзаса совершает ПЕРВОЕ нарушение приказа о выводе из эксплуатации (out-of-service) во время перевозки опасных материалов с табличками или перевозки пассажиров. Дисквалификация составляет:","options":["Не менее 60 дней","Не менее 180 дней, до 2 лет","Не менее 90 дней, до 1 года","Пожизненно"],"explanation":"Первое нарушение приказа о выводе из эксплуатации во время перевозки опасных материалов с табличками (HazMat) или перевозки пассажиров влечёт за собой дисквалификацию не менее чем на 180 дней и не более чем на 2 года (в отличие от срока до 1 года для обычных грузов). Источник: Руководство по CDL Канзаса; 49 CFR 383.51(e)."},"57":{"q":"В Канзасе водитель CMV, у которого обнаружено ЛЮБОЕ определяемое количество алкоголя в организме (даже ниже 0.04%) во время исполнения обязанностей, подлежит чему?","options":["Немедленной пожизненной дисквалификации","Выводу из эксплуатации на 24 часа","Дисквалификации на 1 год","Дисквалификации на 60 дней"],"explanation":"Водитель CMV с любым измеримым или определяемым количеством алкоголя (ниже 0.04%) выводится из эксплуатации на 24 часа; BAC 0.04% или более становится серьёзным правонарушением (дисквалификация на 1 год). Источник: Руководство по CDL Канзаса, Раздел 1; 49 CFR 392.5."},"58":{"q":"Помимо дисквалификации, какое дополнительное наказание может наложить гражданский штраф Канзаса/федеральный на ТРАНСПОРТНУЮ КОМПАНИЮ, которая сознательно позволяет водителю работать во время действия приказа о выводе из эксплуатации (out-of-service)?","options":["Штраф от $2,750 до $11,000","Фиксированный штраф в $500","Потеря разрешения компании на эксплуатацию на 60 дней","К компании не применяется наказание"],"explanation":"Работодатель, который сознательно позволяет или требует от водителя нарушить приказ о выводе из эксплуатации, подлежит гражданскому штрафу от $2,750 до $11,000 в дополнение к дисквалификации и штрафу водителя. Источник: Руководство по CDL Канзаса; 49 CFR 383.53(b)."},"59":{"q":"Владелец CDL Канзаса осуждён за серьёзное правонарушение, а затем, спустя годы, осуждён за второе серьёзное правонарушение. После пожизненной дисквалификации восстановление может быть возможным только:","options":["Через 1 год","Через 5 лет","Минимум через 10 лет, при выполнении условий","Это никогда не возможно"],"explanation":"Пожизненная дисквалификация за два серьёзных правонарушения может, согласно правилам, принятым FMCSA, быть сокращена минимум до 10 лет, если водитель выполнит предписанные условия; некоторые пожизненные запреты (например, использование CMV для производства/распространения наркотиков) являются постоянными. Источник: Руководство по CDL Канзаса; 49 CFR 383.51(b)."},"60":{"q":"В Канзасе, когда школьный автобус с пассажирами приближается к железнодорожному переезду, на каком расстоянии от ближайшего рельса водитель обязан остановиться?","options":["В пределах 50 футов, но не ближе 15 футов от ближайшего рельса","В пределах 25 футов, но не ближе 5 футов от ближайшего рельса","В пределах 75 футов, но не ближе 25 футов от ближайшего рельса","В пределах 100 футов, но не ближе 50 футов от ближайшего рельса"],"explanation":"Канзас требует, чтобы определённые транспортные средства останавливались в пределах 50 футов, но не ближе 15 футов от ближайшего рельса, а также смотрели и прислушивались перед переездом. Источник: K.S.A. 8-1551; Kansas CDL Manual (KDOR)."},"61":{"q":"Согласно законодательству Канзаса, коммерческое транспортное средство с табличками об опасных грузах, обязанное останавливаться на железнодорожном переезде, должно полностью остановиться на каком расстоянии от ближайшего рельса?","options":["Не ближе 10 футов и не дальше 30 футов","Не ближе 15 футов и не дальше 50 футов","Не ближе 20 футов и не дальше 60 футов","Не ближе 5 футов и не дальше 25 футов"],"explanation":"Транспортные средства с табличками HazMat должны останавливаться в пределах 50 футов, но не ближе 15 футов от ближайшего рельса и продолжать движение только тогда, когда это безопасно. Источник: K.S.A. 8-1551; Kansas CDL Manual (KDOR)."},"62":{"q":"Закон Канзаса «Move Over» был расширен начиная с 1 июля 2025 года. Что действующий закон требует от водителя, приближающегося к остановившемуся транспортному средству?","options":["Перестроиться только ради полицейских, пожарных машин и машин скорой помощи","Перестроиться только ради аварийных машин и эвакуаторов","Перестроиться ради ЛЮБОГО неподвижного транспортного средства с мигающими или аварийными огнями, а не только ради аварийных машин","Перестроиться только тогда, когда офицер стоит снаружи транспортного средства"],"explanation":"Senate Bill 8 (вступивший в силу 1 июля 2025 года) расширил K.S.A. 8-1530, поэтому водители должны перестроиться или снизить скорость ради любого неподвижного транспортного средства с мигающими/аварийными огнями. Источник: K.S.A. 8-1530; Kansas SB 8 (2025)."},"63":{"q":"На автомагистрали Канзаса с двумя или более полосами в направлении движения водителя, что требует закон «Move Over» при проезде мимо неподвижного транспортного средства с включёнными предупредительными огнями?","options":["Всегда полностью останавливаться, пока транспортное средство не уедет","Непрерывно сигналить во время проезда","Сохранять обычную скорость, но включить аварийные огни","Перестроиться в полосу, не примыкающую к остановившемуся транспортному средству, если это можно сделать безопасно"],"explanation":"K.S.A. 8-1530(b) требует, чтобы водители на многополосных дорогах перестраивались в непримыкающую полосу, если это безопасно; если это невозможно — снижали скорость и продолжали движение с должной осторожностью. Источник: K.S.A. 8-1530; Kansas CDL Manual (KDOR)."},"64":{"q":"Согласно закону Канзаса «Move Over», если перестроиться в сторону от остановившегося транспортного средства с предупредительными огнями небезопасно или невозможно, что должен сделать водитель?","options":["Остановиться в полосе движения и ждать","Снизить скорость и поддерживать безопасную скорость с учётом состояния дороги, погоды и условий движения","Продолжать движение с установленной максимально разрешённой скоростью","Съехать на обочину и остановиться"],"explanation":"Когда перестроение невозможно или небезопасно, K.S.A. 8-1530(b) требует, чтобы водитель продолжал движение с должной осторожностью, снижал скорость и поддерживал безопасную скорость. Источник: K.S.A. 8-1530."},"65":{"q":"Какова максимальная установленная разрешённая скорость на многополосной автомагистрали с разделёнными проезжими частями (межштатной автомагистрали) в Канзасе, установленная министром транспорта?","options":["70 mph","65 mph","75 mph","80 mph"],"explanation":"Канзас устанавливает максимальную скорость на многополосных автомагистралях с разделёнными проезжими частями в 75 mph, как обозначено и установлено министром транспорта. Источник: K.S.A. 8-1558."},"66":{"q":"Устанавливает ли Канзас для грузовиков/CMV отдельный, более низкий максимальный предел скорости в масштабах штата, чем для легковых автомобилей на своих межштатных автомагистралях?","options":["Да — грузовики ограничены 65 mph в масштабах штата, а легковые автомобили могут двигаться со скоростью 75 mph","Да — грузовики ограничены 60 mph на всех межштатных автомагистралях","Да — грузовики ограничены 55 mph в ночное время в масштабах штата","Нет — для грузовиков и легковых автомобилей в Канзасе применяется одинаковый максимальный установленный предел"],"explanation":"Канзас не вводит отдельный предел скорости для грузовиков в масштабах штата; одинаковый установленный максимум применяется ко всем транспортным средствам, если знаки не указывают иное. Источник: K.S.A. 8-1558; KDOT."},"67":{"q":"Согласно K.S.A. 8-1558, каков максимальный законный предел скорости на дороге округа или городка в Канзасе?","options":["55 mph","45 mph","65 mph","60 mph"],"explanation":"Канзас устанавливает максимум на дорогах округов или городков в 55 mph, на других (немногополосных) дорогах — в 65 mph, а в городских районах — 30 mph. Источник: K.S.A. 8-1558."},"68":{"q":"Согласно K.S.A. 8-1558, каков максимальный законный предел скорости в городском районе в Канзасе, если не установлено иное?","options":["25 mph","35 mph","30 mph","20 mph"],"explanation":"Установленный законом максимум в городском районе составляет 30 mph, если не установлен иной предел. Источник: K.S.A. 8-1558."},"69":{"q":"На двухполосной (неразделённой) дороге Канзаса, что должен сделать водитель, встречающий остановившийся школьный автобус с мигающими красными огнями?","options":["Снизить скорость до 20 mph и проехать с осторожностью","Перестроиться в дальнюю полосу и продолжить движение мимо автобуса","Остановиться только если дети явно переходят дорогу","Остановиться, не доезжая до автобуса, и не продолжать движение, пока красные огни не перестанут мигать или автобус не тронется"],"explanation":"Водители, встречающие или обгоняющие школьный автобус с мигающими красными огнями, должны остановиться, не доезжая до него, и оставаться на месте, пока огни не погаснут или автобус не тронется. Источник: K.S.A. 8-1556."},"70":{"q":"На разделённой автомагистрали Канзаса с отдельными проезжими частями, каково исключение из правила остановки для школьного автобуса, забирающего детей?","options":["Водителю на иной проезжей части, чем автобус, останавливаться не нужно","Водителю в полосе, ближайшей к автобусу, останавливаться не нужно","Исключений не существует; все водители всегда обязаны останавливаться","Водитель может продолжать движение, если автобус находится дальше 100 футов"],"explanation":"K.S.A. 8-1556 предусматривает, что водителю на дороге с отдельными проезжими частями не нужно останавливаться ради школьного автобуса на ИНОЙ проезжей части (или в зоне посадки с контролируемым доступом, где пешеходы не могут переходить дорогу). Источник: K.S.A. 8-1556."},"71":{"q":"Согласно исключению Канзаса об отдельных проезжих частях для школьных автобусов, какой сценарий всё же ТРЕБУЕТ остановки транспорта во всех направлениях?","options":["Разделённая автомагистраль, где автобус находится на противоположной проезжей части за разделительной полосой","Неразделённая двухполосная дорога без физического разделения между направлениями","Автомагистраль с контролируемым доступом, где автобус находится в зоне посадки и пешеходы не могут переходить дорогу","Две проезжие части, физически разделённые барьером"],"explanation":"Исключение применяется только там, где имеются ОТДЕЛЬНЫЕ проезжие части. На неразделённой дороге без разделения транспорт в обоих направлениях обязан останавливаться. Источник: K.S.A. 8-1556."},"72":{"q":"В Канзасе базовый штраф за незаконный проезд мимо остановившегося школьного автобуса с мигающими красными огнями составляет какую из следующих сумм?","options":["$75, без увеличения","$150, удваивается только в школьных зонах","$500 фиксированно за каждое нарушение","$315, с увеличивающимися штрафами за повторные нарушения"],"explanation":"Единая шкала штрафов Канзаса устанавливает базовый штраф в $315 за незаконный проезд мимо школьного автобуса, с увеличивающимися штрафами за последующие нарушения. Источник: K.S.A. 8-2118."},"73":{"q":"Когда водитель CDL в Канзасе останавливает коммерческое транспортное средство на обочине разделённой автомагистрали, где следует разместить самый дальний светоотражающий предупредительный треугольник?","options":["Примерно в 200 футах позади транспортного средства в сторону приближающегося транспорта","Примерно в 50 футах позади транспортного средства","Примерно в 500 футах позади транспортного средства","Примерно в 150 футах позади транспортного средства"],"explanation":"На разделённой/односторонней автомагистрали треугольники размещаются на 10 футов, 100 футов и 200 футов в сторону приближающегося транспорта. Источник: Kansas CDL Manual (KDOR); 49 CFR 392.22."},"74":{"q":"Водитель CDL в Канзасе останавливается на односторонней или разделённой автомагистрали. Каково правильное размещение всех трёх светоотражающих треугольников в сторону приближающегося транспорта?","options":["10 футов, 50 футов и 150 футов позади","10 футов, 100 футов и 200 футов позади","25 футов, 100 футов и 250 футов позади","5 футов, 75 футов и 175 футов позади"],"explanation":"На разделённых/односторонних дорогах размещайте треугольники на 10, 100 и 200 футов в сторону приближающегося транспорта. Источник: Kansas CDL Manual (KDOR); 49 CFR 392.22."},"75":{"q":"После остановки CMV на двухполосной двусторонней дороге Канзаса, как скоро водитель обязан выставить требуемые аварийные предупредительные устройства?","options":["В течение 30 минут после остановки","В течение 1 часа после остановки","В течение 10 минут после остановки","Только если остановка длится дольше 2 часов"],"explanation":"Аварийные предупредительные устройства должны быть выставлены в течение 10 минут после остановки на автомагистрали или обочине. Источник: Kansas CDL Manual (KDOR); 49 CFR 392.22."},"76":{"q":"На двухполосной двусторонней дороге Канзаса, где водитель CMV должен разместить три предупредительных треугольника после остановки?","options":["Один в пределах 10 футов позади, один примерно в 100 футах позади и один примерно в 100 футах впереди транспортного средства","Все три в пределах 10 футов позади транспортного средства","Один в 200 футах позади и два впереди транспортного средства","Один в 50 футах позади и два по бокам транспортного средства"],"explanation":"На двусторонней дороге размещайте один треугольник в 10 футах позади, один примерно в 100 футах позади и один примерно в 100 футах впереди. Источник: Kansas CDL Manual (KDOR); 49 CFR 392.22."},"77":{"q":"Когда водитель автобуса с CDL в Канзасе пересекает железнодорожные пути на переезде, чего водитель НЕ должен делать, пока любая часть автобуса находится на путях?","options":["Держать автобус на пониженной передаче","Смотреть и прислушиваться перед въездом","Переключать передачи во время пересечения путей","Держать дверь закрытой"],"explanation":"Водители должны пересекать железнодорожные пути на передаче, которая не потребует переключения, и не должны переключать передачи, пока любая часть транспортного средства находится на путях. Источник: Kansas CDL Manual (KDOR)."},"78":{"q":"Какой факт о маршрутизации действительно отличает коммерческие перевозки в Канзасе?","options":["Все межштатные автомагистрали Канзаса бесплатны и не имеют коммерческих маршрутов","Значительная часть I-35, I-335, I-470 и I-70 образует платную Kansas Turnpike, где разрешены сдвоенные 53-футовые прицепы","Канзас запрещает все грузовики длиннее 40 футов на каждой межштатной автомагистрали","Канзас требует, чтобы все грузовики использовали только дороги US (немежштатные)"],"explanation":"Kansas Turnpike (KTA), протяжённостью около 236 миль вдоль I-35/I-335/I-470/I-70, является платной дорогой, на которой разрешены сдвоенные 53-футовые прицепы. Источник: KDOT; Kansas Turnpike Authority."},"79":{"q":"Какое агентство Канзаса выдаёт разрешения на негабаритные/сверхтяжёлые грузы и утверждает маршруты грузовиков через систему K-TRIPS?","options":["Kansas Department of Revenue (KDOR)","Лицензионное подразделение Kansas Highway Patrol","Federal Motor Carrier Safety Administration","Kansas Department of Transportation (KDOT)"],"explanation":"KDOT администрирует разрешения на негабаритные/сверхтяжёлые грузы и маршрутизацию через систему Kansas Truck Routing and Intelligent Permitting System (K-TRIPS). Источник: KDOT Commercial Vehicle Information."},"80":{"q":"Какое государственное агентство Канзаса выдаёт коммерческие водительские удостоверения (CDL)?","options":["Federal Motor Carrier Safety Administration","Kansas Department of Transportation (KDOT)","Kansas Department of Revenue, Division of Vehicles","Kansas Highway Patrol"],"explanation":"В Канзасе CDL выдаётся Kansas Department of Revenue (KDOR), Division of Vehicles, которое также публикует руководство Kansas CDL manual. KDOT занимается дорогами и разрешениями, но не лицензированием водителей. Источник: страница CDL Kansas DOR Division of Vehicles (ksrevenue.gov/dovcdl.html)."},"81":{"q":"Прежде чем заявитель в Канзасе сможет сдать практический экзамен на CDL, необходимо сдать как теоретический экзамен, так и экзамен по навыкам. Какие два общих типа экзаменов, согласно руководству Kansas CDL manual, вы должны сдать, чтобы получить CDL или CLP?","options":["Только письменный экзамен и проверку зрения","Только медицинский осмотр и проверку биографии","Экзамен по дорожным знакам и курс безопасного вождения","Теоретические экзамены и экзамены по навыкам"],"explanation":"В руководстве Kansas CDL manual говорится: «Чтобы получить CDL или CLP, вы должны сдать теоретические экзамены и экзамены по навыкам». Проверка зрения и медицинская сертификация являются отдельными требованиями. Источник: Kansas CDL Manual, Section 1.1, «Commercial Driver License Tests»."},"82":{"q":"Экзамен по навыкам на CDL в Канзасе состоит из трёх частей, которые необходимо проходить в установленном порядке. Какая последовательность верна?","options":["Вождение по дороге, затем осмотр транспортного средства, затем базовое управление транспортным средством","Осмотр транспортного средства, затем базовое управление транспортным средством, затем вождение по дороге","Осмотр транспортного средства, затем вождение по дороге, затем базовое управление транспортным средством","Базовое управление транспортным средством, затем вождение по дороге, затем осмотр транспортного средства"],"explanation":"В руководстве Kansas CDL manual указано, что экзамен по навыкам состоит из трёх частей — осмотр транспортного средства, базовое управление транспортным средством и вождение по дороге — и вы должны проходить их именно в таком порядке и сдавать каждую, прежде чем переходить к следующей. Источник: Kansas CDL Manual, Section 1.1.2, «Skills Tests»."},"83":{"q":"Из скольких категорий самосертификации должен выбрать заявитель на CDL в Канзасе при декларировании типа коммерческой деятельности, в которой он работает?","options":["Пять","Три","Четыре","Две"],"explanation":"Канзас требует, чтобы заявители/держатели CDL самостоятельно сертифицировались по одной из четырёх категорий коммерческой деятельности. Источник: Kansas CDL Manual, Section 1.2 («the four types of commerce you must self-certify») и страница Kansas DOR Medical Certification Information."},"84":{"q":"Какая из следующих категорий является одной из четырёх категорий самосертификации CDL в Канзасе?","options":["Provisional Intrastate","Non-excepted Interstate","Restricted Interstate","Exempt Federal"],"explanation":"Четыре категории самосертификации Канзаса — это Non-excepted Interstate, Excepted Interstate, Non-excepted Intrastate и Excepted Intrastate. «Restricted», «Provisional» и «Exempt Federal» категориями не являются. Источник: страница Kansas DOR Medical Certification Information; Kansas CDL Manual Section 1.2."},"85":{"q":"Что должен сделать водитель в Канзасе, самостоятельно сертифицировавшийся как «Non-excepted Interstate», чтобы сохранить «сертифицированный» медицинский статус?","options":["Постоянно возить бумажную копию своего медосмотра в кабине","Ежегодно сдавать дополнительный теоретический экзамен по пневматическим тормозам","Поддерживать действующий сертификат медицинского эксперта (медицинскую карту DOT)","Продлевать свой CDL каждый год вместо каждых четырёх лет"],"explanation":"Водители категории non-excepted interstate должны предоставить и поддерживать действующим федеральный сертификат медицинского эксперта (49 CFR 391.45), иначе они становятся «не сертифицированными» и могут лишиться CDL. Источник: Kansas CDL Manual, Section 1.2, Medical Documentation Requirements."},"86":{"q":"Начиная со 2 июня 2025 года, каким образом сертификат медицинского эксперта (MEC) держателя CDL в Канзасе должен поступать в Division of Vehicles?","options":["Отправляется водителем по почте на абонентский ящик KDOR в Топике","Отправляется работодателем водителя по факсу в KDOR","Лично доставляется водителем в любую станцию приёма экзаменов на удостоверение","В электронном виде из National Registry of Certified Medical Examiners"],"explanation":"Начиная со 2 июня 2025 года, Канзас больше не принимает MEC, предоставленные водителем, и больше не может вводить их вручную; сертифицированные данные должны поступать в электронном виде из National Registry of Certified Medical Examiners (их вводит сам эксперт). Источник: страница Kansas DOR Medical Certification Information (ksrevenue.gov/dovmedcertfaq.html)."},"87":{"q":"В рамках процесса Канзаса от июня 2025 года, сколько времени есть у сертифицированного медицинского эксперта, чтобы внести новый MEC в National Registry?","options":["Немедленно, прежде чем водитель покинет кабинет","До полуночи следующего календарного дня","В течение 10 рабочих дней после осмотра","В течение 30 дней после осмотра"],"explanation":"Канзас отмечает, что медицинский эксперт имеет время до полуночи следующего дня, чтобы внести MEC в National Registry, откуда Канзас затем получает его в электронном виде. Источник: страница Kansas DOR Medical Certification Information."},"88":{"q":"Для впервые подающих заявление на CDL в Канзасе, когда должно быть выполнено федеральное требование о начальной подготовке водителей (ELDT)?","options":["В течение 30 дней после выдачи CDL","Только после первого нарушения, связанного с движением","Перед сдачей экзамена по навыкам на CDL","Перед первым продлением CDL"],"explanation":"ELDT (вступившая в силу 7 февраля 2022 года) требует теоретической подготовки и подготовки за рулём у поставщика, зарегистрированного FMCSA, завершённой до того, как заявитель сможет сдавать экзамен по навыкам на CDL. Этот федеральный стандарт применяется в Канзасе. Источник: правило FMCSA ELDT (49 CFR Part 380, Subpart F); FMCSA Training Provider Registry."},"89":{"q":"Начинающий заявитель на CDL в Канзасе должен получить требуемую подготовку ELDT у поставщика, который указан где?","options":["В списке утверждённых школ Kansas DOR","В реестре перевозчиков Kansas Highway Patrol","В National Registry of Certified Medical Examiners","В FMCSA Training Provider Registry (TPR)"],"explanation":"ELDT должна предоставляться школой, указанной в FMCSA Training Provider Registry (TPR); о завершении сообщается в электронном виде в FMCSA до того, как штат разрешит сдачу экзамена по навыкам. Источник: FMCSA Entry-Level Driver Training, Training Provider Registry."},"90":{"q":"Получение какого из следующих допусков впервые влечёт за собой требование о подготовке ELDT до сдачи экзамена?","options":["Только допуск к пневматическим тормозам","Пассажирский (P), Школьный автобус (S) или Опасные материалы (H)","Только сдвоенные/строенные прицепы (T)","Только цистерна (N)"],"explanation":"ELDT применяется к впервые подающим заявление на CDL, при переходе с Class B на A и при получении впервые допусков P, S или H. Допуски на сдвоенные/строенные прицепы и цистерну сами по себе не влекут ELDT. Источник: применимость FMCSA ELDT (49 CFR Part 380, Subpart F)."},"91":{"q":"Повышение существующего CDL Class B до CDL Class A в Канзасе требует какого дополнительного шага согласно федеральному правилу ELDT?","options":["Ничего дополнительного; повышение происходит автоматически","Сначала владеть CDL Class B не менее пяти лет","Пересдать только общий теоретический экзамен","Завершить ELDT для повышения до Class A перед экзаменом по навыкам"],"explanation":"Повышение с Class B до Class A является одной из операций, охватываемых ELDT, поэтому водитель должен завершить программу подготовки для повышения у поставщика из списка TPR перед сдачей экзамена по навыкам на Class A. Источник: правило FMCSA ELDT (49 CFR Part 380, Subpart F)."},"92":{"q":"После того как заявителю в Канзасе выдан CLP, как долго он должен ждать, прежде чем сможет сдавать экзамен по навыкам на CDL?","options":["Не менее 30 дней","Не менее 60 дней","Не менее 14 дней","Не менее 7 дней"],"explanation":"Держатель CLP должен владеть разрешением не менее 14 дней, прежде чем сдавать экзамен по навыкам на CDL. Это федеральное требование применяется в Канзасе. Источник: 49 CFR 383.25; Kansas CDL applicant guidance."},"93":{"q":"Как часто необходимо продлевать стандартный CDL в Канзасе?","options":["Каждые 6 лет","Каждые 8 лет","Каждые 2 года","Каждые 4 года"],"explanation":"CDL в Канзасе выдаются на 4-летний цикл и должны продлеваться каждые четыре года, независимо от 6-летнего цикла, используемого для некоторых некоммерческих удостоверений Канзаса. Источник: Kansas DOR Division of Vehicles licensing information."},"94":{"q":"Каков минимальный возраст для получения CDL в Канзасе для внутриштатных перевозок (только в пределах Канзаса)?","options":["18 лет","19 лет","21 год","16 лет"],"explanation":"CDL в Канзасе для внутриштатных перевозок может быть выдан в возрасте 18 лет; для межштатных перевозок (и опасных грузов) требуется возраст 21 год. Источник: Kansas CDL Manual; правила квалификации водителей FMCSA (49 CFR 391.11)."},"95":{"q":"Каков минимальный возраст для управления коммерческим транспортным средством в межштатных перевозках с CDL Канзаса?","options":["25 лет","21 год","18 лет","23 года"],"explanation":"Для управления CMV в межштатных перевозках, а также для перевозки опасных грузов, водитель должен быть в возрасте не менее 21 года. Водители 18–20 лет ограничены внутриштатными перевозками. Источник: правила квалификации водителей FMCSA (49 CFR 391.11); Kansas CDL guidance."},"96":{"q":"Какой набор документов лучше всего отражает то, что заявитель в Канзасе должен предоставить для подачи заявления на CLP/CDL?","options":["Только паспорт, без необходимости подтверждения места жительства","Подтверждение личности/даты рождения, номер Social Security, законное присутствие и два подтверждения проживания в Канзасе","Аттестат об окончании средней школы и рекомендательное письмо от работодателя","Только действующее некоммерческое удостоверение Канзаса и фотографию"],"explanation":"Канзас требует подтверждение личности/даты рождения, подтверждение номера Social Security, подтверждение законного присутствия и два документа, подтверждающих проживание в Канзасе (физический адрес); заявители также уже должны иметь некоммерческое водительское удостоверение Канзаса. Источник: Kansas DOR Division of Vehicles application requirements."},"97":{"q":"Вопрос о процессе в Канзасе по сборам: какое утверждение о сборах за CDL является верным для обучения заявителей?","options":["Сбор за CDL навсегда зафиксирован законом Канзаса и никогда не меняется","Канзас не взимает плату за CDL или его допуски","Сборы за CDL устанавливаются федерально FMCSA и одинаковы в каждом штате","Сборы за CDL и допуски устанавливаются Канзасом и могут меняться, поэтому заявителям следует уточнять текущие суммы в KDOR"],"explanation":"Сборы за CDL, допуски и CLP устанавливаются штатом и могут изменяться; заявителям следует уточнять текущие суммы в Kansas DOR, а не полагаться на фиксированную цифру. Сборы устанавливаются штатом, а не являются федерально едиными. Источник: Kansas DOR Division of Vehicles fee schedule guidance."}},"tr":{"0":{"q":"Kansas karayollarında, izin olmaksızın bir aracın veya yükünün izin verilen azami toplam dış genişliği nedir?","options":["8 fit (96 inç)","8 1/2 fit (102 inç)","9 fit (108 inç)","10 fit (120 inç)"],"explanation":"K.S.A. 8-1902, herhangi bir aracın veya yükünün toplam dış genişliğini 8 1/2 fit (102 inç) ile sınırlar. Kansas CDL el kitabı ve Kansas Karayolu Devriyesi de aynı standart genişlik sınırını belirtir."},"1":{"q":"Kansas karayollarında, yükü dahil bir aracın genel azami yüksekliği nedir?","options":["13 fit 6 inç","14 fit","14 fit 6 inç","15 fit"],"explanation":"K.S.A. 8-1904, azami araç yüksekliğini (yük dahil) 14 fit olarak belirler. Kansas Karayolu Devriyesi yasal yükseklik sınırını 14 fit olarak teyit eder."},"2":{"q":"Kansas, bir tür yükün 14 fitlik yükseklik sınırını aşmasına ve 14 1/2 fite kadar sabitlenmesine izin verir. Bu yük hangisidir?","options":["Balyalanmış pamuk","Silindir biçimli saman balyaları","İnşaat çelik kirişleri","Nakliye konteynerleri"],"explanation":"K.S.A. 8-1904, silindir biçimli saman balyaları taşıyan bir aracın 14 1/2 fite kadar yüklenmesine izin verir; yük bir üst geçide çarparsa oluşacak her türlü hasardan sürücü sorumludur."},"3":{"q":"Kansas karayollarında, tek bir motorlu aracın (düz kamyon gibi) yükü dahil azami uzunluğu nedir?","options":["40 fit","45 fit","48 fit","53 fit"],"explanation":"K.S.A. 8-1904, tek bir motorlu aracı, yükü dahil, azami 45 fit toplam uzunlukla sınırlar."},"4":{"q":"Bir çekici ve yarı römork kombinasyonunda, Kansas'ta yarı römorka izin verilen azami uzunluk nedir?","options":["48 fit","53 fit","57 fit","59 1/2 fit"],"explanation":"K.S.A. 8-1904, bir çekiciyle kombinasyon halinde çalıştırılan bir yarı römorkun uzunluğunun 59 1/2 fiti aşamayacağını öngörür."},"5":{"q":"Kansas karayollarında, izin olmaksızın bir aracın herhangi bir tek dingiline izin verilen azami brüt ağırlık nedir?","options":["18.000 pound","20.000 pound","22.000 pound","24.000 pound"],"explanation":"K.S.A. 8-1908, herhangi bir tek dingildeki brüt ağırlığı 20.000 pound (ve herhangi bir tek tekerlekteki ağırlığı 10.000 pound) ile sınırlar."},"6":{"q":"Kansas'ta izin olmaksızın bir tandem dingil grubuna izin verilen azami brüt ağırlık nedir?","options":["32.000 pound","34.000 pound","36.000 pound","40.000 pound"],"explanation":"K.S.A. 8-1908, tandem dingillerdeki brüt ağırlığı, federal standartla uyumlu olarak 34.000 pound ile sınırlar."},"7":{"q":"Kansas yasalarına göre bir aracın herhangi bir tek tekerleğine düşen azami brüt ağırlık nedir?","options":["8.000 pound","10.000 pound","12.000 pound","17.000 pound"],"explanation":"K.S.A. 8-1908, bir aracın herhangi bir tekerleğine düşen brüt ağırlığın 10.000 poundu aşamayacağını belirtir."},"8":{"q":"Kansas'ta Eyaletlerarası karayolu sisteminde, izin olmaksızın izin verilen azami brüt araç ağırlığı nedir?","options":["73.280 pound","80.000 pound","85.500 pound","90.000 pound"],"explanation":"K.S.A. 8-1909 uyarınca, dingil aralığı ağırlık tablosu, federal yasayla uyumlu olarak Eyaletlerarası sistemde 80.000 poundtan fazla brüt ağırlığa izin veremez."},"9":{"q":"Kansas'ta Eyaletlerarası sistemin parçası OLMAYAN eyalet ve ABD karayollarında, dingil aralığı tablosu azami ne kadar brüt ağırlığa izin verebilir?","options":["80.000 pound","85.500 pound","90.000 pound","94.000 pound"],"explanation":"K.S.A. 8-1909'un dingil aralığı tablosu, Kansas ve ABD (Eyaletlerarası olmayan) karayollarında 80.000 poundluk Eyaletlerarası üst sınırından daha yüksek olarak 85.500 pounda kadar brüt ağırlığa izin verir."},"10":{"q":"Kansas, iki veya daha fazla ardışık dingilden oluşan bir gruptaki azami brüt ağırlığı esas olarak hangi yöntemi kullanarak belirler?","options":["Römork başına sabit bir ağırlık üst sınırı","Bir dingil aralığı ağırlık tablosu (köprü formülü)","Yalnızca lastik sayısı","Yalnızca kamyonun tescilli ağırlığı"],"explanation":"K.S.A. 8-1909, ardışık dingiller grubundaki azami ağırlığı belirlemek için dingiller arasındaki mesafeye ve dingil sayısına dayanan bir dingil aralığı ağırlık tablosu kullanır; bu, federal köprü formülünün Kansas biçimidir."},"11":{"q":"Kansas köprü/dingil aralığı kavramına göre, bir araç bir dingil grubunda yasal olarak nasıl daha fazla toplam ağırlık taşıyabilir?","options":["Lastik basıncını artırarak","Dingilleri birbirinden daha uzağa açarak ve dingil ekleyerek","Römork uzunluğunu azaltarak","Römork taban yüksekliğini düşürerek"],"explanation":"K.S.A. 8-1909 dingil aralığı tablosu (köprü formülü), köprüleri korumak amacıyla dingiller arasındaki mesafe arttıkça ve dingil sayısı çoğaldıkça daha fazla toplam ağırlığa izin verir."},"12":{"q":"Kansas yasal boyut veya ağırlık sınırlarını aşan ve azaltılamayan (bölünemez) bir yük, seyahat edebilmesi için öncesinde neyi gerektirir?","options":["Gündüz seyahat ediyorsa hiçbir şey","KDOT'tan bir aşırı boyut/aşırı ağırlık izni","Gönderenden bir not","Yalnızca federal DOT muafiyeti"],"explanation":"Kansas DOR, yasal sınırları aşan bölünemez yükler için bir aşırı boyut/aşırı ağırlık izni gerektirir; izinler KDOT'un K-TRIPS sistemi aracılığıyla alınır."},"13":{"q":"Aşırı boyut/aşırı ağırlık izinleri için başvurmak ve bunları almak üzere hangi Kansas sistemi kullanılır?","options":["IRP Online","K-TRIPS (Kansas Kamyon Yönlendirme ve Akıllı İzin Sistemi)","IFTA Web","CDLIS"],"explanation":"KDOT, aşırı boyut/aşırı ağırlık izinlerini K-TRIPS (Kansas Kamyon Yönlendirme ve Akıllı İzin Sistemi) aracılığıyla düzenler; başvuranlar kaydolur ve araç, yük ve güzergah bilgilerini çevrimiçi olarak sunar."},"14":{"q":"Standart tek seferlik bir Kansas aşırı boyut/aşırı ağırlık izni genellikle ne kadar süre geçerlidir?","options":["24 saat","3 gün","7 gün","30 gün"],"explanation":"KDOT tek seferlik aşırı boyut/aşırı ağırlık izinleri genellikle düzenlendiği tarihten itibaren yedi gün geçerlidir."},"15":{"q":"Kansas'ta izinli bir aşırı boyutlu yükün hareketi genellikle günün hangi saatiyle sınırlandırılır?","options":["Gece veya gündüz herhangi bir zaman","Gün doğumundan yarım saat önce ile gün batımından yarım saat sonra arası","Yalnızca gece yarısı ile sabah 6 arası","Yalnızca hafta içi mesai saatlerinde"],"explanation":"KDOT izin koşulları, izinde belirtilen istisnalar dışında, aşırı boyutlu yük hareketini genellikle hafta sonları ve tatiller dahil olmak üzere gün doğumundan yarım saat önce ile gün batımından yarım saat sonra arasıyla sınırlandırır."},"16":{"q":"Kansas'ta bir araç veya yük, izin gerektirecek şekilde hangi genişlikte 'aşırı boyutlu' hale gelir?","options":["8 fitten fazla","8 fit 6 inçten fazla","10 fitten fazla","12 fitten fazla"],"explanation":"K.S.A. 8-1902 yasal genişliği 8 1/2 fit (8 fit 6 inç) olarak belirlediğinden, 8 fit 6 inçten daha geniş herhangi bir araç veya yük aşırı boyutludur ve bir KDOT izni gerektirir."},"17":{"q":"Rutin bir Kansas aşırı ağırlık izni kapsamında (KAR 36-1-37), tek bir dingile izin verilen azami ağırlık nedir?","options":["20.000 pound","22.000 pound","24.000 pound","26.000 pound"],"explanation":"KAR 36-1-37 kapsamındaki Kansas aşırı ağırlık izni sınırları, tek tahriksiz dingil azamisini 20.000 poundluk yasal sınırın üzerine, 22.000 pounda (ve tandem dingilleri 45.000 pounda) yükseltir."},"18":{"q":"Kansas, tarım ürünleri, malzemeler ve biyoyakıtlar için özel bir yıllık aşırı ağırlık BÖLÜNEBİLİR yük izni sunar. Bunun azami brüt ağırlığı nedir ve nerede izin verilmez?","options":["80.000 pound; ilçe yollarında değil","90.000 pound; Eyaletlerarası sistemde değil","100.000 pound; şehirler içinde değil","85.500 pound; köprülerde değil"],"explanation":"Kansas, tarımsal girdiler, ürünler, canlı hayvanlar ve biyoyakıtlar için en az altı dingille 90.000 pounda kadar yıllık bir aşırı ağırlık bölünebilir yük iznine izin verir ve bu tür araçlar Eyaletlerarası sistemde çalıştırılamaz."},"19":{"q":"Kansas'ta, 85.500 poundun üzerinde çalışan bir aracın hangi koşulda seyahat etmesi yasaktır?","options":["Yağmur yağdığında","Karayolu yüzeyinde buz, sıkışmış kar veya savrulan kar olduğunda","Hasat mevsiminde","Bir şehrin 50 mil yakınında"],"explanation":"K.S.A. 8-1919, 85.500 poundun üzerinde çalışan araçların karayolu yüzeyinde buz, sıkışmış kar veya savrulan kar olduğunda seyahat etmesini yasaklar."},"20":{"q":"Kansas'ta, herhangi bir çekilen ünitenin 10.000 pound GVWR'yi AŞMADIĞI durumlarda, 26.001 pound veya daha fazla brüt araç ağırlık derecelendirmesine sahip tek bir aracı çalıştırmak için hangi CDL sınıfı gereklidir?","options":["A Sınıfı","B Sınıfı","C Sınıfı","D Sınıfı"],"explanation":"Kansas, B Sınıfı CDL'yi 26.001 lbs veya daha fazla GVWR'ye sahip herhangi bir tek araç ya da 10.000 lbs GVWR'yi aşmayan bir üniteyi çeken böyle bir araç olarak tanımlar. Kaynak: Kansas CDL Kılavuzu (KDOR) ve K.S.A. 8-2,128."},"21":{"q":"Çekilen ünite 10.000 poundu aştığında bir Kansas A Sınıfı CDL'yi tanımlayan asgari brüt kombinasyon ağırlık derecelendirmesi nedir?","options":["18.000 pound","26.001 pound","33.000 pound","10.001 pound"],"explanation":"Bir Kansas A Sınıfı CDL, çekilen ünite(ler)in 10.000 lbs'den fazla GVWR'ye sahip olması koşuluyla, 26.001 lbs veya daha fazla GCWR'ye sahip herhangi bir araç kombinasyonunu kapsar. Kaynak: Kansas CDL Kılavuzu (KDOR); K.S.A. 8-2,128."},"22":{"q":"Bir sürücü, GVWR'si 26.001 poundun altında olan bir vanda plakart gerektiren miktarda tehlikeli madde taşımaktadır. Hangi Kansas CDL sınıfı ve onay kombinasyonu geçerlidir?","options":["Onaysız A Sınıfı","N onaylı B Sınıfı","H onaylı C Sınıfı","P onaylı D Sınıfı"],"explanation":"Bir araç A veya B Sınıfı ağırlık tanımlarını karşılamıyorsa ancak plakart gerektiren miktarlarda tehlikeli madde taşıyorsa (veya 16+ yolcu taşıyorsa), Kansas, tehlikeli madde için H onayı ile birlikte C Sınıfı CDL gerektirir. Kaynak: Kansas CDL Kılavuzu (KDOR); 49 CFR 383.91."},"23":{"q":"Bir Kansas CDL'sinde, 'N' onayı sürücünün ne yapmasına izin verir?","options":["Tank araçları çalıştırmak","Tehlikeli madde taşımak","Çift ve üçlü römork çekmek","Okul otobüsü kullanmak"],"explanation":"Kansas'ta 'N' onayı tank araçlarının çalıştırılmasına izin verir. Kaynak: K.S.A. 8-2,135; Kansas CDL Kılavuzu (KDOR)."},"24":{"q":"Çift ve üçlü römorkları çekmek için bir Kansas CDL'sinde hangi onay kodu gereklidir?","options":["P","H","T","S"],"explanation":"'T' onayı çift ve üçlü römork çekmeye izin verir; yalnızca bir bilgi sınavını geçerek alınır (ayrı bir beceri sınavı yoktur). Kaynak: K.S.A. 8-2,135; Kansas CDL Kılavuzu (KDOR)."},"25":{"q":"Bir araç, sürücü dahil 16 veya daha fazla kişi taşımak için tasarlanmıştır. Hangi Kansas CDL onayı gereklidir (okul otobüsü istisnası dışında)?","options":["N (tanker)","P (yolcu)","T (çift/üçlü)","H (tehlikeli madde)"],"explanation":"'P' (yolcu) onayı, sürücü dahil 16 veya daha fazla kişi taşımak için tasarlanmış araçlar için gereklidir ve hem bir bilgi hem de bir beceri sınavını gerektirir. Kaynak: Kansas CDL Kılavuzu (KDOR); 49 CFR 383.93."},"26":{"q":"Kansas'ta Okul Otobüsü (S) onayını almak için sürücünün ayrıca hangi onaya sahip olması gerekir?","options":["H (tehlikeli madde)","N (tank aracı)","P (yolcu)","T (çift/üçlü)"],"explanation":"Kansas, sürücülerin 'S' (okul otobüsü) onayını eklemeden önce ilk olarak 'P' (yolcu) onayına sahip olmasını gerektirir; bu onay ayrıca ek bilgi ve beceri sınavlarının geçilmesini de gerektirir. Kaynak: Kansas CDL Kılavuzu (KDOR); 49 CFR 383.93."},"27":{"q":"Kansas, Tehlikeli Madde (H) onayını düzenlemeden önce, başvuru sahibinin hangi ek federal şartı yerine getirmesi gerekir?","options":["Bir TSA güvenlik tehdit değerlendirmesi (geçmiş kontrolü)","FMCSA'dan bir görüş muafiyeti","30 günlük bir yol çıraklığı","Bir hava freni beceri yeniden sınavı"],"explanation":"H (tehlikeli madde) onayı, Kansas bunu düzenlemeden önce bir bilgi sınavının VE parmak izi ve geçmiş kontrolünü içeren bir TSA Güvenlik Tehdit Değerlendirmesinin geçilmesini gerektirir. Kaynak: Kansas CDL Kılavuzu (KDOR); 49 CFR 383.71/1572."},"28":{"q":"Yalnızca eyalet içi (Kansas içi) sürüş ile sınırlı bir Kansas CDL almak için asgari yaş nedir?","options":["16 yaş","17 yaş","18 yaş","21 yaş"],"explanation":"Kansas, yalnızca eyalet içi çalışma için bir CDL almak üzere sürücünün en az 18 yaşında olmasını gerektirir. Kaynak: Kansas CDL Kılavuzu (KDOR); K.S.A. 8-2,129."},"29":{"q":"Eyaletlerarası sürüş (eyalet sınırlarının ötesinde) veya tehlikeli madde taşımak için bir Kansas CDL almak için asgari yaş nedir?","options":["18 yaş","19 yaş","20 yaş","21 yaş"],"explanation":"Bir sürücünün eyaletlerarası ticarette CMV kullanmak, tehlikeli madde taşımak veya eyalet sınırları ötesine yolcu taşımak için en az 21 yaşında olması gerekir. Kaynak: Kansas CDL Kılavuzu (KDOR); 49 CFR 391.11."},"30":{"q":"Kansas'ta bir Ticari Öğrenme İzni (CLP) ilk düzenlendikten sonra, başvuru sahibinin CDL beceri sınavına girmeye hak kazanmadan önce bunu ne kadar süre elinde tutması gerekir?","options":["En az 7 gün","En az 14 gün","En az 30 gün","En az 60 gün"],"explanation":"Kansas tarafından benimsenen federal kural: Bir CLP sahibi, izni asgari 14 gün boyunca elinde tutmadan CDL beceri sınavına girmeye hak kazanamaz. Kaynak: Kansas CDL Kılavuzu (KDOR); 49 CFR 383.25."},"31":{"q":"Bir Kansas CLP sahibi, pratik için bir ticari motorlu araç kullanırken ne yapmalıdır?","options":["Yalnızca gün doğumu ile gün batımı arasında sürmeli","Yanında ön koltukta oturan bir CDL sahibi bulunmalı","Sürüşü evin 25 millik yarıçapı ile sınırlamalı","Hiçbir türde yük taşımamalı"],"explanation":"Bir Kansas CLP sahibi, bir CMV'yi yalnızca araç türü için geçerli bir CDL'ye sahip olan ve sürücünün yanındaki ön koltukta oturması gereken bir kişi eşliğinde çalıştırabilir. Kaynak: Kansas CDL Kılavuzu (KDOR); 49 CFR 383.25."},"32":{"q":"Kansas tarafından benimsenen federal standartlara göre, bir Ticari Öğrenme İzni, yeniden sınava girmeksizin azami hangi süreden daha uzun geçerli OLMAMALIDIR?","options":["90 gün","6 ay","1 yıl","5 yıl"],"explanation":"Bir CLP, başvuru sahibinin bilgi sınavlarını yeniden almasını gerektirmeden ilk düzenlenmesinden itibaren en fazla bir yıl için düzenlenebilir. Kaynak: Kansas CDL Kılavuzu (KDOR); 49 CFR 383.25."},"33":{"q":"Bir Kansas CDL başvuru sahibi başvururken Araçlar Bölümüne hangi belge setini sunmalıdır?","options":["Kimlik kanıtı, Sosyal Güvenlik numarası, Kansas ikametgahı ve yasal mevcudiyet","Yalnızca bir Sosyal Güvenlik kartı ve bir doğum belgesi","Bir pasaport ve bir araç tescili","İstihdam kanıtı ve bir tehlikeli madde izni"],"explanation":"Kansas Gelir İdaresi, Araçlar Bölümü, başvuru sahiplerinin kimliklerini kanıtlamalarını, Sosyal Güvenlik numaralarını vermelerini ve Kansas ikametgahı ile yasal (hukuki) mevcudiyet kanıtı göstermelerini gerektirir. Kaynak: Kansas Gelir İdaresi, Araçlar Bölümü (ksrevenue.gov)."},"34":{"q":"Kansas'ın ilk kez A/B Sınıfı başvuru sahipleri için gerektirdiği Giriş Düzeyi Sürücü Eğitimi (ELDT), aşağıdaki niteliklere sahip bir eğitim kuruluşu tarafından sağlanmalıdır:","options":["Yerel okul bölgesi tarafından onaylanmış","FMCSA Eğitim Sağlayıcı Kaydı'nda listelenmiş","Kansas Karayolu Devriyesi tarafından sertifikalandırılmış","ABD Eğitim Bakanlığı tarafından akredite edilmiş"],"explanation":"7 Şubat 2022'den bu yana, Kansas belirli beceri/bilgi sınavlarına izin vermeden önce ELDT, FMCSA Eğitim Sağlayıcı Kaydı'nda (TPR) listelenmiş bir sağlayıcı aracılığıyla tamamlanmalıdır. Kaynak: Kansas Gelir İdaresi (dovcdlentry.html); 49 CFR Part 380."},"35":{"q":"Aşağıdaki ilk kez yapılan işlemlerden hangisi Kansas'ta federal ELDT şartını TETİKLEMEZ?","options":["İlk kez bir A Sınıfı CDL almak","Bir B Sınıfı CDL'yi A Sınıfı CDL'ye yükseltmek","İlk kez Tehlikeli Madde (H) onayını almak","Yeni onay olmadan mevcut bir A Sınıfı CDL'yi yenilemek"],"explanation":"ELDT, ilk kez A/B Sınıfı düzenlenmesi, B'den A'ya Sınıf yükseltmesi ve ilk kez H, P veya S onayları için geçerlidir. Yükseltme veya yeni onay içermeyen mevcut bir CDL'nin rutin yenilenmesi ELDT gerektirmez. Kaynak: Kansas Gelir İdaresi (dovcdlentry.html); 49 CFR Part 380."},"36":{"q":"Yalnızca Kansas içinde çalışan ve tıbbi gerekliliklerden muaf olmayan bir Kansas CDL sürücüsü hangi kategori olarak kendini sertifikalandırmalıdır?","options":["Muaf olmayan eyaletlerarası","Muaf eyaletlerarası","Muaf olmayan eyalet içi","Muaf eyalet içi"],"explanation":"Yalnızca Kansas içinde çalışan ve tıbbi sertifika şartına tabi olan bir sürücü, 'Muaf olmayan eyalet içi' olarak kendini sertifikalandırır ve güncel bir Tıbbi Muayene Sertifikası bulundurmalıdır. Kaynak: Kansas Gelir İdaresi, Tıbbi Sertifikasyon (ksrevenue.gov); 49 CFR 383.71."},"37":{"q":"Hangi Kansas CDL kendini sertifikalandırma kategorisi, sürücünün güncel bir federal Tıbbi Muayene Sertifikası bulundurmasını ve sunmasını gerektirir?","options":["Muaf eyaletlerarası","Muaf eyalet içi","Muaf olmayan eyaletlerarası","Kısıtlı çiftlik operatörü"],"explanation":"Muaf olmayan eyaletlerarası (ve muaf olmayan eyalet içi) olarak sertifikalandıran sürücüler güncel bir Tıbbi Muayene Sertifikası bulundurmalıdır; muaf sürücüler tıbbi belge sunmazlar. Kaynak: Kansas Gelir İdaresi, Tıbbi Sertifikasyon (ksrevenue.gov); 49 CFR 383.71."},"38":{"q":"Kansas/federal kurallara göre, N onayı için bir 'tank aracı' genellikle, kalıcı veya geçici olarak takılmış bir tankta en az şu kadar derecelendirilmiş kapasiteyle sıvı veya gaz taşımak üzere tasarlanmış olandır:","options":["100 galon","500 galon","1.000 galon","5.000 galon"],"explanation":"N (tank) onayı, 1.000 galon veya daha fazla toplam derecelendirilmiş kapasiteye sahip tanklarda (119 galon veya daha fazla bireysel tanklar) sıvı veya gaz halindeki maddeleri taşıyan araçlar için geçerlidir. Kaynak: Kansas CDL Kılavuzu (KDOR); 49 CFR 383.5."},"39":{"q":"Bir sürücü, bir Kansas CDL'sinde Tehlikeli Madde ve Tank onaylarını birleştirmek istiyor. Bu kombinasyonu hangi tek onay kodu temsil eder?","options":["X","T","P","L"],"explanation":"Kansas, Tehlikeli Madde (H) ve Tank (N) onaylarının kombinasyonunu temsil etmek için 'X' onay kodunu kullanır. Kaynak: K.S.A. 8-2,135; Kansas CDL Kılavuzu (KDOR)."},"40":{"q":"Kansas'ta, bir kişinin yasal olarak ticari bir motorlu aracı (CMV) çalıştırabileceği azami kandaki alkol konsantrasyonu (BAC) nedir?","options":["%0,08 veya daha yüksek sınırdır","%0,04'ün altındaki herhangi bir BAC","%0,10'un altındaki herhangi bir BAC","%0,02'nin altındaki herhangi bir BAC"],"explanation":"Kansas, %0,04 veya daha yüksek BAC ile bir CMV çalıştırmayı yasaklar; CMV sürücüleri için yasal sınır %0,04'ün altıdır, yani sıradan sürücüler için olan %0,08 sınırının yarısıdır. Kaynak: Kansas CDL Kılavuzu, Bölüm 1 (Sürücü Diskalifiyeleri); Kansas'ta benimsendiği şekliyle 49 CFR 383.51."},"41":{"q":"Plakartlı tehlikeli madde taşınMADIĞINDA, bir CMV'de DUI gibi İLK ciddi suç için bir Kansas CDL sahibi ne kadar süre diskalifiye edilir?","options":["60 gün","1 yıl","3 yıl","6 ay"],"explanation":"İlk ciddi suç (DUI, bir testi reddetme, olay yerinden ayrılma, bir CMV'yi bir suçta kullanma vb.) Kansas'ta 1 yıllık bir diskalifiye ile sonuçlanır. Kaynak: K.S.A. 8-2,142; Kansas CDL Kılavuzu; 49 CFR 383.51."},"42":{"q":"Bir Kansas sürücüsü, plakart gerektiren tehlikeli madde taşırken İLK ciddi suçu işlerse, diskalifiye süresi ne kadardır?","options":["1 yıl","3 yıl","Ömür boyu","120 gün"],"explanation":"Plakartlı tehlikeli madde taşıyan bir CMV çalıştırırken işlenen ilk ciddi suç, Kansas'ta standart 1 yıl yerine 3 yıllık bir diskalifiye ile sonuçlanır. Kaynak: K.S.A. 8-2,142; Kansas CDL Kılavuzu; 49 CFR 383.51."},"43":{"q":"Bir CMV'de işlenen İKİNCİ ciddi suç için Kansas'taki diskalifiye süresi nedir?","options":["3 yıl","10 yıl","Ömür boyu","5 yıl"],"explanation":"İkinci ciddi suç, Kansas'ta CDL'nin ömür boyu diskalifiyesiyle sonuçlanır. Kaynak: K.S.A. 8-2,142; Kansas CDL Kılavuzu; 49 CFR 383.51(b)."},"44":{"q":"Kansas zımni rıza kurallarına göre, nefes veya kan kimyasal testini REDDEDEN bir CDL sahibi ne işlemiş sayılır?","options":["Ciddi bir trafik ihlali","Bir ciddi suç","Bir hizmet dışı bırakma ihlali","Bildirilemeyen bir suç"],"explanation":"Yasal olarak talep edilen bir kimyasal testi reddetmek bir ciddi suç olarak sınıflandırılır ve bir DUI ile aynı 1 yıllık (veya tehlikeli madde için 3 yıllık) diskalifiyeyi taşır. Kaynak: K.S.A. 8-2,142; Kansas CDL Kılavuzu, Bölüm 1."},"45":{"q":"Plakartlı tehlikeli madde taşımayan bir CMV kullanırken kimyasal testi reddeden bir Kansas CDL sahibi ne kadar süre diskalifiye edilir?","options":["90 gün","1 yıl","3 yıl","Ömür boyu"],"explanation":"Bir CMV'de ilk test reddi 1 yıllık bir CDL diskalifiyesiyle sonuçlanır (plakartlı tehlikeli madde taşınıyorsa 3 yıl). Kaynak: K.S.A. 8-2,142; 49 CFR 383.51."},"46":{"q":"Bir Kansas CDL sürücüsü 3 yıllık bir süre içinde (bir CMV'de) İKİ ciddi trafik ihlali biriktirdiğinde, asgari diskalifiye şudur:","options":["30 gün","60 gün","120 gün","1 yıl"],"explanation":"3 yıl içinde iki ciddi trafik ihlali, Kansas'ta asgari 60 günlük bir diskalifiye ile sonuçlanır. Kaynak: Kansas CDL Kılavuzu, Bölüm 1; 49 CFR 383.51(c)."},"47":{"q":"Bir Kansas CDL sürücüsü 3 yıllık bir süre içinde (bir CMV'de) ÜÇ ciddi trafik ihlali biriktirdiğinde, asgari diskalifiye şudur:","options":["60 gün","90 gün","120 gün","180 gün"],"explanation":"3 yıl içinde üç ciddi trafik ihlali, Kansas'ta asgari 120 günlük bir diskalifiye ile sonuçlanır. Kaynak: Kansas CDL Kılavuzu, Bölüm 1; 49 CFR 383.51(c)."},"48":{"q":"Aşağıdakilerden hangisi bir Kansas CDL sahibi için 'ciddi trafik ihlali' sayılır?","options":["Hız sınırının 15 mph veya daha fazla üzerinde sürmek","Hız sınırının 5 mph üzerinde sürmek","Bir park ihlali","Süresi dolmuş bir tescil etiketi"],"explanation":"Ciddi trafik ihlalleri arasında sınırın 15 mph veya daha fazla üzerinde hız yapmak, dikkatsiz sürüş, uygunsuz veya düzensiz şerit değiştirme, çok yakından takip etme ve ölümlü bir kazayla bağlantılı trafik suçları yer alır. Kaynak: Kansas CDL Kılavuzu, Bölüm 1; 49 CFR 383.51(c)."},"49":{"q":"Kansas/federal CDL kurallarına göre, bir CMV'yi kullanırken MESAJ YAZMAK hangi tür suç olarak sınıflandırılır?","options":["Bir ciddi suç","Bir ciddi trafik ihlali","Bir hizmet dışı bırakma ihlali","Bir demiryolu geçidi ihlali"],"explanation":"Bir CMV kullanırken mesaj yazmak ve bir CMV kullanırken elde tutulan bir cep telefonu kullanmak, 3 yılda 2 (60 gün) ve 3 yılda 3 (120 gün) diskalifiyelere sayılan ciddi trafik ihlalleridir. Kaynak: Kansas CDL Kılavuzu; 49 CFR 383.51(c) ve 392.80/392.82."},"50":{"q":"Bir Kansas CDL sürücüsü için, bir CMV'yi çalıştırırken ELDE TUTULAN bir cep telefonu kullanmak şöyle değerlendirilir:","options":["Bildirilemeyen bir ihlal","Bir ciddi trafik ihlali","Bir ciddi suç","Otomatik ömür boyu yasak"],"explanation":"Bir CMV kullanırken elde tutulan bir telefon kullanmak 49 CFR 392.82'yi ihlal eder ve bir ciddi trafik ihlalidir; sürücü federal bir hukuki ceza (2.750 dolara kadar) ile karşı karşıya kalır ve ihlal ciddi ihlal diskalifiyelerine sayılır. Kaynak: Kansas CDL Kılavuzu; 49 CFR 392.82, 383.51(c)."},"51":{"q":"Bir Kansas CDL sahibinin İLK demiryolu-karayolu hemzemin geçit ihlali mahkumiyeti için diskalifiye süresi nedir?","options":["30 günden az olmamak üzere","60 günden az olmamak üzere","120 günden az olmamak üzere","180 günden az olmamak üzere"],"explanation":"İlk demiryolu-karayolu hemzemin geçit ihlali, Kansas'ta 60 günden az olmamak üzere bir diskalifiye ile sonuçlanır. Kaynak: Kansas CDL Kılavuzu, Bölüm 1; 49 CFR 383.51(d)."},"52":{"q":"Bir Kansas CDL sahibi 3 yıllık bir süre içinde İKİNCİ bir demiryolu-karayolu hemzemin geçit ihlali işler. Asgari diskalifiye şudur:","options":["60 gün","90 gün","120 gün","1 yıl"],"explanation":"3 yıl içinde ikinci bir demiryolu geçit ihlali, 120 günden az olmamak üzere bir diskalifiye ile sonuçlanır. Kaynak: Kansas CDL Kılavuzu, Bölüm 1; 49 CFR 383.51(d)."},"53":{"q":"Bir Kansas CDL sahibi 3 yıllık bir süre içinde ÜÇÜNCÜ bir demiryolu-karayolu hemzemin geçit ihlali işler. Asgari diskalifiye şudur:","options":["120 gün","180 gün","1 yıldan az olmamak üzere","2 yıl"],"explanation":"3 yıl içinde üçüncü bir demiryolu geçit ihlali, 1 yıldan az olmamak üzere bir diskalifiye ile sonuçlanır. Kaynak: Kansas CDL Kılavuzu, Bölüm 1; 49 CFR 383.51(d)."},"54":{"q":"Bir Kansas CDL sürücüsünün İLK hizmet dışı bırakma emri ihlali (tehlikeli madde dışı, yolcu dışı) için asgari diskalifiye nedir?","options":["60 günden az olmamak üzere","90 günden az olmamak üzere","180 günden az olmamak üzere","1 yıldan az olmamak üzere"],"explanation":"İlk hizmet dışı bırakma emri ihlali, Kansas'ta 180 günden az olmamak (ve 1 yıldan fazla olmamak) üzere bir diskalifiye ile sonuçlanır. Kaynak: Kansas CDL Kılavuzu, Bölüm 1; 49 CFR 383.51(e)."},"55":{"q":"Bir Kansas CDL sürücüsü için 10 yıl içinde İKİNCİ bir hizmet dışı bırakma emri ihlali için diskalifiye aralığı nedir (tehlikeli madde dışı, yolcu dışı)?","options":["180 gün ile 1 yıl","1 ile 3 yıl","2 ile 5 yıl","3 ile 5 yıl"],"explanation":"10 yıl içinde ikinci bir hizmet dışı bırakma emri ihlali, 2 yıldan az ve 5 yıldan fazla olmamak üzere bir diskalifiye ile sonuçlanır. Kaynak: Kansas CDL Kılavuzu, Bölüm 1; 49 CFR 383.51(e)."},"56":{"q":"Bir Kansas CDL sürücüsü, plakartlı tehlikeli madde taşırken veya yolcu taşırken İLK hizmet dışı bırakma emri ihlalini işler. Diskalifiye şudur:","options":["60 günden az olmamak üzere","180 günden az olmamak üzere, 2 yıla kadar","90 günden az olmamak üzere, 1 yıla kadar","Ömür boyu"],"explanation":"Plakartlı tehlikeli madde taşırken veya yolcu taşırken işlenen ilk hizmet dışı bırakma emri ihlali, 180 günden az ve 2 yıldan fazla olmamak üzere bir diskalifiye ile sonuçlanır (sıradan yükler için 1 yıla kadar olanın aksine). Kaynak: Kansas CDL Kılavuzu; 49 CFR 383.51(e)."},"57":{"q":"Kansas'ta, görev başındayken sisteminde HERHANGİ bir tespit edilebilir miktarda alkol (%0,04'ün altında bile) bulunan bir CMV sürücüsü neye tabidir?","options":["Anında ömür boyu diskalifiye","24 saat hizmet dışı bırakılma","1 yıllık diskalifiye","60 günlük diskalifiye"],"explanation":"Ölçülebilir veya tespit edilebilir herhangi bir alkole (%0,04'ün altında) sahip bir CMV sürücüsü 24 saat hizmet dışı bırakılır; %0,04 veya daha fazla BAC bir ciddi suç (1 yıllık diskalifiye) haline gelir. Kaynak: Kansas CDL Kılavuzu, Bölüm 1; 49 CFR 392.5."},"58":{"q":"Diskalifiyenin yanı sıra, bir sürücünün bir hizmet dışı bırakma emri sırasında çalışmasına bilerek izin veren bir KAMYON TAŞIMACILIĞI ŞİRKETİNE bir Kansas/federal hukuki ceza hangi ek cezayı uygulayabilir?","options":["2.750 ila 11.000 dolar para cezası","Sabit 500 dolar para cezası","Şirketin işletme yetkisinin 60 gün kaybı","Şirkete hiçbir ceza uygulanmaz"],"explanation":"Bir sürücünün bir hizmet dışı bırakma emrini ihlal etmesine bilerek izin veren veya bunu gerektiren bir işveren, sürücünün diskalifiyesine ve para cezasına ek olarak 2.750 ila 11.000 dolar hukuki cezaya tabidir. Kaynak: Kansas CDL Kılavuzu; 49 CFR 383.53(b)."},"59":{"q":"Bir Kansas CDL sahibi bir ciddi suçtan mahkum olur ve daha sonra, yıllar sonra, ikinci bir ciddi suçtan mahkum olur. Ömür boyu bir diskalifiyeden sonra, yeniden yetkilendirme yalnızca şu durumda mümkün olabilir:","options":["1 yıl sonra","5 yıl sonra","Koşullar yerine getirilirse, asgari 10 yıl sonra","Hiçbir zaman mümkün değildir"],"explanation":"İki ciddi suç için ömür boyu bir diskalifiye, FMCSA tarafından benimsenen kurallar çerçevesinde, sürücü öngörülen koşulları yerine getirirse asgari 10 yıla indirilebilir; bazı ömür boyu yasaklar (örneğin, uyuşturucu üretmek/dağıtmak için bir CMV kullanmak) kalıcıdır. Kaynak: Kansas CDL Kılavuzu; 49 CFR 383.51(b)."},"60":{"q":"Kansas eyaletinde, yolcu taşıyan bir okul otobüsü hemzemin demir yolu geçidine yaklaştığında, sürücü en yakın raydan ne kadar mesafede durmalıdır?","options":["En yakın raydan 50 fitten yakın ama 15 fitten az olmamak üzere","En yakın raydan 25 fitten yakın ama 5 fitten az olmamak üzere","En yakın raydan 75 fitten yakın ama 25 fitten az olmamak üzere","En yakın raydan 100 fitten yakın ama 50 fitten az olmamak üzere"],"explanation":"Kansas, belirli araçların en yakın raydan 50 fitten yakın ama 15 fitten az olmamak üzere durmasını ve geçmeden önce bakıp dinlemesini gerektirir. Kaynak: K.S.A. 8-1551; Kansas CDL El Kitabı (KDOR)."},"61":{"q":"Kansas yasalarına göre, demir yolu geçidinde durması gereken, tehlikeli madde plakartları taşıyan bir ticari araç en yakın raya ne kadar mesafede tam olarak durmalıdır?","options":["10 fitten yakın ve 30 fitten uzak olmayacak şekilde","15 fitten yakın ve 50 fitten uzak olmayacak şekilde","20 fitten yakın ve 60 fitten uzak olmayacak şekilde","5 fitten yakın ve 25 fitten uzak olmayacak şekilde"],"explanation":"Plakartlı HazMat araçları en yakın raydan 50 fitten yakın ama 15 fitten az olmamak üzere durmalı ve yalnızca güvenli olduğunda devam etmelidir. Kaynak: K.S.A. 8-1551; Kansas CDL El Kitabı (KDOR)."},"62":{"q":"Kansas'ın 'Şerit Değiştir' (Move Over) yasası 1 Temmuz 2025 tarihinden itibaren geçerli olmak üzere genişletildi. Mevcut yasa, duran bir araca yaklaşan bir sürücünün ne yapmasını gerektirir?","options":["Yalnızca polis, itfaiye ve ambulans araçları için şerit değiştirmek","Yalnızca acil durum araçları ve çekiciler için şerit değiştirmek","Sadece acil durum araçları için değil, yanıp sönen veya tehlike (dörtlü) lambaları yanan HERHANGİ bir duran araç için şerit değiştirmek","Yalnızca bir memur aracın dışında dururken şerit değiştirmek"],"explanation":"8 Sayılı Senato Tasarısı (1 Temmuz 2025'ten itibaren geçerli) K.S.A. 8-1530'u genişletti; böylece sürücüler yanıp sönen/tehlike lambaları yanan herhangi bir duran araç için şerit değiştirmeli veya yavaşlamalıdır. Kaynak: K.S.A. 8-1530; Kansas SB 8 (2025)."},"63":{"q":"Sürücünün gittiği yönde iki veya daha fazla şeridi olan bir Kansas otoyolunda, aktif uyarı lambaları yanan duran bir aracı geçerken Şerit Değiştir yasası ne gerektirir?","options":["Araç hareket edene kadar her zaman tamamen durmak","Geçerken kornaya sürekli basmak","Normal hızı korumak ama tehlike lambalarını açmak","Güvenli bir şekilde yapılabiliyorsa duran araca bitişik olmayan bir şeride geçmek"],"explanation":"K.S.A. 8-1530(b), çok şeritli yollarda sürücülerin güvenliyse bitişik olmayan bir şeride geçmesini gerektirir; mümkün değilse yavaşlayıp gereken dikkatle devam edilmelidir. Kaynak: K.S.A. 8-1530; Kansas CDL El Kitabı (KDOR)."},"64":{"q":"Kansas Şerit Değiştir yasasına göre, uyarı lambası yanan duran bir araçtan uzağa şerit değiştirmek güvenli değilse veya mümkün değilse, sürücü ne yapmalıdır?","options":["Seyir şeridinde durup beklemek","Hızı azaltmak ve yol, hava ve trafik koşulları için güvenli bir hız korumak","Belirlenen hız sınırında devam etmek","Banketin üzerine çekip durmak"],"explanation":"Şerit değiştirmek mümkün olmadığında veya güvenli olmadığında, K.S.A. 8-1530(b) sürücünün gereken dikkatle ilerlemesini, hızı azaltmasını ve güvenli bir hız korumasını gerektirir. Kaynak: K.S.A. 8-1530."},"65":{"q":"Ulaştırma Bakanı tarafından belirlenen şekilde, Kansas'ta ayrılmış çok şeritli (eyaletler arası) bir otoyolda belirlenen azami hız sınırı nedir?","options":["70 mph","65 mph","75 mph","80 mph"],"explanation":"Kansas, ayrılmış çok şeritli otoyollardaki azamiyi Ulaştırma Bakanı tarafından belirlenip işaretlendiği şekilde 75 mph olarak belirler. Kaynak: K.S.A. 8-1558."},"66":{"q":"Kansas, eyaletler arası yollarında kamyonlar/CMV'ler için, otomobillere kıyasla ayrı ve daha düşük bir eyalet çapında azami hız sınırı belirler mi?","options":["Evet - kamyonlar eyalet çapında 65 mph ile sınırlıyken otomobiller 75 mph gidebilir","Evet - kamyonlar tüm eyaletler arası yollarda 60 mph ile sınırlıdır","Evet - kamyonlar geceleri eyalet çapında 55 mph ile sınırlıdır","Hayır - Kansas'ta kamyonlar ve otomobiller için aynı azami belirlenen sınır geçerlidir"],"explanation":"Kansas, eyalet çapında ayrı bir kamyon hız sınırı uygulamaz; işaretler aksini belirtmedikçe tüm araçlar için aynı belirlenen azami geçerlidir. Kaynak: K.S.A. 8-1558; KDOT."},"67":{"q":"K.S.A. 8-1558 uyarınca, bir Kansas ilçe veya kasaba (township) karayolunda azami yasal hız sınırı nedir?","options":["55 mph","45 mph","65 mph","60 mph"],"explanation":"Kansas, ilçe veya kasaba karayollarında azamiyi 55 mph, diğer (çok şeritli olmayan) karayollarında 65 mph ve kentsel bölgelerde 30 mph olarak belirler. Kaynak: K.S.A. 8-1558."},"68":{"q":"K.S.A. 8-1558 uyarınca, aksi belirtilmedikçe Kansas'ta bir kentsel bölgede azami yasal hız sınırı nedir?","options":["25 mph","35 mph","30 mph","20 mph"],"explanation":"Bir kentsel bölgede yasal azami, farklı bir sınır işaretlenmedikçe 30 mph'dir. Kaynak: K.S.A. 8-1558."},"69":{"q":"Kansas'ta iki şeritli (bölünmemiş) bir yolda, yanıp sönen kırmızı lambaları yanan, durmuş bir okul otobüsüyle karşılaşan bir sürücü ne yapmalıdır?","options":["20 mph'ye yavaşlayıp dikkatle geçmek","En uzaktaki şeride geçip otobüsü geçerek devam etmek","Yalnızca çocuklar gözle görülür şekilde karşıdan karşıya geçiyorsa durmak","Otobüse ulaşmadan önce durmak ve kırmızı lambalar yanıp sönmeyi bırakana veya otobüs hareket edene kadar devam etmemek"],"explanation":"Yanıp sönen kırmızı lambaları yanan bir okul otobüsüyle karşılaşan veya onu geçen sürücüler, ona ulaşmadan önce durmalı ve lambalar sönene veya otobüs hareket edene kadar durmuş kalmalıdır. Kaynak: K.S.A. 8-1556."},"70":{"q":"Ayrı yol şeritleri olan bölünmüş bir Kansas otoyolunda, çocuk alan bir okul otobüsü için durma kuralının istisnası nedir?","options":["Otobüsten farklı bir yol şeridinde olan bir sürücünün durması gerekmez","Otobüse en yakın şeritteki bir sürücünün durması gerekmez","Hiçbir istisna geçerli değildir; tüm sürücüler her zaman durmalıdır","Otobüs 100 fitten daha uzaktaysa bir sürücü devam edebilir"],"explanation":"K.S.A. 8-1556, ayrı yol şeritleri olan bir karayolundaki bir sürücünün FARKLI bir yol şeridindeki (veya yayaların karşıya geçemeyeceği, erişimi kontrollü bir yükleme bölgesindeki) bir okul otobüsü için durması gerekmediğini öngörür. Kaynak: K.S.A. 8-1556."},"71":{"q":"Kansas okul otobüsü ayrı yol şeridi istisnasına göre, hangi senaryo hâlâ her yöndeki trafiğin durmasını GEREKTİRİR?","options":["Otobüsün bir refüjün karşısındaki ters yol şeridinde olduğu bölünmüş bir otoyol","Yönler arasında fiziksel ayrım olmayan, bölünmemiş iki şeritli bir yol","Otobüsün bir yükleme bölgesinde olduğu ve yayaların karşıya geçemediği, erişimi kontrollü bir otoyol","Bir bariyerle fiziksel olarak ayrılmış iki yol şeridi"],"explanation":"İstisna yalnızca AYRI yol şeritlerinin bulunduğu yerlerde geçerlidir. Ayrım olmayan bölünmemiş bir yolda, her iki yöndeki trafik durmalıdır. Kaynak: K.S.A. 8-1556."},"72":{"q":"Kansas'ta, kırmızı lambaları yanıp sönen, durmuş bir okul otobüsünü yasadışı bir şekilde geçmenin temel cezası aşağıdakilerden hangisidir?","options":["Artış olmaksızın $75","Yalnızca okul bölgelerinde iki katına çıkarılan $150","Her ihlal için sabit $500","Tekrarlanan ihlaller için artan cezalarla birlikte $315"],"explanation":"Kansas'ın standart ceza cetveli, bir okul otobüsünü yasadışı şekilde geçmek için $315 temel ceza belirler ve sonraki ihlaller için cezalar artar. Kaynak: K.S.A. 8-2118."},"73":{"q":"Bir Kansas CDL sürücüsü bölünmüş bir otoyolun banketinde ticari bir aracı durdurduğunda, en arkadaki yansıtıcı uyarı üçgeni nereye yerleştirilmelidir?","options":["Yaklaşan trafiğe doğru aracın yaklaşık 200 fit arkasına","Aracın yaklaşık 50 fit arkasına","Aracın yaklaşık 500 fit arkasına","Aracın yaklaşık 150 fit arkasına"],"explanation":"Bölünmüş/tek yönlü bir otoyolda, üçgenler yaklaşan trafiğe doğru 10 fit, 100 fit ve 200 fite yerleştirilir. Kaynak: Kansas CDL El Kitabı (KDOR); 49 CFR 392.22."},"74":{"q":"Bir Kansas CDL sürücüsü tek yönlü veya bölünmüş bir otoyolda durur. Üç yansıtıcı üçgenin tümünün yaklaşan trafiğe doğru doğru yerleşimi nedir?","options":["Arkaya doğru 10 fit, 50 fit ve 150 fit","Arkaya doğru 10 fit, 100 fit ve 200 fit","Arkaya doğru 25 fit, 100 fit ve 250 fit","Arkaya doğru 5 fit, 75 fit ve 175 fit"],"explanation":"Bölünmüş/tek yönlü yollarda, üçgenleri yaklaşan trafiğe doğru 10, 100 ve 200 fite yerleştirin. Kaynak: Kansas CDL El Kitabı (KDOR); 49 CFR 392.22."},"75":{"q":"Bir CMV'yi Kansas'ta iki şeritli, çift yönlü bir yolda durdurduktan sonra, bir sürücünün gerekli acil durum uyarı cihazlarını ne kadar süre içinde yerleştirmesi gerekir?","options":["Durduktan sonra 30 dakika içinde","Durduktan sonra 1 saat içinde","Durduktan sonra 10 dakika içinde","Yalnızca 2 saatten uzun durulursa"],"explanation":"Acil durum uyarı cihazları, bir karayolunda veya bankette durduktan sonra 10 dakika içinde yerleştirilmelidir. Kaynak: Kansas CDL El Kitabı (KDOR); 49 CFR 392.22."},"76":{"q":"Kansas'ta iki şeritli, çift yönlü bir yolda, bir CMV sürücüsü durduktan sonra üç uyarı üçgenini nereye yerleştirmelidir?","options":["Biri arkadan 10 fit içinde, biri yaklaşık 100 fit arkada ve biri aracın yaklaşık 100 fit önünde","Üçü de aracın arkasından 10 fit içinde","Biri 200 fit arkada ve ikisi aracın önünde","Biri 50 fit arkada ve ikisi aracın yan taraflarında"],"explanation":"Çift yönlü bir yolda, bir üçgeni arkaya 10 fit, birini yaklaşık 100 fit arkaya ve birini yaklaşık 100 fit öne yerleştirin. Kaynak: Kansas CDL El Kitabı (KDOR); 49 CFR 392.22."},"77":{"q":"Bir Kansas CDL otobüs sürücüsü bir geçitte demir yolu raylarını geçerken, otobüsün herhangi bir kısmı raylar üzerindeyken sürücünün NE yapmaması gerekir?","options":["Otobüsü düşük viteste tutmak","Girmeden önce bakıp dinlemek","Rayları geçerken vites değiştirmek","Kapıyı kapalı tutmak"],"explanation":"Sürücüler demir yolu raylarını vites değiştirmeyi gerektirmeyecek bir viteste geçmeli ve aracın herhangi bir kısmı raylar üzerindeyken vites değiştirmemelidir. Kaynak: Kansas CDL El Kitabı (KDOR)."},"78":{"q":"Hangi güzergâh bilgisi Kansas'taki ticari operasyonlara gerçekten özgüdür?","options":["Tüm Kansas eyaletler arası yolları ücretsizdir ve ticari güzergâh yoktur","I-35, I-335, I-470 ve I-70'in büyük bir kısmı, ikiz 53 fitlik treylerlere izin verilen ücretli Kansas Turnpike'ı oluşturur","Kansas, 40 fitten uzun tüm kamyonları her eyaletler arası yoldan yasaklar","Kansas, tüm kamyonların yalnızca US (eyaletler arası olmayan) karayollarını kullanmasını gerektirir"],"explanation":"Kansas Turnpike (KTA), I-35/I-335/I-470/I-70 boyunca yaklaşık 236 mil uzunluğunda, ikiz 53 fitlik treylerlere izin veren ücretli bir yoldur. Kaynak: KDOT; Kansas Turnpike Authority."},"79":{"q":"Hangi Kansas kurumu, gabari/ağırlık aşımı izinlerini verir ve K-TRIPS sistemi aracılığıyla kamyon güzergâhlarını onaylar?","options":["Kansas Gelir Dairesi (KDOR)","Kansas Karayolu Devriyesi ruhsat bölümü","Federal Motorlu Taşıyıcı Güvenliği İdaresi","Kansas Ulaştırma Dairesi (KDOT)"],"explanation":"KDOT, Kansas Kamyon Güzergâh Belirleme ve Akıllı İzin Sistemi (K-TRIPS) aracılığıyla gabari/ağırlık aşımı izinlerini ve güzergâh belirlemesini yönetir. Kaynak: KDOT Ticari Araç Bilgileri."},"80":{"q":"Hangi Kansas eyalet kurumu Ticari Sürücü Belgelerini (CDL) verir?","options":["Federal Motorlu Taşıyıcı Güvenliği İdaresi","Kansas Ulaştırma Dairesi (KDOT)","Kansas Gelir Dairesi, Araçlar Bölümü","Kansas Karayolu Devriyesi"],"explanation":"Kansas'ta CDL, aynı zamanda Kansas CDL el kitabını da yayımlayan Kansas Gelir Dairesi (KDOR) Araçlar Bölümü tarafından verilir. KDOT yolları ve izinleri ele alır ancak sürücü ruhsatlandırmasını değil. Kaynak: Kansas DOR Araçlar Bölümü CDL sayfası (ksrevenue.gov/dovcdl.html)."},"81":{"q":"Bir Kansas başvuru sahibi CDL beceri testine girmeden önce, hem bilgi hem de beceri testleri geçilmelidir. Kansas CDL el kitabı, bir CDL veya CLP almak için hangi iki genel test türünü geçmeniz gerektiğini söyler?","options":["Yalnızca bir yazılı test ve bir görme testi","Yalnızca bir tıbbi muayene ve bir geçmiş kontrolü","Bir trafik işaretleri testi ve bir savunmacı sürüş kursu","Bilgi testleri ve beceri testleri"],"explanation":"Kansas CDL el kitabı şunu belirtir: 'Bir CDL veya CLP almak için bilgi ve beceri testlerini geçmelisiniz.' Görme ve tıbbi sertifikasyon ayrı gerekliliklerdir. Kaynak: Kansas CDL El Kitabı, Bölüm 1.1, 'Ticari Sürücü Belgesi Testleri.'"},"82":{"q":"Kansas CDL beceri testi, belirli bir sırayla yapılması gereken üç bölümden oluşur. Hangi sıralama doğrudur?","options":["Yolda sürüş, ardından araç muayenesi, ardından temel araç kontrolü","Araç muayenesi, ardından temel araç kontrolü, ardından yolda sürüş","Araç muayenesi, ardından yolda sürüş, ardından temel araç kontrolü","Temel araç kontrolü, ardından yolda sürüş, ardından araç muayenesi"],"explanation":"Kansas CDL el kitabı, beceri testinin üç bölümü olduğunu belirtir -araç muayenesi, temel araç kontrolü ve yolda sürüş- ve bunları bu sırayla yapmanız ve bir sonrakine geçmeden önce her birini geçmeniz gerekir. Kaynak: Kansas CDL El Kitabı, Bölüm 1.1.2, 'Beceri Testleri.'"},"83":{"q":"Bir Kansas CDL başvuru sahibi, faaliyet gösterdiği ticaret türünü beyan ederken kaç öz-sertifikasyon kategorisinden seçim yapmalıdır?","options":["Beş","Üç","Dört","İki"],"explanation":"Kansas, CDL başvuru sahiplerinin/sahiplerinin dört ticaret kategorisinden birine öz-sertifikasyon yapmasını gerektirir. Kaynak: Kansas CDL El Kitabı, Bölüm 1.2 ('öz-sertifikasyon yapmanız gereken dört ticaret türü') ve Kansas DOR Tıbbi Sertifikasyon Bilgileri sayfası."},"84":{"q":"Aşağıdakilerden hangisi dört Kansas CDL öz-sertifikasyon kategorisinden biridir?","options":["Geçici Eyalet İçi (Provisional Intrastate)","İstisnasız Eyaletler Arası (Non-excepted Interstate)","Kısıtlı Eyaletler Arası (Restricted Interstate)","Muaf Federal (Exempt Federal)"],"explanation":"Dört Kansas öz-sertifikasyon kategorisi şunlardır: İstisnasız Eyaletler Arası (Non-excepted Interstate), İstisnalı Eyaletler Arası (Excepted Interstate), İstisnasız Eyalet İçi (Non-excepted Intrastate) ve İstisnalı Eyalet İçi (Excepted Intrastate). 'Restricted,' 'Provisional' ve 'Exempt Federal' birer kategori değildir. Kaynak: Kansas DOR Tıbbi Sertifikasyon Bilgileri sayfası; Kansas CDL El Kitabı Bölüm 1.2."},"85":{"q":"Kendisini 'Non-excepted Interstate' olarak öz-sertifikasyon yapan bir Kansas sürücüsü, 'sertifikalı' tıbbi statüsünü korumak için ne yapmalıdır?","options":["Fiziki muayenesinin bir kâğıt kopyasını her zaman kabinde taşımak","Her yıl ek bir hava frenleri bilgi testini geçmek","Güncel bir tıbbi muayene sertifikası (DOT tıbbi kartı) bulundurmak","CDL'lerini dört yılda bir yerine her yıl yenilemek"],"explanation":"İstisnasız eyaletler arası sürücüler, federal bir tıbbi muayene sertifikası (49 CFR 391.45) sunmalı ve güncel tutmalıdır; aksi takdirde 'sertifikasız' duruma düşerler ve CDL'lerini kaybedebilirler. Kaynak: Kansas CDL El Kitabı, Bölüm 1.2, Tıbbi Belge Gereklilikleri."},"86":{"q":"2 Haziran 2025 tarihinden itibaren geçerli olmak üzere, bir Kansas CDL sahibinin tıbbi muayene sertifikası (MEC) Araçlar Bölümü'ne nasıl ulaşmalıdır?","options":["Sürücü tarafından Topeka'daki KDOR posta kutusuna postalanarak","Sürücünün işvereni tarafından KDOR'a faksla gönderilerek","Sürücü tarafından herhangi bir ruhsat sınav istasyonuna elden teslim edilerek","Ulusal Sertifikalı Tıbbi Muayene Yapanlar Kayıt Sistemi'nden elektronik olarak"],"explanation":"2/6/2025 tarihinden itibaren geçerli olmak üzere, Kansas artık sürücü tarafından sunulan MEC'leri kabul etmez ve bunları artık manuel olarak giremez; sertifikalı veriler elektronik olarak Ulusal Sertifikalı Tıbbi Muayene Yapanlar Kayıt Sistemi'nden (muayeneyi yapan kişi girer) gelmelidir. Kaynak: Kansas DOR Tıbbi Sertifikasyon Bilgileri sayfası (ksrevenue.gov/dovmedcertfaq.html)."},"87":{"q":"Haziran 2025 Kansas sürecine göre, sertifikalı bir tıbbi muayene yapan kişinin yeni bir MEC'i Ulusal Kayıt Sistemi'ne girmek için ne kadar süresi vardır?","options":["Derhal, sürücü ofisten ayrılmadan önce","Bir sonraki takvim gününün gece yarısına kadar","Muayeneden sonra 10 iş günü içinde","Muayeneden sonra 30 gün içinde"],"explanation":"Kansas, tıbbi muayene yapan kişinin MEC'i Ulusal Kayıt Sistemi'ne girmek için bir sonraki günün gece yarısına kadar süresi olduğunu belirtir; Kansas bu veriyi daha sonra oradan elektronik olarak alır. Kaynak: Kansas DOR Tıbbi Sertifikasyon Bilgileri sayfası."},"88":{"q":"Kansas'ta ilk kez CDL başvurusu yapanlar için, federal Giriş Seviyesi Sürücü Eğitimi (ELDT) gerekliliği ne zaman tamamlanmış olmalıdır?","options":["CDL verildikten sonra 30 gün içinde","Yalnızca ilk hareket hâlindeki trafik ihlalinden sonra","CDL beceri testine girmeden önce","CDL'i ilk kez yenilemeden önce"],"explanation":"ELDT (7 Şubat 2022'den itibaren geçerli), başvuru sahibinin CDL beceri testine girebilmesinden önce tamamlanan, FMCSA'ya kayıtlı bir sağlayıcıdan teorik ve direksiyon başı eğitimi gerektirir. Bu federal standart Kansas'ta geçerlidir. Kaynak: FMCSA ELDT kuralı (49 CFR Part 380, Subpart F); FMCSA Eğitim Sağlayıcı Kayıt Sistemi."},"89":{"q":"Giriş seviyesi bir Kansas CDL başvuru sahibi, gerekli ELDT eğitimini nerede listelenen bir sağlayıcıdan almalıdır?","options":["Kansas DOR onaylı okullar listesinde","Kansas Karayolu Devriyesi taşıyıcı listesinde","Ulusal Sertifikalı Tıbbi Muayene Yapanlar Kayıt Sistemi'nde","FMCSA Eğitim Sağlayıcı Kayıt Sistemi'nde (TPR)"],"explanation":"ELDT, FMCSA Eğitim Sağlayıcı Kayıt Sistemi'nde (TPR) listelenen bir okul tarafından sağlanmalıdır; tamamlanma, eyalet beceri testine izin vermeden önce FMCSA'ya elektronik olarak bildirilir. Kaynak: FMCSA Giriş Seviyesi Sürücü Eğitimi, Eğitim Sağlayıcı Kayıt Sistemi."},"90":{"q":"Aşağıdaki onaylardan (endorsement) hangisini ilk kez almak, test öncesi ELDT eğitimi gerekliliğini tetikler?","options":["Yalnızca hava frenleri yetkisi (clearance)","Yolcu (P), Okul Otobüsü (S) veya Tehlikeli Maddeler (H)","Yalnızca Çiftli/Üçlü (T)","Yalnızca Tank (N)"],"explanation":"ELDT, ilk kez CDL başvurusu yapanlar için, B Sınıfından A Sınıfına yükseltmeler için ve ilk kez P, S veya H onayları için geçerlidir. Çiftli/Üçlü ve Tank onayları tek başına ELDT'yi tetiklemez. Kaynak: FMCSA ELDT uygulanabilirliği (49 CFR Part 380, Subpart F)."},"91":{"q":"Kansas'ta mevcut bir B Sınıfı CDL'i A Sınıfı CDL'e yükseltmek, federal ELDT kuralı kapsamında hangi ek adımı gerektirir?","options":["Hiçbir ek adım gerektirmez; yükseltme otomatiktir","Önce B Sınıfı CDL'i en az beş yıl boyunca bulundurmak","Yalnızca genel bilgi testini yeniden vermek","Beceri testinden önce A Sınıfı yükseltme ELDT'sini tamamlamak"],"explanation":"B Sınıfından A Sınıfına yükseltme, ELDT kapsamındaki operasyonlardan biridir, bu nedenle sürücü A Sınıfı beceri testine girmeden önce TPR'de listelenen bir sağlayıcıdan yükseltme eğitim programını tamamlamalıdır. Kaynak: FMCSA ELDT kuralı (49 CFR Part 380, Subpart F)."},"92":{"q":"Bir Kansas başvuru sahibine CLP verildikten sonra, CDL beceri testine girmeye uygun hâle gelmesi için ne kadar beklemesi gerekir?","options":["En az 30 gün","En az 60 gün","En az 14 gün","En az 7 gün"],"explanation":"Bir CLP sahibi, CDL beceri testine girmeden önce izni en az 14 gün boyunca bulundurmalıdır. Bu federal gereklilik Kansas'ta uygulanır. Kaynak: 49 CFR 383.25; Kansas CDL başvuru sahibi rehberliği."},"93":{"q":"Standart bir Kansas CDL'i ne sıklıkla yenilenmelidir?","options":["Her 6 yılda bir","Her 8 yılda bir","Her 2 yılda bir","Her 4 yılda bir"],"explanation":"Kansas CDL'leri 4 yıllık bir döngüyle verilir ve bazı ticari olmayan Kansas ruhsatları için kullanılan 6 yıllık döngüden bağımsız olarak her dört yılda bir yenilenmelidir. Kaynak: Kansas DOR Araçlar Bölümü ruhsatlandırma bilgileri."},"94":{"q":"Eyalet içi (yalnızca Kansas içinde) operasyon için bir Kansas CDL almanın asgari yaşı nedir?","options":["18 yaşında","19 yaşında","21 yaşında","16 yaşında"],"explanation":"Eyalet içi operasyon için bir Kansas CDL'i 18 yaşında verilebilir; eyaletler arası operasyon (ve hazmat) 21 yaşını gerektirir. Kaynak: Kansas CDL El Kitabı; FMCSA sürücü yeterlilik kuralları (49 CFR 391.11)."},"95":{"q":"Bir Kansas CDL ile eyaletler arası ticarette ticari bir motorlu taşıt kullanmanın asgari yaşı nedir?","options":["25 yaşında","21 yaşında","18 yaşında","23 yaşında"],"explanation":"Eyaletler arası CMV operasyonu ve tehlikeli madde taşımacılığı, bir sürücünün en az 21 yaşında olmasını gerektirir. 18-20 yaşındaki sürücüler eyalet içi operasyonla sınırlıdır. Kaynak: FMCSA sürücü yeterlilik kuralları (49 CFR 391.11); Kansas CDL rehberliği."},"96":{"q":"Hangi belge grubu, bir Kansas başvuru sahibinin CLP/CDL için başvurmak amacıyla sağlaması gerekenleri en iyi şekilde yansıtır?","options":["İkamet kanıtı gerektirmeden yalnızca bir pasaport","Kimlik/doğum tarihi kanıtı, Sosyal Güvenlik numarası, yasal mevcudiyet ve iki Kansas ikamet kanıtı","Bir lise diploması ve bir işveren referans mektubu","Yalnızca güncel bir Kansas ticari olmayan ruhsatı ve bir fotoğraf"],"explanation":"Kansas, kimlik/doğum tarihi kanıtı, Sosyal Güvenlik numarası kanıtı, yasal mevcudiyet kanıtı ve Kansas ikametini (fiziki adresi) kanıtlayan iki belge gerektirir; başvuru sahipleri ayrıca halihazırda bir Kansas ticari olmayan sürücü ruhsatına da sahip olmalıdır. Kaynak: Kansas DOR Araçlar Bölümü başvuru gereklilikleri."},"97":{"q":"Ücretler hakkında bir Kansas süreç sorusu: CDL ücretleri hakkında hangi ifade başvuru sahiplerine öğretmek için doğrudur?","options":["CDL ücreti Kansas yasasıyla kalıcı olarak sabitlenmiştir ve asla değişmez","Kansas, bir CDL veya onayları için hiçbir ücret almaz","CDL ücretleri FMCSA tarafından federal olarak belirlenir ve her eyalette aynıdır","CDL ve onay ücretleri Kansas tarafından belirlenir ve değişebilir, bu nedenle başvuru sahipleri güncel tutarları KDOR ile teyit etmelidir"],"explanation":"CDL, onay ve CLP ücretleri eyalet tarafından belirlenir ve değişikliğe tabidir; başvuru sahipleri sabit bir rakama güvenmek yerine güncel tutarları Kansas DOR ile doğrulamalıdır. Ücretler federal olarak tek tip değil, eyalet tarafından belirlenir. Kaynak: Kansas DOR Araçlar Bölümü ücret cetveli rehberliği."}},"es":{"0":{"q":"En las carreteras de Kansas, ¿cuál es el ancho exterior total máximo de un vehículo o su carga sin un permiso?","options":["8 pies (96 pulgadas)","8 1/2 pies (102 pulgadas)","9 pies (108 pulgadas)","10 pies (120 pulgadas)"],"explanation":"La K.S.A. 8-1902 limita el ancho exterior total de cualquier vehículo o su carga a 8 1/2 pies (102 pulgadas). El manual de CDL de Kansas y la Patrulla de Carreteras de Kansas establecen el mismo límite de ancho estándar."},"1":{"q":"¿Cuál es la altura máxima general de un vehículo, incluida su carga, en las carreteras de Kansas?","options":["13 pies 6 pulgadas","14 pies","14 pies 6 pulgadas","15 pies"],"explanation":"La K.S.A. 8-1904 fija la altura máxima del vehículo (incluida la carga) en 14 pies. La Patrulla de Carreteras de Kansas confirma 14 pies como el límite legal de altura."},"2":{"q":"Kansas permite que un tipo de carga supere el límite de altura de 14 pies y se asegure hasta 14 1/2 pies. ¿Cuál es esa carga?","options":["Algodón en pacas","Pacas de heno de forma cilíndrica","Vigas de acero para construcción","Contenedores de carga"],"explanation":"La K.S.A. 8-1904 permite que un vehículo que transporta pacas de heno de forma cilíndrica se cargue hasta 14 1/2 pies; el operador es responsable de cualquier daño si la carga golpea un paso elevado."},"3":{"q":"¿Cuál es la longitud máxima de un solo vehículo automotor (como un camión rígido), incluida su carga, en las carreteras de Kansas?","options":["40 pies","45 pies","48 pies","53 pies"],"explanation":"La K.S.A. 8-1904 limita un solo vehículo automotor, incluida la carga, a una dimensión total máxima de 45 pies."},"4":{"q":"En una combinación de camión tractor y semirremolque, ¿cuál es la longitud máxima del semirremolque permitida en Kansas?","options":["48 pies","53 pies","57 pies","59 1/2 pies"],"explanation":"La K.S.A. 8-1904 establece que un semirremolque operado en combinación con un camión tractor no debe exceder los 59 1/2 pies de longitud."},"5":{"q":"¿Cuál es el peso bruto máximo permitido sobre cualquier eje individual de un vehículo en las carreteras de Kansas sin un permiso?","options":["18,000 libras","20,000 libras","22,000 libras","24,000 libras"],"explanation":"La K.S.A. 8-1908 limita el peso bruto sobre cualquier eje individual a 20,000 libras (y sobre cualquier rueda individual a 10,000 libras)."},"6":{"q":"¿Cuál es el peso bruto máximo permitido sobre un grupo de ejes en tándem en Kansas sin un permiso?","options":["32,000 libras","34,000 libras","36,000 libras","40,000 libras"],"explanation":"La K.S.A. 8-1908 limita el peso bruto sobre ejes en tándem a 34,000 libras, lo que coincide con el estándar federal."},"7":{"q":"¿Cuál es el peso bruto máximo sobre cualquier rueda individual de un vehículo según la ley de Kansas?","options":["8,000 libras","10,000 libras","12,000 libras","17,000 libras"],"explanation":"La K.S.A. 8-1908 establece que el peso bruto sobre cualquier rueda de un vehículo no debe exceder las 10,000 libras."},"8":{"q":"En el sistema de carreteras interestatales en Kansas, ¿cuál es el peso bruto vehicular máximo permitido sin un permiso?","options":["73,280 libras","80,000 libras","85,500 libras","90,000 libras"],"explanation":"Según la K.S.A. 8-1909, la tabla de pesos por separación de ejes no puede autorizar más de 80,000 libras de peso bruto en el sistema interestatal, en concordancia con la ley federal."},"9":{"q":"En las carreteras estatales y de EE. UU. de Kansas que NO forman parte del sistema interestatal, la tabla de separación de ejes puede permitir un peso bruto de hasta qué máximo?","options":["80,000 libras","85,500 libras","90,000 libras","94,000 libras"],"explanation":"La tabla de separación de ejes de la K.S.A. 8-1909 permite hasta 85,500 libras de peso bruto en las carreteras de Kansas y de EE. UU. (no interestatales), más que el tope de 80,000 libras del sistema interestatal."},"10":{"q":"Kansas determina el peso bruto máximo sobre un grupo de dos o más ejes consecutivos principalmente mediante qué método?","options":["Un tope de peso fijo por remolque","Una tabla de pesos por separación de ejes (la fórmula de puentes)","Únicamente el número de neumáticos","Únicamente el peso registrado del camión"],"explanation":"La K.S.A. 8-1909 utiliza una tabla de pesos por separación de ejes basada en la distancia entre los ejes y el número de ejes, la versión de Kansas de la fórmula federal de puentes, para fijar el peso máximo sobre un grupo de ejes consecutivos."},"11":{"q":"Según el concepto de puentes/separación de ejes de Kansas, ¿cómo puede un vehículo transportar legalmente más peso total sobre un grupo de ejes?","options":["Aumentando la presión de los neumáticos","Separando más los ejes y agregando más ejes","Reduciendo la longitud del remolque","Bajando la altura del piso del remolque"],"explanation":"La tabla de separación de ejes de la K.S.A. 8-1909 (fórmula de puentes) permite mayor peso total a medida que aumenta la distancia entre los ejes y crece el número de ejes, para proteger los puentes."},"12":{"q":"Una carga que excede los límites legales de tamaño o peso de Kansas y que NO puede reducirse (una carga indivisible) requiere qué antes de poder circular?","options":["Nada, si circula a la luz del día","Un permiso de sobredimensión/sobrepeso de KDOT","Una nota del remitente","Únicamente una exención federal del DOT"],"explanation":"El Departamento de Transporte de Kansas (KDOT) exige un permiso de sobredimensión/sobrepeso para cargas indivisibles que excedan los límites legales; los permisos se obtienen a través del sistema K-TRIPS de KDOT."},"13":{"q":"¿Qué sistema de Kansas se utiliza para solicitar y obtener permisos de sobredimensión/sobrepeso?","options":["IRP Online","K-TRIPS (Kansas Truck Routing and Intelligent Permitting System)","IFTA Web","CDLIS"],"explanation":"KDOT emite permisos de sobredimensión/sobrepeso a través de K-TRIPS (Kansas Truck Routing and Intelligent Permitting System); los solicitantes se registran y envían en línea los datos del vehículo, la carga y la ruta."},"14":{"q":"Un permiso estándar de sobredimensión/sobrepeso de un solo viaje de Kansas generalmente es válido por cuánto tiempo?","options":["24 horas","3 días","7 días","30 días"],"explanation":"Los permisos de sobredimensión/sobrepeso de un solo viaje de KDOT generalmente son válidos por siete días a partir de la fecha de emisión."},"15":{"q":"El movimiento de una carga con permiso de sobredimensión en Kansas generalmente está restringido a qué horario del día?","options":["A cualquier hora, de día o de noche","Desde media hora antes del amanecer hasta media hora después del atardecer","Únicamente entre la medianoche y las 6 a.m.","Únicamente entre semana durante el horario laboral"],"explanation":"Las condiciones del permiso de KDOT generalmente restringen el movimiento de cargas sobredimensionadas desde media hora antes del amanecer hasta media hora después del atardecer, incluidos fines de semana y días festivos, con las excepciones indicadas en el permiso."},"16":{"q":"¿A partir de qué ancho un vehículo o carga se considera 'sobredimensionado' en Kansas y requiere un permiso?","options":["Más de 8 pies","Más de 8 pies 6 pulgadas","Más de 10 pies","Más de 12 pies"],"explanation":"Dado que la K.S.A. 8-1902 fija el ancho legal en 8 1/2 pies (8 pies 6 pulgadas), cualquier vehículo o carga más ancho que 8 pies 6 pulgadas es sobredimensionado y requiere un permiso de KDOT."},"17":{"q":"Bajo un permiso de sobrepeso de rutina de Kansas (KAR 36-1-37), ¿cuál es el peso máximo permitido sobre un eje individual?","options":["20,000 libras","22,000 libras","24,000 libras","26,000 libras"],"explanation":"Los límites del permiso de sobrepeso de Kansas según KAR 36-1-37 elevan el máximo del eje individual no motriz a 22,000 libras (y los ejes en tándem a 45,000 libras), por encima del límite legal de 20,000 libras."},"18":{"q":"Kansas ofrece un permiso anual especial de sobrepeso para cargas DIVISIBLES de productos agrícolas, insumos y biocombustibles. ¿Cuál es su peso bruto máximo y dónde NO se permite?","options":["80,000 libras; no en caminos del condado","90,000 libras; no en el sistema interestatal","100,000 libras; no dentro de las ciudades","85,500 libras; no en los puentes"],"explanation":"Kansas permite un permiso anual de sobrepeso para cargas divisibles de insumos agrícolas, productos básicos, ganado y biocombustibles de hasta 90,000 libras con al menos seis ejes, y dichos vehículos no pueden operar en el sistema interestatal."},"19":{"q":"En Kansas, un vehículo que opera con más de 85,500 libras tiene prohibido circular bajo qué condición?","options":["Cuando está lloviendo","Cuando la superficie de la carretera tiene hielo, nieve compactada o nieve arrastrada por el viento","Durante la temporada de cosecha","A menos de 50 millas de una ciudad"],"explanation":"La K.S.A. 8-1919 prohíbe que los vehículos que operan con más de 85,500 libras circulen cuando la superficie de la carretera tiene hielo, nieve compactada o nieve arrastrada por el viento."},"20":{"q":"En Kansas, ¿qué clase de CDL se requiere para operar un solo vehículo con un peso bruto vehicular nominal de 26,001 libras o más, donde cualquier unidad remolcada NO exceda las 10,000 libras de GVWR?","options":["Clase A","Clase B","Clase C","Clase D"],"explanation":"Kansas define una CDL Clase B como cualquier vehículo individual con un GVWR de 26,001 libras o más, o dicho vehículo remolcando una unidad que no exceda las 10,000 libras de GVWR. Fuente: Manual de CDL de Kansas (KDOR) y K.S.A. 8-2,128."},"21":{"q":"¿Cuál es el peso bruto combinado nominal mínimo que define una CDL Clase A de Kansas cuando la unidad remolcada excede las 10,000 libras?","options":["18,000 libras","26,001 libras","33,000 libras","10,001 libras"],"explanation":"Una CDL Clase A de Kansas cubre cualquier combinación de vehículos con un GCWR de 26,001 libras o más, siempre que la(s) unidad(es) remolcada(s) tenga un GVWR de más de 10,000 libras. Fuente: Manual de CDL de Kansas (KDOR); K.S.A. 8-2,128."},"22":{"q":"Un conductor transporta una cantidad de materiales peligrosos que requiere placas (placardable) en una camioneta con un GVWR inferior a 26,001 libras. ¿Qué combinación de clase de CDL y aval (endorsement) de Kansas corresponde?","options":["Clase A sin aval","Clase B con aval N","Clase C con aval H","Clase D con aval P"],"explanation":"Si un vehículo no cumple con las definiciones de peso de Clase A o B, pero transporta materiales peligrosos en cantidades que requieren placas (o transporta 16 o más pasajeros), Kansas exige una CDL Clase C, más el aval H para materiales peligrosos. Fuente: Manual de CDL de Kansas (KDOR); 49 CFR 383.91."},"23":{"q":"En una CDL de Kansas, ¿qué autoriza al conductor a hacer el aval (endorsement) 'N'?","options":["Operar vehículos cisterna","Transportar materiales peligrosos","Remolcar dobles y triples remolques","Conducir un autobús escolar"],"explanation":"En Kansas, el aval 'N' permite la operación de vehículos cisterna. Fuente: K.S.A. 8-2,135; Manual de CDL de Kansas (KDOR)."},"24":{"q":"¿Qué código de aval (endorsement) en una CDL de Kansas se requiere para arrastrar dobles y triples remolques?","options":["P","H","T","S"],"explanation":"El aval 'T' autoriza el remolque de dobles y triples remolques; se obtiene aprobando únicamente un examen de conocimientos (sin un examen de habilidades por separado). Fuente: K.S.A. 8-2,135; Manual de CDL de Kansas (KDOR)."},"25":{"q":"Un vehículo está diseñado para transportar 16 o más personas, incluido el conductor. ¿Qué aval (endorsement) de CDL de Kansas se requiere (salvo la excepción del autobús escolar)?","options":["N (cisterna)","P (pasajeros)","T (dobles/triples)","H (materiales peligrosos)"],"explanation":"El aval 'P' (pasajeros) se requiere para vehículos diseñados para transportar 16 o más personas incluido el conductor, y requiere tanto un examen de conocimientos como uno de habilidades. Fuente: Manual de CDL de Kansas (KDOR); 49 CFR 383.93."},"26":{"q":"Para obtener el aval (endorsement) de Autobús Escolar (S) en Kansas, ¿qué otro aval debe tener también el conductor?","options":["H (materiales peligrosos)","N (vehículo cisterna)","P (pasajeros)","T (dobles/triples)"],"explanation":"Kansas exige que los conductores tengan primero el aval 'P' (pasajeros) antes de agregar el aval 'S' (autobús escolar), lo cual también requiere aprobar exámenes adicionales de conocimientos y de habilidades. Fuente: Manual de CDL de Kansas (KDOR); 49 CFR 383.93."},"27":{"q":"Antes de que Kansas pueda emitir el aval (endorsement) de Materiales Peligrosos (H), el solicitante debe completar qué requisito federal adicional?","options":["Una evaluación de amenazas de seguridad de la TSA (verificación de antecedentes)","Una exención de visión de la FMCSA","Un aprendizaje en carretera de 30 días","Un nuevo examen de habilidades de frenos de aire"],"explanation":"El aval H (materiales peligrosos) requiere aprobar un examen de conocimientos Y una Evaluación de Amenazas de Seguridad de la TSA, que incluye toma de huellas dactilares y una verificación de antecedentes, antes de que Kansas lo emita. Fuente: Manual de CDL de Kansas (KDOR); 49 CFR 383.71/1572."},"28":{"q":"¿Cuál es la edad mínima para obtener una CDL de Kansas restringida únicamente a la conducción intraestatal (dentro de Kansas)?","options":["16 años","17 años","18 años","21 años"],"explanation":"Kansas exige que un conductor tenga al menos 18 años para obtener una CDL únicamente para operación intraestatal. Fuente: Manual de CDL de Kansas (KDOR); K.S.A. 8-2,129."},"29":{"q":"¿Cuál es la edad mínima para obtener una CDL de Kansas para conducción interestatal (a través de las fronteras estatales) o para transportar materiales peligrosos?","options":["18 años","19 años","20 años","21 años"],"explanation":"Un conductor debe tener al menos 21 años para conducir un CMV en comercio interestatal, transportar materiales peligrosos o transportar pasajeros a través de las fronteras estatales. Fuente: Manual de CDL de Kansas (KDOR); 49 CFR 391.11."},"30":{"q":"Después de que se emite por primera vez un Permiso de Aprendiz Comercial (CLP) en Kansas, ¿cuánto tiempo debe conservarlo el solicitante antes de poder presentar el examen de habilidades de la CDL?","options":["Al menos 7 días","Al menos 14 días","Al menos 30 días","Al menos 60 días"],"explanation":"Norma federal adoptada por Kansas: el titular de un CLP no es elegible para presentar el examen de habilidades de la CDL hasta que haya tenido el permiso durante un mínimo de 14 días. Fuente: Manual de CDL de Kansas (KDOR); 49 CFR 383.25."},"31":{"q":"¿Qué debe hacer el titular de un CLP de Kansas mientras conduce un vehículo automotor comercial para practicar?","options":["Conducir solo entre el amanecer y el atardecer","Estar acompañado por un titular de CDL sentado en el asiento delantero junto a él","Limitar la conducción a un radio de 25 millas de su casa","No llevar ningún tipo de carga"],"explanation":"El titular de un CLP de Kansas puede operar un CMV solo cuando esté acompañado por una persona que tenga una CDL válida para el tipo de vehículo, quien debe estar sentada en el asiento delantero junto al conductor. Fuente: Manual de CDL de Kansas (KDOR); 49 CFR 383.25."},"32":{"q":"Según las normas federales adoptadas por Kansas, un Permiso de Aprendiz Comercial NO debe ser válido por más de qué período máximo sin volver a examinarse?","options":["90 días","6 meses","1 año","5 años"],"explanation":"Un CLP puede emitirse por no más de un año a partir de su emisión inicial sin requerir que el solicitante vuelva a presentar los exámenes de conocimientos. Fuente: Manual de CDL de Kansas (KDOR); 49 CFR 383.25."},"33":{"q":"¿Qué conjunto de documentos debe presentar el solicitante de una CDL de Kansas a la División de Vehículos al solicitarla?","options":["Prueba de identidad, número de Seguro Social, residencia en Kansas y presencia legal","Únicamente una tarjeta de Seguro Social y un acta de nacimiento","Un pasaporte y un registro de vehículo","Prueba de empleo y un permiso de materiales peligrosos"],"explanation":"El Departamento de Ingresos de Kansas, División de Vehículos, exige que los solicitantes prueben su identidad, proporcionen su número de Seguro Social y muestren prueba de residencia en Kansas y de presencia legal. Fuente: Departamento de Ingresos de Kansas, División de Vehículos (ksrevenue.gov)."},"34":{"q":"La Capacitación para Conductores de Nivel Inicial (ELDT) que Kansas exige a los solicitantes de Clase A/B por primera vez debe ser impartida por una entidad de capacitación que esté:","options":["Aprobada por el distrito escolar local","Listada en el Registro de Proveedores de Capacitación (Training Provider Registry) de la FMCSA","Certificada por la Patrulla de Carreteras de Kansas","Acreditada por el Departamento de Educación de EE. UU."],"explanation":"Desde el 7 de febrero de 2022, la ELDT debe completarse a través de un proveedor listado en el Registro de Proveedores de Capacitación (TPR) de la FMCSA antes de que Kansas permita ciertos exámenes de habilidades/conocimientos. Fuente: Departamento de Ingresos de Kansas (dovcdlentry.html); 49 CFR Part 380."},"35":{"q":"¿Cuál de las siguientes acciones realizadas por primera vez NO activa el requisito federal de ELDT en Kansas?","options":["Obtener una CDL Clase A por primera vez","Subir de categoría de una CDL Clase B a una CDL Clase A","Obtener el aval de Materiales Peligrosos (H) por primera vez","Renovar una CDL Clase A existente sin nuevos avales"],"explanation":"La ELDT aplica a la emisión por primera vez de Clase A/B, a un cambio de categoría de Clase B a A y a los avales H, P o S por primera vez. Una renovación de rutina de una CDL existente sin cambio de categoría ni nuevo aval no requiere ELDT. Fuente: Departamento de Ingresos de Kansas (dovcdlentry.html); 49 CFR Part 380."},"36":{"q":"Un conductor con CDL de Kansas que opera únicamente dentro de Kansas y que no está exento de los requisitos médicos debe autocertificarse en qué categoría?","options":["Interestatal no exento","Interestatal exento","Intraestatal no exento","Intraestatal exento"],"explanation":"Un conductor que opera únicamente dentro de Kansas y que está sujeto al requisito de certificado médico se autocertifica como 'Intraestatal no exento' y debe mantener un Certificado de Examinador Médico vigente. Fuente: Departamento de Ingresos de Kansas, Certificación Médica (ksrevenue.gov); 49 CFR 383.71."},"37":{"q":"¿Qué categoría de autocertificación de la CDL de Kansas exige que el conductor mantenga y presente un Certificado de Examinador Médico federal vigente?","options":["Interestatal exento","Intraestatal exento","Interestatal no exento","Operador agrícola restringido"],"explanation":"Los conductores que se certifican como interestatales no exentos (e intraestatales no exentos) deben mantener un Certificado de Examinador Médico vigente; los conductores exentos no presentan documentos médicos. Fuente: Departamento de Ingresos de Kansas, Certificación Médica (ksrevenue.gov); 49 CFR 383.71."},"38":{"q":"Según las normas de Kansas/federales, un 'vehículo cisterna' para el aval N generalmente es uno diseñado para transportar un líquido o un gas en un tanque adherido de forma permanente o temporal con una capacidad nominal de al menos:","options":["100 galones","500 galones","1,000 galones","5,000 galones"],"explanation":"El aval N (cisterna) aplica a vehículos que transportan materiales líquidos o gaseosos en tanques con una capacidad nominal agregada de 1,000 galones o más (tanques individuales de 119 galones o más). Fuente: Manual de CDL de Kansas (KDOR); 49 CFR 383.5."},"39":{"q":"Un conductor desea combinar los avales de Materiales Peligrosos y de Cisterna en una CDL de Kansas. ¿Qué código de aval único representa esa combinación?","options":["X","T","P","L"],"explanation":"Kansas utiliza el código de aval 'X' para representar la combinación de los avales de Materiales Peligrosos (H) y de Cisterna (N). Fuente: K.S.A. 8-2,135; Manual de CDL de Kansas (KDOR)."},"40":{"q":"En Kansas, ¿cuál es la concentración máxima de alcohol en sangre (BAC) con la que una persona puede operar legalmente un vehículo automotor comercial (CMV)?","options":["El límite es 0.08% o más","Cualquier BAC por debajo de 0.04%","Cualquier BAC por debajo de 0.10%","Cualquier BAC por debajo de 0.02%"],"explanation":"Kansas prohíbe operar un CMV con un BAC de 0.04% o más; el límite legal para conductores de CMV es por debajo de 0.04%, la mitad del límite de 0.08% para conductores comunes. Fuente: Manual de CDL de Kansas, Sección 1 (Descalificaciones del Conductor); 49 CFR 383.51 según se adopta en Kansas."},"41":{"q":"¿Por cuánto tiempo se descalifica al titular de una CDL de Kansas por una PRIMERA infracción mayor, como un DUI en un CMV, cuando NO transporta materiales peligrosos con placas?","options":["60 días","1 año","3 años","6 meses"],"explanation":"Una primera infracción mayor (DUI, negarse a una prueba, abandonar el lugar de los hechos, usar un CMV en un delito grave, etc.) resulta en una descalificación de 1 año en Kansas. Fuente: K.S.A. 8-2,142; Manual de CDL de Kansas; 49 CFR 383.51."},"42":{"q":"Si un conductor de Kansas comete una primera infracción mayor MIENTRAS transporta materiales peligrosos que requieren placas, ¿por cuánto tiempo es la descalificación?","options":["1 año","3 años","De por vida","120 días"],"explanation":"Una primera infracción mayor mientras se opera un CMV que transporta materiales peligrosos con placas resulta en una descalificación de 3 años en Kansas, en lugar del estándar de 1 año. Fuente: K.S.A. 8-2,142; Manual de CDL de Kansas; 49 CFR 383.51."},"43":{"q":"¿Cuál es el período de descalificación en Kansas por una SEGUNDA infracción mayor cometida en un CMV?","options":["3 años","10 años","De por vida","5 años"],"explanation":"Una segunda infracción mayor resulta en una descalificación de por vida de la CDL en Kansas. Fuente: K.S.A. 8-2,142; Manual de CDL de Kansas; 49 CFR 383.51(b)."},"44":{"q":"Según las normas de consentimiento implícito de Kansas, un titular de CDL que SE NIEGA a una prueba química de aliento o sangre se considera que ha cometido qué?","options":["Una infracción de tránsito grave","Una infracción mayor","Una violación de fuera de servicio (out-of-service)","Una infracción no reportable"],"explanation":"Negarse a una prueba química solicitada legalmente se clasifica como una infracción mayor, conllevando la misma descalificación de 1 año (o 3 años para materiales peligrosos) que un DUI. Fuente: K.S.A. 8-2,142; Manual de CDL de Kansas, Sección 1."},"45":{"q":"¿Por cuánto tiempo se descalifica al titular de una CDL de Kansas por negarse a una prueba química mientras conduce un CMV que NO transporta materiales peligrosos con placas?","options":["90 días","1 año","3 años","De por vida"],"explanation":"Una primera negativa a una prueba en un CMV resulta en una descalificación de la CDL de 1 año (3 años si transporta materiales peligrosos con placas). Fuente: K.S.A. 8-2,142; 49 CFR 383.51."},"46":{"q":"Cuando un conductor con CDL de Kansas acumula DOS infracciones de tránsito graves dentro de un período de 3 años (en un CMV), la descalificación mínima es:","options":["30 días","60 días","120 días","1 año"],"explanation":"Dos infracciones de tránsito graves dentro de 3 años resultan en una descalificación mínima de 60 días en Kansas. Fuente: Manual de CDL de Kansas, Sección 1; 49 CFR 383.51(c)."},"47":{"q":"Cuando un conductor con CDL de Kansas acumula TRES infracciones de tránsito graves dentro de un período de 3 años (en un CMV), la descalificación mínima es:","options":["60 días","90 días","120 días","180 días"],"explanation":"Tres infracciones de tránsito graves dentro de 3 años resultan en una descalificación mínima de 120 días en Kansas. Fuente: Manual de CDL de Kansas, Sección 1; 49 CFR 383.51(c)."},"48":{"q":"¿Cuál de las siguientes cuenta como una 'infracción de tránsito grave' para el titular de una CDL de Kansas?","options":["Conducir a 15 mph o más por encima del límite de velocidad","Conducir a 5 mph por encima del límite de velocidad","Una infracción de estacionamiento","Una calcomanía de registro vencida"],"explanation":"Las infracciones de tránsito graves incluyen exceder la velocidad en 15 mph o más por encima del límite, conducción imprudente, cambios de carril indebidos o erráticos, seguir demasiado cerca e infracciones de tránsito relacionadas con un accidente fatal. Fuente: Manual de CDL de Kansas, Sección 1; 49 CFR 383.51(c)."},"49":{"q":"Según las normas de CDL de Kansas/federales, conducir un CMV mientras se ENVÍAN MENSAJES DE TEXTO se clasifica como qué tipo de infracción?","options":["Una infracción mayor","Una infracción de tránsito grave","Una violación de fuera de servicio (out-of-service)","Una violación de cruce ferroviario"],"explanation":"Enviar mensajes de texto mientras se conduce un CMV, y usar un teléfono móvil de mano mientras se conduce un CMV, son infracciones de tránsito graves que cuentan para las descalificaciones de 2 en 3 años (60 días) y 3 en 3 años (120 días). Fuente: Manual de CDL de Kansas; 49 CFR 383.51(c) y 392.80/392.82."},"50":{"q":"Para un conductor con CDL de Kansas, usar un teléfono móvil DE MANO mientras opera un CMV se considera:","options":["Una infracción no reportable","Una infracción de tránsito grave","Una infracción mayor","Una prohibición automática de por vida"],"explanation":"Conducir un CMV mientras se usa un teléfono de mano viola el 49 CFR 392.82 y es una infracción de tránsito grave; el conductor enfrenta una sanción civil federal (de hasta $2,750) y la infracción cuenta para las descalificaciones por infracciones graves. Fuente: Manual de CDL de Kansas; 49 CFR 392.82, 383.51(c)."},"51":{"q":"¿Cuál es el período de descalificación para la PRIMERA condena del titular de una CDL de Kansas por una violación de cruce a nivel entre carretera y vía férrea?","options":["No menos de 30 días","No menos de 60 días","No menos de 120 días","No menos de 180 días"],"explanation":"Una primera violación de cruce a nivel entre carretera y vía férrea resulta en una descalificación de no menos de 60 días en Kansas. Fuente: Manual de CDL de Kansas, Sección 1; 49 CFR 383.51(d)."},"52":{"q":"Un titular de CDL de Kansas comete una SEGUNDA violación de cruce a nivel entre carretera y vía férrea dentro de un período de 3 años. La descalificación mínima es:","options":["60 días","90 días","120 días","1 año"],"explanation":"Una segunda violación de cruce ferroviario dentro de 3 años resulta en una descalificación de no menos de 120 días. Fuente: Manual de CDL de Kansas, Sección 1; 49 CFR 383.51(d)."},"53":{"q":"Un titular de CDL de Kansas comete una TERCERA violación de cruce a nivel entre carretera y vía férrea dentro de un período de 3 años. La descalificación mínima es:","options":["120 días","180 días","No menos de 1 año","2 años"],"explanation":"Una tercera violación de cruce ferroviario dentro de 3 años resulta en una descalificación de no menos de 1 año. Fuente: Manual de CDL de Kansas, Sección 1; 49 CFR 383.51(d)."},"54":{"q":"¿Cuál es la descalificación mínima para la PRIMERA violación de una orden de fuera de servicio (out-of-service) por parte de un conductor con CDL de Kansas (sin materiales peligrosos, sin pasajeros)?","options":["No menos de 60 días","No menos de 90 días","No menos de 180 días","No menos de 1 año"],"explanation":"Una primera violación de una orden de fuera de servicio resulta en una descalificación de no menos de 180 días (y no más de 1 año) en Kansas. Fuente: Manual de CDL de Kansas, Sección 1; 49 CFR 383.51(e)."},"55":{"q":"¿Cuál es el rango de descalificación para una SEGUNDA violación de una orden de fuera de servicio (out-of-service) dentro de 10 años para un conductor con CDL de Kansas (sin materiales peligrosos, sin pasajeros)?","options":["180 días a 1 año","1 a 3 años","2 a 5 años","3 a 5 años"],"explanation":"Una segunda violación de una orden de fuera de servicio dentro de 10 años resulta en una descalificación de no menos de 2 años y no más de 5 años. Fuente: Manual de CDL de Kansas, Sección 1; 49 CFR 383.51(e)."},"56":{"q":"Un conductor con CDL de Kansas comete una PRIMERA violación de una orden de fuera de servicio (out-of-service) mientras transporta materiales peligrosos con placas o lleva pasajeros. La descalificación es:","options":["No menos de 60 días","No menos de 180 días, hasta 2 años","No menos de 90 días, hasta 1 año","De por vida"],"explanation":"Una primera violación de una orden de fuera de servicio mientras transporta materiales peligrosos con placas o lleva pasajeros resulta en una descalificación de no menos de 180 días y no más de 2 años (frente a hasta 1 año para cargas comunes). Fuente: Manual de CDL de Kansas; 49 CFR 383.51(e)."},"57":{"q":"En Kansas, un conductor de CMV al que se le detecta CUALQUIER cantidad medible de alcohol en su organismo (incluso por debajo de 0.04%) mientras está de servicio está sujeto a qué?","options":["Descalificación inmediata de por vida","Ser puesto fuera de servicio durante 24 horas","Una descalificación de 1 año","Una descalificación de 60 días"],"explanation":"Un conductor de CMV con cualquier cantidad medible o detectable de alcohol (por debajo de 0.04%) es puesto fuera de servicio durante 24 horas; un BAC de 0.04% o más se convierte en una infracción mayor (descalificación de 1 año). Fuente: Manual de CDL de Kansas, Sección 1; 49 CFR 392.5."},"58":{"q":"Además de la descalificación, ¿qué sanción adicional puede imponer una sanción civil de Kansas/federal a una EMPRESA DE TRANSPORTE que a sabiendas permite que un conductor opere durante una orden de fuera de servicio (out-of-service)?","options":["Una multa de $2,750 a $11,000","Una multa fija de $500","Pérdida de la autoridad operativa de la empresa durante 60 días","No aplica ninguna sanción a la empresa"],"explanation":"Un empleador que a sabiendas permite o exige que un conductor viole una orden de fuera de servicio está sujeto a una sanción civil de $2,750 a $11,000, además de la descalificación y la multa del conductor. Fuente: Manual de CDL de Kansas; 49 CFR 383.53(b)."},"59":{"q":"Un titular de CDL de Kansas es condenado por una infracción mayor y, años después, es condenado por una segunda infracción mayor. Tras una descalificación de por vida, la rehabilitación puede ser posible únicamente:","options":["Después de 1 año","Después de 5 años","Después de un mínimo de 10 años, si se cumplen las condiciones","Nunca es posible"],"explanation":"Una descalificación de por vida por dos infracciones mayores puede, según las normas adoptadas por la FMCSA, reducirse a un mínimo de 10 años si el conductor cumple las condiciones prescritas; algunas prohibiciones de por vida (p. ej., usar un CMV para fabricar/distribuir drogas) son permanentes. Fuente: Manual de CDL de Kansas; 49 CFR 383.51(b)."},"60":{"q":"En Kansas, cuando un autobús escolar que transporta pasajeros se aproxima a un cruce a nivel de ferrocarril, ¿a qué distancia del riel más cercano debe detenerse el conductor?","options":["A menos de 50 pies, pero no a menos de 15 pies del riel más cercano","A menos de 25 pies, pero no a menos de 5 pies del riel más cercano","A menos de 75 pies, pero no a menos de 25 pies del riel más cercano","A menos de 100 pies, pero no a menos de 50 pies del riel más cercano"],"explanation":"Kansas exige que ciertos vehículos se detengan a menos de 50 pies, pero no a menos de 15 pies del riel más cercano, y que miren y escuchen antes de cruzar. Fuente: K.S.A. 8-1551; Manual CDL de Kansas (KDOR)."},"61":{"q":"Según la ley de Kansas, un vehículo comercial que exhibe placas (placards) de materiales peligrosos y que debe detenerse en un cruce de ferrocarril, ¿dentro de qué distancia del riel más cercano debe detenerse por completo?","options":["No más cerca de 10 pies y no más lejos de 30 pies","No más cerca de 15 pies y no más lejos de 50 pies","No más cerca de 20 pies y no más lejos de 60 pies","No más cerca de 5 pies y no más lejos de 25 pies"],"explanation":"Los vehículos con placas de HazMat deben detenerse a menos de 50 pies, pero no a menos de 15 pies del riel más cercano, y continuar solo cuando sea seguro. Fuente: K.S.A. 8-1551; Manual CDL de Kansas (KDOR)."},"62":{"q":"La ley 'Move Over' (cédase el paso) de Kansas fue ampliada a partir del 1 de julio de 2025. ¿Qué exige la ley actual que haga un conductor que se aproxima a un vehículo detenido?","options":["Cederse el paso solo para vehículos de policía, bomberos y ambulancias","Cederse el paso solo para vehículos de emergencia y grúas de remolque","Cederse el paso para CUALQUIER vehículo detenido que exhiba luces intermitentes o de emergencia, no solo vehículos de emergencia","Cederse el paso solo cuando un oficial esté parado fuera del vehículo"],"explanation":"El proyecto de ley Senate Bill 8 (vigente desde el 1 de julio de 2025) amplió la K.S.A. 8-1530 para que los conductores deban cederse el paso o reducir la velocidad ante cualquier vehículo detenido que exhiba luces intermitentes o de emergencia. Fuente: K.S.A. 8-1530; Kansas SB 8 (2025)."},"63":{"q":"En una carretera de Kansas con dos o más carriles en la dirección del conductor, ¿qué exige la ley Move Over al pasar junto a un vehículo detenido con luces de advertencia activas?","options":["Detenerse por completo siempre hasta que el vehículo se retire","Tocar la bocina de forma continua mientras se pasa","Mantener la velocidad normal pero encender las luces de emergencia","Cambiar a un carril no adyacente al vehículo detenido si se puede hacer de forma segura"],"explanation":"La K.S.A. 8-1530(b) exige que los conductores en vías de varios carriles cambien a un carril no adyacente si es seguro; si no es posible, deben reducir la velocidad y continuar con la debida precaución. Fuente: K.S.A. 8-1530; Manual CDL de Kansas (KDOR)."},"64":{"q":"Según la ley Move Over de Kansas, si cambiar de carril para alejarse de un vehículo detenido con luces de advertencia es inseguro o imposible, ¿qué debe hacer el conductor?","options":["Detenerse en el carril de circulación y esperar","Reducir la velocidad y mantener una velocidad segura según las condiciones de la vía, el clima y el tráfico","Continuar al límite de velocidad indicado","Orillarse hacia el acotamiento y detenerse"],"explanation":"Cuando un cambio de carril no es posible o es inseguro, la K.S.A. 8-1530(b) exige que el conductor proceda con la debida precaución, reduzca la velocidad y mantenga una velocidad segura. Fuente: K.S.A. 8-1530."},"65":{"q":"¿Cuál es el límite de velocidad máximo indicado en una carretera (interestatal) de varios carriles separados en Kansas, según lo establecido por el Secretario de Transporte?","options":["70 mph","65 mph","75 mph","80 mph"],"explanation":"Kansas establece el máximo en carreteras de varios carriles separados en 75 mph, según lo designado y señalizado por el Secretario de Transporte. Fuente: K.S.A. 8-1558."},"66":{"q":"¿Establece Kansas un límite de velocidad máximo estatal separado y más bajo para camiones/CMV que para automóviles en sus carreteras interestatales?","options":["Sí: los camiones están limitados a 65 mph en todo el estado mientras que los automóviles pueden ir a 75 mph","Sí: los camiones están limitados a 60 mph en todas las interestatales","Sí: los camiones están limitados a 55 mph por la noche en todo el estado","No: el mismo límite máximo indicado aplica a camiones y automóviles en Kansas"],"explanation":"Kansas no impone un límite de velocidad estatal separado para camiones; el mismo máximo indicado aplica a todos los vehículos a menos que las señales indiquen lo contrario. Fuente: K.S.A. 8-1558; KDOT."},"67":{"q":"Según la K.S.A. 8-1558, ¿cuál es el límite de velocidad máximo legal en una carretera de condado o de municipio (township) en Kansas?","options":["55 mph","45 mph","65 mph","60 mph"],"explanation":"Kansas establece el máximo en carreteras de condado o de municipio en 55 mph, en otras carreteras (que no son de varios carriles) en 65 mph, y 30 mph en distritos urbanos. Fuente: K.S.A. 8-1558."},"68":{"q":"Según la K.S.A. 8-1558, ¿cuál es el límite de velocidad máximo legal en un distrito urbano en Kansas, a menos que se indique lo contrario?","options":["25 mph","35 mph","30 mph","20 mph"],"explanation":"El máximo legal en un distrito urbano es 30 mph, a menos que se indique un límite diferente. Fuente: K.S.A. 8-1558."},"69":{"q":"En un camino de dos carriles (sin división) de Kansas, ¿qué debe hacer un conductor que se encuentra con un autobús escolar detenido con luces rojas intermitentes?","options":["Reducir a 20 mph y pasar con precaución","Moverse al carril más alejado y continuar pasando junto al autobús","Detenerse solo si hay niños cruzando visiblemente","Detenerse antes de llegar al autobús y no continuar hasta que las luces rojas dejen de parpadear o el autobús se mueva"],"explanation":"Los conductores que se encuentran o alcanzan a un autobús escolar con luces rojas intermitentes deben detenerse antes de llegar a él y permanecer detenidos hasta que las luces dejen de parpadear o el autobús se mueva. Fuente: K.S.A. 8-1556."},"70":{"q":"En una carretera dividida de Kansas con calzadas separadas, ¿cuál es la excepción para detenerse ante un autobús escolar que recoge niños?","options":["Un conductor en una calzada distinta a la del autobús no necesita detenerse","Un conductor en el carril más cercano al autobús no necesita detenerse","No aplica ninguna excepción; todos los conductores deben detenerse siempre","Un conductor puede continuar si el autobús está a más de 100 pies de distancia"],"explanation":"La K.S.A. 8-1556 establece que un conductor en una carretera con calzadas separadas no necesita detenerse ante un autobús escolar que está en una calzada DISTINTA (o en una zona de carga de acceso controlado donde los peatones no pueden cruzar). Fuente: K.S.A. 8-1556."},"71":{"q":"Según la excepción de calzada separada para autobuses escolares de Kansas, ¿qué escenario aún EXIGE que el tráfico en todas las direcciones se detenga?","options":["Una carretera dividida donde el autobús está en la calzada opuesta al otro lado de un camellón","Un camino de dos carriles sin división y sin separación física entre las direcciones","Una carretera de acceso controlado donde el autobús está en una zona de carga y los peatones no pueden cruzar","Dos calzadas separadas físicamente por una barrera"],"explanation":"La excepción aplica solo donde hay calzadas SEPARADAS. En un camino sin división y sin separación, el tráfico en ambas direcciones debe detenerse. Fuente: K.S.A. 8-1556."},"72":{"q":"En Kansas, la multa base por rebasar ilegalmente un autobús escolar detenido con sus luces rojas intermitentes encendidas es ¿cuál de las siguientes?","options":["$75, sin aumentos","$150, duplicada solo en zonas escolares","$500 fijos por cada infracción","$315, con multas crecientes para infracciones reincidentes"],"explanation":"El esquema uniforme de multas de Kansas establece una multa base de $315 por rebasar ilegalmente un autobús escolar, con multas crecientes para infracciones posteriores. Fuente: K.S.A. 8-2118."},"73":{"q":"Cuando un conductor con CDL de Kansas detiene un vehículo comercial en el acotamiento de una carretera dividida, ¿dónde se debe colocar el triángulo reflectante de advertencia más alejado hacia atrás?","options":["A unos 200 pies detrás del vehículo, hacia el tráfico que se aproxima","A unos 50 pies detrás del vehículo","A unos 500 pies detrás del vehículo","A unos 150 pies detrás del vehículo"],"explanation":"En una carretera dividida o de un solo sentido, los triángulos se colocan a 10 pies, 100 pies y 200 pies hacia el tráfico que se aproxima. Fuente: Manual CDL de Kansas (KDOR); 49 CFR 392.22."},"74":{"q":"Un conductor con CDL de Kansas se detiene en una carretera de un solo sentido o dividida. ¿Cuál es la colocación correcta de los tres triángulos reflectantes hacia el tráfico que se aproxima?","options":["10 pies, 50 pies y 150 pies hacia atrás","10 pies, 100 pies y 200 pies hacia atrás","25 pies, 100 pies y 250 pies hacia atrás","5 pies, 75 pies y 175 pies hacia atrás"],"explanation":"En vías divididas o de un solo sentido, coloque los triángulos a 10, 100 y 200 pies hacia el tráfico que se aproxima. Fuente: Manual CDL de Kansas (KDOR); 49 CFR 392.22."},"75":{"q":"Después de detener un CMV en un camino de dos carriles y doble sentido en Kansas, ¿en cuánto tiempo debe un conductor colocar los dispositivos de advertencia de emergencia requeridos?","options":["Dentro de los 30 minutos de haberse detenido","Dentro de 1 hora de haberse detenido","Dentro de los 10 minutos de haberse detenido","Solo si está detenido por más de 2 horas"],"explanation":"Los dispositivos de advertencia de emergencia deben colocarse dentro de los 10 minutos de haberse detenido en una carretera o acotamiento. Fuente: Manual CDL de Kansas (KDOR); 49 CFR 392.22."},"76":{"q":"En un camino de dos carriles y doble sentido de Kansas, ¿dónde debe colocar un conductor de CMV los tres triángulos de advertencia después de detenerse?","options":["Uno a menos de 10 pies de la parte trasera, uno a unos 100 pies detrás y uno a unos 100 pies delante del vehículo","Los tres a menos de 10 pies de la parte trasera del vehículo","Uno a 200 pies detrás y dos delante del vehículo","Uno a 50 pies detrás y dos a los lados del vehículo"],"explanation":"En un camino de doble sentido, coloque un triángulo a 10 pies hacia atrás, uno a unos 100 pies hacia atrás y uno a unos 100 pies hacia adelante. Fuente: Manual CDL de Kansas (KDOR); 49 CFR 392.22."},"77":{"q":"Cuando un conductor de autobús con CDL de Kansas cruza vías de ferrocarril en un cruce, ¿qué NO debe hacer mientras cualquier parte del autobús esté sobre las vías?","options":["Mantener el autobús en una marcha baja","Mirar y escuchar antes de entrar","Cambiar de marcha (hacer cambios) mientras cruza las vías","Mantener la puerta cerrada"],"explanation":"Los conductores deben cruzar las vías del ferrocarril en una marcha que no requiera hacer cambios, y no deben cambiar de marcha mientras cualquier parte del vehículo esté sobre las vías. Fuente: Manual CDL de Kansas (KDOR)."},"78":{"q":"¿Qué dato sobre rutas es genuinamente distintivo de las operaciones comerciales en Kansas?","options":["Todas las interestatales de Kansas son libres de peaje y no tienen rutas comerciales","Gran parte de la I-35, la I-335, la I-470 y la I-70 forman la autopista de peaje Kansas Turnpike, donde se permiten dobles remolques de 53 pies","Kansas prohíbe todos los camiones de más de 40 pies en cada interestatal","Kansas exige que todos los camiones usen únicamente carreteras US (no interestatales)"],"explanation":"La Kansas Turnpike (KTA), de unas 236 millas a lo largo de la I-35/I-335/I-470/I-70, es una carretera de peaje que permite dobles remolques de 53 pies. Fuente: KDOT; Kansas Turnpike Authority."},"79":{"q":"¿Qué agencia de Kansas emite los permisos de sobredimensión/sobrepeso y aprueba las rutas de camiones a través del sistema K-TRIPS?","options":["Kansas Department of Revenue (KDOR)","La división de licencias de la Patrulla de Caminos de Kansas","La Administración Federal de Seguridad de Autotransportes (FMCSA)","Kansas Department of Transportation (KDOT)"],"explanation":"KDOT administra los permisos de sobredimensión/sobrepeso y las rutas a través del Kansas Truck Routing and Intelligent Permitting System (K-TRIPS). Fuente: KDOT Commercial Vehicle Information."},"80":{"q":"¿Qué agencia estatal de Kansas emite las Licencias de Conducir Comerciales (CDL)?","options":["La Administración Federal de Seguridad de Autotransportes (FMCSA)","El Kansas Department of Transportation (KDOT)","El Kansas Department of Revenue, Division of Vehicles","La Patrulla de Caminos de Kansas"],"explanation":"En Kansas, la CDL es emitida por el Kansas Department of Revenue (KDOR), Division of Vehicles, que también publica el manual CDL de Kansas. KDOT se encarga de las carreteras y los permisos, pero no de las licencias de conducir. Fuente: página de CDL del Kansas DOR Division of Vehicles (ksrevenue.gov/dovcdl.html)."},"81":{"q":"Antes de que un solicitante de Kansas pueda tomar el examen de habilidades del CDL, se deben aprobar tanto los exámenes de conocimientos como los de habilidades. ¿Qué dos tipos generales de exámenes dice el manual CDL de Kansas que se deben aprobar para obtener una CDL o CLP?","options":["Solo un examen escrito y un examen de la vista","Solo un examen médico y una verificación de antecedentes","Un examen de señales de tránsito y un curso de manejo defensivo","Exámenes de conocimientos y exámenes de habilidades"],"explanation":"El manual CDL de Kansas indica: 'Para obtener una CDL o CLP, debe aprobar los exámenes de conocimientos y de habilidades.' La certificación de la vista y la médica son requisitos aparte. Fuente: Manual CDL de Kansas, Sección 1.1, 'Commercial Driver License Tests.'"},"82":{"q":"El examen de habilidades del CDL de Kansas consta de tres segmentos que deben realizarse en un orden establecido. ¿Cuál secuencia es correcta?","options":["Manejo en carretera, luego inspección del vehículo, luego control básico del vehículo","Inspección del vehículo, luego control básico del vehículo, luego manejo en carretera","Inspección del vehículo, luego manejo en carretera, luego control básico del vehículo","Control básico del vehículo, luego manejo en carretera, luego inspección del vehículo"],"explanation":"El manual CDL de Kansas indica que el examen de habilidades tiene tres segmentos -inspección del vehículo, control básico del vehículo y manejo en carretera- y que se deben realizar en ese orden, aprobando cada uno antes de pasar al siguiente. Fuente: Manual CDL de Kansas, Sección 1.1.2, 'Skills Tests.'"},"83":{"q":"¿Entre cuántas categorías de autocertificación debe elegir un solicitante de CDL de Kansas al declarar el tipo de comercio en el que opera?","options":["Cinco","Tres","Cuatro","Dos"],"explanation":"Kansas exige que los solicitantes/titulares de CDL se autocertifiquen en una de cuatro categorías de comercio. Fuente: Manual CDL de Kansas, Sección 1.2 ('los cuatro tipos de comercio que debe autocertificar') y la página Medical Certification Information del Kansas DOR."},"84":{"q":"¿Cuál de las siguientes es una de las cuatro categorías de autocertificación del CDL de Kansas?","options":["Provisional Intrastate","Non-excepted Interstate","Restricted Interstate","Exempt Federal"],"explanation":"Las cuatro categorías de autocertificación de Kansas son Non-excepted Interstate, Excepted Interstate, Non-excepted Intrastate y Excepted Intrastate. 'Restricted', 'Provisional' y 'Exempt Federal' no son categorías. Fuente: página Medical Certification Information del Kansas DOR; Manual CDL de Kansas, Sección 1.2."},"85":{"q":"Un conductor de Kansas que se autocertifica como 'Non-excepted Interstate' ¿qué debe hacer para mantener un estado médico 'certificado'?","options":["Llevar una copia impresa de su examen físico en la cabina en todo momento","Aprobar un examen adicional de conocimientos de frenos de aire cada año","Mantener vigente un certificado de examinador médico (tarjeta médica DOT)","Renovar su CDL cada año en lugar de cada cuatro años"],"explanation":"Los conductores non-excepted interstate deben proporcionar y mantener vigente un certificado federal de examinador médico (49 CFR 391.45), o de lo contrario pasan a estar 'not-certified' y pueden perder la CDL. Fuente: Manual CDL de Kansas, Sección 1.2, Medical Documentation Requirements."},"86":{"q":"A partir del 2 de junio de 2025, ¿cómo debe llegar a la Division of Vehicles el certificado de examinador médico (MEC) de un titular de CDL de Kansas?","options":["Enviado por correo por el conductor al apartado postal (P.O. Box) de KDOR en Topeka","Enviado por fax por el empleador del conductor a KDOR","Entregado en persona por el conductor en cualquier estación de exámenes de licencias","De forma electrónica desde el National Registry of Certified Medical Examiners"],"explanation":"A partir del 6/2/2025, Kansas ya no acepta MEC presentados por el conductor y ya no puede ingresarlos manualmente; los datos certificados deben llegar de forma electrónica desde el National Registry of Certified Medical Examiners (el examinador los ingresa). Fuente: página Medical Certification Information del Kansas DOR (ksrevenue.gov/dovmedcertfaq.html)."},"87":{"q":"Bajo el proceso de Kansas de junio de 2025, ¿cuánto tiempo tiene un examinador médico certificado para ingresar un nuevo MEC en el National Registry?","options":["De inmediato, antes de que el conductor salga del consultorio","Hasta la medianoche del siguiente día calendario","Dentro de los 10 días hábiles del examen","Dentro de los 30 días del examen"],"explanation":"Kansas señala que el examinador médico tiene hasta la medianoche del día siguiente para ingresar el MEC en el National Registry, desde donde Kansas luego lo recibe de forma electrónica. Fuente: página Medical Certification Information del Kansas DOR."},"88":{"q":"Para los solicitantes de CDL por primera vez en Kansas, ¿cuándo debe completarse el requisito federal de Entry-Level Driver Training (ELDT)?","options":["Dentro de los 30 días después de emitida la CDL","Solo después de una primera infracción de movimiento","Antes de tomar el examen de habilidades del CDL","Antes de renovar la CDL por primera vez"],"explanation":"El ELDT (vigente desde el 7 de febrero de 2022) exige capacitación teórica y práctica detrás del volante de un proveedor registrado ante FMCSA, completada antes de que el solicitante pueda tomar el examen de habilidades del CDL. Este estándar federal aplica en Kansas. Fuente: regla ELDT de FMCSA (49 CFR Part 380, Subpart F); FMCSA Training Provider Registry."},"89":{"q":"Un solicitante de CDL de nivel inicial en Kansas debe obtener la capacitación ELDT requerida de un proveedor que esté listado ¿dónde?","options":["En la lista de escuelas aprobadas del Kansas DOR","En el registro de transportistas de la Patrulla de Caminos de Kansas","En el National Registry of Certified Medical Examiners","En el FMCSA Training Provider Registry (TPR)"],"explanation":"El ELDT debe ser impartido por una escuela listada en el FMCSA Training Provider Registry (TPR); la finalización se reporta de forma electrónica a FMCSA antes de que el estado permita el examen de habilidades. Fuente: FMCSA Entry-Level Driver Training, Training Provider Registry."},"90":{"q":"Obtener cuál de los siguientes endosos por primera vez activa el requisito de capacitación ELDT antes del examen?","options":["Solo la autorización de frenos de aire","Pasajeros (P), Autobús Escolar (S) o Materiales Peligrosos (H)","Solo Dobles/Triples (T)","Solo Tanque (N)"],"explanation":"El ELDT aplica a los solicitantes de CDL por primera vez, a los ascensos de Clase B a A, y a los endosos P, S o H por primera vez. Los endosos de Dobles/Triples y Tanque no activan el ELDT por sí solos. Fuente: aplicabilidad del ELDT de FMCSA (49 CFR Part 380, Subpart F)."},"91":{"q":"Ascender una CDL Clase B existente a una CDL Clase A en Kansas requiere qué paso adicional bajo la regla federal del ELDT?","options":["Nada adicional; el ascenso es automático","Tener primero la CDL Clase B por al menos cinco años","Volver a tomar solo el examen de conocimientos generales","Completar el ELDT de ascenso a Clase A antes del examen de habilidades"],"explanation":"Un ascenso de Clase B a Clase A es una de las operaciones cubiertas por el ELDT, por lo que el conductor debe completar el programa de capacitación de ascenso de un proveedor listado en el TPR antes de tomar el examen de habilidades de Clase A. Fuente: regla ELDT de FMCSA (49 CFR Part 380, Subpart F)."},"92":{"q":"Después de que se emite un CLP a un solicitante de Kansas, ¿cuánto tiempo debe esperar antes de ser elegible para tomar el examen de habilidades del CDL?","options":["Al menos 30 días","Al menos 60 días","Al menos 14 días","Al menos 7 días"],"explanation":"Un titular de CLP debe tener el permiso por al menos 14 días antes de tomar el examen de habilidades del CDL. Este requisito federal se aplica en Kansas. Fuente: 49 CFR 383.25; guía para solicitantes de CDL de Kansas."},"93":{"q":"¿Con qué frecuencia debe renovarse una CDL estándar de Kansas?","options":["Cada 6 años","Cada 8 años","Cada 2 años","Cada 4 años"],"explanation":"Las CDL de Kansas se emiten en un ciclo de 4 años y deben renovarse cada cuatro años, independientemente del ciclo de 6 años que se usa para algunas licencias no comerciales de Kansas. Fuente: información de licencias del Kansas DOR Division of Vehicles."},"94":{"q":"¿Cuál es la edad mínima para obtener una CDL de Kansas para operación intraestatal (solo dentro de Kansas)?","options":["18 años","19 años","21 años","16 años"],"explanation":"Una CDL de Kansas para operación intraestatal puede emitirse a los 18 años; la operación interestatal (y los materiales peligrosos) requiere tener 21 años. Fuente: Manual CDL de Kansas; reglas de calificación de conductores de FMCSA (49 CFR 391.11)."},"95":{"q":"¿Cuál es la edad mínima para operar un vehículo motor comercial en comercio interestatal con una CDL de Kansas?","options":["25 años","21 años","18 años","23 años"],"explanation":"La operación interestatal de un CMV, y el transporte de materiales peligrosos, requiere que el conductor tenga al menos 21 años. Los conductores de 18 a 20 años están limitados a la operación intraestatal. Fuente: reglas de calificación de conductores de FMCSA (49 CFR 391.11); guía de CDL de Kansas."},"96":{"q":"¿Qué conjunto de documentos refleja mejor lo que un solicitante de Kansas debe proporcionar para solicitar un CLP/CDL?","options":["Solo un pasaporte, sin necesidad de comprobante de residencia","Comprobante de identidad/fecha de nacimiento, número de Seguro Social, presencia legal y dos comprobantes de residencia en Kansas","Un diploma de preparatoria y una carta de referencia de un empleador","Solo una licencia no comercial vigente de Kansas y una foto"],"explanation":"Kansas exige comprobante de identidad/fecha de nacimiento, comprobante de número de Seguro Social, comprobante de presencia legal y dos documentos que prueben la residencia en Kansas (domicilio físico); los solicitantes también deben tener ya una licencia de conducir no comercial de Kansas. Fuente: requisitos de solicitud del Kansas DOR Division of Vehicles."},"97":{"q":"Una pregunta de proceso de Kansas sobre tarifas: ¿qué afirmación sobre las tarifas de CDL es correcta para enseñar a los solicitantes?","options":["La tarifa de la CDL está fijada permanentemente por estatuto de Kansas y nunca cambia","Kansas no cobra ninguna tarifa por una CDL ni por sus endosos","Las tarifas de CDL son establecidas a nivel federal por FMCSA y son idénticas en cada estado","Las tarifas de CDL y de endosos son establecidas por Kansas y pueden cambiar, por lo que los solicitantes deben confirmar los montos actuales con KDOR"],"explanation":"Las tarifas de CDL, de endosos y de CLP son establecidas por el estado y están sujetas a cambios; los solicitantes deben verificar los montos actuales con el Kansas DOR en lugar de confiar en una cifra fija. Las tarifas las establece el estado, no son uniformes a nivel federal. Fuente: guía del esquema de tarifas del Kansas DOR Division of Vehicles."}},"hi":{"0":{"q":"कैनसस के राजमार्गों पर, बिना परमिट के किसी वाहन या उसके लोड की अधिकतम कुल बाहरी चौड़ाई कितनी हो सकती है?","options":["8 feet (96 inches)","8 1/2 feet (102 inches)","9 feet (108 inches)","10 feet (120 inches)"],"explanation":"K.S.A. 8-1902 किसी भी वाहन या उसके लोड की कुल बाहरी चौड़ाई को 8 1/2 feet (102 inches) तक सीमित करता है। कैनसस CDL हैंडबुक और कैनसस हाईवे पेट्रोल भी यही मानक चौड़ाई सीमा बताते हैं।"},"1":{"q":"कैनसस के राजमार्गों पर लोड सहित किसी वाहन की सामान्य अधिकतम ऊँचाई कितनी होती है?","options":["13 feet 6 inches","14 feet","14 feet 6 inches","15 feet"],"explanation":"K.S.A. 8-1904 अधिकतम वाहन ऊँचाई (लोड सहित) 14 feet निर्धारित करता है। कैनसस हाईवे पेट्रोल 14 feet को वैध ऊँचाई सीमा के रूप में पुष्टि करता है।"},"2":{"q":"कैनसस एक प्रकार के लोड को 14-foot की ऊँचाई सीमा से अधिक होने और 14 1/2 feet तक सुरक्षित रखने की अनुमति देता है। वह लोड कौन-सा है?","options":["गाँठ बँधी कपास (Baled cotton)","बेलनाकार आकार की घास की गाँठें","निर्माण के स्टील बीम","शिपिंग कंटेनर"],"explanation":"K.S.A. 8-1904 बेलनाकार आकार की घास की गाँठें ले जाने वाले वाहन को 14 1/2 feet तक लोड करने की अनुमति देता है; यदि लोड किसी ओवरपास से टकराता है तो किसी भी क्षति के लिए ऑपरेटर ज़िम्मेदार होता है।"},"3":{"q":"कैनसस के राजमार्गों पर लोड सहित किसी एकल मोटर वाहन (जैसे स्ट्रेट ट्रक) की अधिकतम लंबाई कितनी हो सकती है?","options":["40 feet","45 feet","48 feet","53 feet"],"explanation":"K.S.A. 8-1904 लोड सहित किसी एकल मोटर वाहन को 45 feet की चरम समग्र माप तक सीमित करता है।"},"4":{"q":"ट्रक-ट्रैक्टर और सेमीट्रेलर के संयोजन में, कैनसस में अनुमत सेमीट्रेलर की अधिकतम लंबाई कितनी होती है?","options":["48 feet","53 feet","57 feet","59 1/2 feet"],"explanation":"K.S.A. 8-1904 यह प्रावधान करता है कि ट्रक-ट्रैक्टर के साथ संयोजन में संचालित सेमीट्रेलर की लंबाई 59 1/2 feet से अधिक नहीं होगी।"},"5":{"q":"कैनसस के राजमार्गों पर बिना परमिट के किसी वाहन के किसी एकल एक्सल पर अनुमत अधिकतम सकल भार कितना होता है?","options":["18,000 pounds","20,000 pounds","22,000 pounds","24,000 pounds"],"explanation":"K.S.A. 8-1908 किसी एक एक्सल पर सकल भार को 20,000 pounds तक (और किसी एक पहिये पर 10,000 pounds तक) सीमित करता है।"},"6":{"q":"कैनसस में बिना परमिट के किसी टैंडम एक्सल समूह पर अनुमत अधिकतम सकल भार कितना होता है?","options":["32,000 pounds","34,000 pounds","36,000 pounds","40,000 pounds"],"explanation":"K.S.A. 8-1908 टैंडम एक्सल पर सकल भार को 34,000 pounds तक सीमित करता है, जो संघीय मानक के अनुरूप है।"},"7":{"q":"कैनसस कानून के तहत किसी वाहन के किसी एकल पहिये पर अधिकतम सकल भार कितना हो सकता है?","options":["8,000 pounds","10,000 pounds","12,000 pounds","17,000 pounds"],"explanation":"K.S.A. 8-1908 कहता है कि किसी वाहन के किसी पहिये पर सकल भार 10,000 pounds से अधिक नहीं होगा।"},"8":{"q":"कैनसस में इंटरस्टेट राजमार्ग प्रणाली पर, बिना परमिट के अनुमत अधिकतम सकल वाहन भार कितना होता है?","options":["73,280 pounds","80,000 pounds","85,500 pounds","90,000 pounds"],"explanation":"K.S.A. 8-1909 के तहत, एक्सल-स्पेसिंग भार तालिका इंटरस्टेट प्रणाली पर 80,000 pounds से अधिक सकल भार को अधिकृत नहीं कर सकती, जो संघीय कानून के अनुरूप है।"},"9":{"q":"कैनसस राज्य और U.S. राजमार्गों पर जो इंटरस्टेट प्रणाली का हिस्सा नहीं हैं, एक्सल-स्पेसिंग तालिका अधिकतम कितने सकल भार की अनुमति दे सकती है?","options":["80,000 pounds","85,500 pounds","90,000 pounds","94,000 pounds"],"explanation":"K.S.A. 8-1909 की एक्सल-स्पेसिंग तालिका कैनसस और U.S. (गैर-इंटरस्टेट) राजमार्गों पर 85,500 pounds तक सकल भार की अनुमति देती है, जो 80,000-pound की इंटरस्टेट सीमा से अधिक है।"},"10":{"q":"कैनसस मुख्य रूप से किस विधि का उपयोग करके दो या अधिक क्रमागत एक्सल के समूह पर अधिकतम सकल भार निर्धारित करता है?","options":["एक समान प्रति-ट्रेलर भार सीमा","एक्सल-स्पेसिंग भार तालिका (ब्रिज फॉर्मूला)","केवल टायरों की संख्या","केवल ट्रक का पंजीकृत भार"],"explanation":"K.S.A. 8-1909 एक्सल के बीच की दूरी और एक्सल की संख्या पर आधारित एक्सल-स्पेसिंग भार तालिका का उपयोग करता है, जो संघीय ब्रिज फॉर्मूला का कैनसस रूप है, ताकि क्रमागत एक्सल के समूह पर अधिकतम भार निर्धारित किया जा सके।"},"11":{"q":"कैनसस ब्रिज/एक्सल-स्पेसिंग अवधारणा के तहत, कोई वाहन एक्सल के समूह पर कानूनी रूप से अधिक कुल भार कैसे ले जा सकता है?","options":["टायर का दबाव बढ़ाकर","एक्सल को आपस में और दूर फैलाकर तथा एक्सल जोड़कर","ट्रेलर की लंबाई घटाकर","ट्रेलर के फर्श की ऊँचाई कम करके"],"explanation":"K.S.A. 8-1909 एक्सल-स्पेसिंग तालिका (ब्रिज फॉर्मूला) पुलों की रक्षा के लिए एक्सल के बीच की दूरी बढ़ने और एक्सल की संख्या बढ़ने पर अधिक कुल भार की अनुमति देती है।"},"12":{"q":"ऐसा लोड जो कैनसस की कानूनी आकार या भार सीमाओं से अधिक है और जिसे घटाया नहीं जा सकता (एक अविभाज्य लोड), उसे यात्रा करने से पहले किसकी आवश्यकता होती है?","options":["कुछ नहीं, यदि दिन के उजाले में यात्रा हो रही हो","KDOT से एक ओवरसाइज़/ओवरवेट परमिट","शिपर से एक नोट","केवल एक संघीय DOT छूट"],"explanation":"कैनसस DOT कानूनी सीमाओं से अधिक अविभाज्य लोड के लिए एक ओवरसाइज़/ओवरवेट परमिट आवश्यक करता है; परमिट KDOT की K-TRIPS प्रणाली के माध्यम से प्राप्त किए जाते हैं।"},"13":{"q":"ओवरसाइज़/ओवरवेट परमिट के लिए आवेदन करने और उन्हें प्राप्त करने के लिए किस कैनसस प्रणाली का उपयोग किया जाता है?","options":["IRP Online","K-TRIPS (Kansas Truck Routing and Intelligent Permitting System)","IFTA Web","CDLIS"],"explanation":"KDOT ओवरसाइज़/ओवरवेट परमिट K-TRIPS (Kansas Truck Routing and Intelligent Permitting System) के माध्यम से जारी करता है; आवेदक ऑनलाइन पंजीकरण करते हैं और वाहन, लोड तथा मार्ग का विवरण प्रस्तुत करते हैं।"},"14":{"q":"एक मानक एकल-यात्रा कैनसस ओवरसाइज़/ओवरवेट परमिट आम तौर पर कितने समय के लिए वैध होता है?","options":["24 hours","3 days","7 days","30 days"],"explanation":"KDOT के एकल-यात्रा ओवरसाइज़/ओवरवेट परमिट आम तौर पर जारी होने की तारीख से seven days के लिए वैध होते हैं।"},"15":{"q":"कैनसस में किसी ओवरसाइज़ परमिट वाले लोड की आवाजाही आम तौर पर दिन के किस समय तक सीमित होती है?","options":["किसी भी समय, दिन या रात","सूर्योदय से आधा घंटा पहले से सूर्यास्त के आधे घंटे बाद तक","केवल मध्यरात्रि और सुबह 6 बजे के बीच","केवल कार्यदिवसों पर व्यावसायिक घंटों के दौरान"],"explanation":"KDOT परमिट की शर्तें आम तौर पर ओवरसाइज़ लोड की आवाजाही को सूर्योदय से आधा घंटा पहले से सूर्यास्त के आधे घंटे बाद तक सीमित करती हैं, जिसमें सप्ताहांत और छुट्टियाँ शामिल हैं, तथा परमिट पर उल्लिखित अपवाद होते हैं।"},"16":{"q":"कैनसस में किस चौड़ाई पर कोई वाहन या लोड 'ओवरसाइज़' हो जाता है, जिसके लिए परमिट की आवश्यकता होती है?","options":["8 feet से अधिक","8 feet 6 inches से अधिक","10 feet से अधिक","12 feet से अधिक"],"explanation":"चूँकि K.S.A. 8-1902 कानूनी चौड़ाई 8 1/2 feet (8 feet 6 inches) निर्धारित करता है, इसलिए 8 feet 6 inches से अधिक चौड़ा कोई भी वाहन या लोड ओवरसाइज़ होता है और उसके लिए KDOT परमिट की आवश्यकता होती है।"},"17":{"q":"एक सामान्य कैनसस ओवरवेट परमिट (KAR 36-1-37) के तहत, किसी एकल एक्सल पर अधिकतम अनुमत भार कितना होता है?","options":["20,000 pounds","22,000 pounds","24,000 pounds","26,000 pounds"],"explanation":"KAR 36-1-37 के तहत कैनसस ओवरवेट परमिट सीमाएँ एकल नॉन-ड्राइव एक्सल की अधिकतम सीमा को 22,000 pounds तक (और टैंडम एक्सल को 45,000 pounds तक) बढ़ाती हैं, जो 20,000-pound की कानूनी सीमा से अधिक है।"},"18":{"q":"कैनसस कृषि वस्तुओं, आपूर्तियों और जैव-ईंधन के लिए एक विशेष वार्षिक ओवरवेट विभाज्य-लोड परमिट प्रदान करता है। इसका अधिकतम सकल भार क्या है, और इसकी अनुमति कहाँ नहीं है?","options":["80,000 pounds; काउंटी सड़कों पर नहीं","90,000 pounds; इंटरस्टेट प्रणाली पर नहीं","100,000 pounds; शहरों के भीतर नहीं","85,500 pounds; पुलों पर नहीं"],"explanation":"कैनसस कृषि इनपुट्स, वस्तुओं, पशुधन और जैव-ईंधन के लिए कम से कम छह एक्सल के साथ 90,000 pounds तक का वार्षिक ओवरवेट विभाज्य-लोड परमिट देता है, और ऐसे वाहन इंटरस्टेट प्रणाली पर संचालित नहीं हो सकते।"},"19":{"q":"कैनसस में, 85,500 pounds से अधिक भार पर संचालित कोई वाहन किस स्थिति में यात्रा करने से प्रतिबंधित है?","options":["जब बारिश हो रही हो","जब राजमार्ग की सतह पर बर्फ, जमी हुई बर्फ या उड़ती हुई बर्फ हो","फसल के मौसम के दौरान","किसी शहर के 50 miles के भीतर"],"explanation":"K.S.A. 8-1919 85,500 pounds से अधिक भार पर संचालित वाहनों को तब यात्रा करने से प्रतिबंधित करता है जब राजमार्ग की सतह पर बर्फ, जमी हुई बर्फ या उड़ती हुई बर्फ हो।"},"20":{"q":"कैनसस में, ऐसे एकल वाहन को संचालित करने के लिए कौन-सा CDL वर्ग आवश्यक होता है जिसकी सकल वाहन भार रेटिंग 26,001 pounds या उससे अधिक हो, जहाँ कोई भी खींची गई इकाई 10,000 pounds GVWR से अधिक न हो?","options":["Class A","Class B","Class C","Class D"],"explanation":"कैनसस एक Class B CDL को किसी भी ऐसे एकल वाहन के रूप में परिभाषित करता है जिसकी GVWR 26,001 lbs या उससे अधिक हो, या ऐसा वाहन जो एक ऐसी इकाई को खींच रहा हो जो 10,000 lbs GVWR से अधिक न हो। स्रोत: Kansas CDL Manual (KDOR) और K.S.A. 8-2,128।"},"21":{"q":"जब खींची गई इकाई 10,000 pounds से अधिक हो, तो कैनसस Class A CDL को परिभाषित करने वाली न्यूनतम सकल संयोजन भार रेटिंग कितनी होती है?","options":["18,000 pounds","26,001 pounds","33,000 pounds","10,001 pounds"],"explanation":"एक कैनसस Class A CDL में 26,001 lbs या उससे अधिक GCWR वाले वाहनों का कोई भी संयोजन शामिल होता है, बशर्ते खींची गई इकाई(याँ) की GVWR 10,000 lbs से अधिक हो। स्रोत: Kansas CDL Manual (KDOR); K.S.A. 8-2,128।"},"22":{"q":"एक चालक 26,001 pounds से कम GVWR वाली एक वैन में प्लेकार्ड योग्य मात्रा में खतरनाक सामग्री ले जाता है। कौन-सा कैनसस CDL वर्ग और एंडोर्समेंट संयोजन लागू होता है?","options":["बिना किसी एंडोर्समेंट के Class A","N एंडोर्समेंट के साथ Class B","H एंडोर्समेंट के साथ Class C","P एंडोर्समेंट के साथ Class D"],"explanation":"यदि कोई वाहन Class A या B भार परिभाषाओं को पूरा नहीं करता परंतु प्लेकार्ड योग्य मात्रा में खतरनाक सामग्री ले जाता है (या 16+ यात्री ले जाता है), तो कैनसस को एक Class C CDL की आवश्यकता होती है, साथ ही HazMat के लिए H एंडोर्समेंट की। स्रोत: Kansas CDL Manual (KDOR); 49 CFR 383.91।"},"23":{"q":"एक कैनसस CDL पर, 'N' एंडोर्समेंट चालक को क्या करने के लिए अधिकृत करता है?","options":["टैंक वाहन संचालित करना","खतरनाक सामग्री का परिवहन करना","डबल और ट्रिपल ट्रेलर खींचना","एक स्कूल बस चलाना"],"explanation":"कैनसस में 'N' एंडोर्समेंट टैंक वाहनों के संचालन की अनुमति देता है। स्रोत: K.S.A. 8-2,135; Kansas CDL Manual (KDOR)।"},"24":{"q":"डबल और ट्रिपल ट्रेलर खींचने के लिए कैनसस CDL पर कौन-सा एंडोर्समेंट कोड आवश्यक होता है?","options":["P","H","T","S"],"explanation":"'T' एंडोर्समेंट डबल और ट्रिपल ट्रेलर खींचने के लिए अधिकृत करता है; इसे केवल एक ज्ञान परीक्षा पास करके प्राप्त किया जाता है (कोई अलग कौशल परीक्षा नहीं)। स्रोत: K.S.A. 8-2,135; Kansas CDL Manual (KDOR)।"},"25":{"q":"एक वाहन चालक सहित 16 या अधिक लोगों के परिवहन के लिए डिज़ाइन किया गया है। कौन-सा कैनसस CDL एंडोर्समेंट आवश्यक है (स्कूल बस अपवाद को छोड़कर)?","options":["N (टैंकर)","P (यात्री)","T (डबल/ट्रिपल)","H (HazMat)"],"explanation":"चालक सहित 16 या अधिक लोगों को ले जाने के लिए डिज़ाइन किए गए वाहनों के लिए 'P' (यात्री) एंडोर्समेंट आवश्यक है, और इसके लिए ज्ञान तथा कौशल दोनों परीक्षाओं की आवश्यकता होती है। स्रोत: Kansas CDL Manual (KDOR); 49 CFR 383.93।"},"26":{"q":"कैनसस में स्कूल बस (S) एंडोर्समेंट प्राप्त करने के लिए, चालक के पास कौन-सा अन्य एंडोर्समेंट भी होना चाहिए?","options":["H (खतरनाक सामग्री)","N (टैंक वाहन)","P (यात्री)","T (डबल/ट्रिपल)"],"explanation":"कैनसस के लिए आवश्यक है कि चालक 'S' (स्कूल बस) एंडोर्समेंट जोड़ने से पहले पहले 'P' (यात्री) एंडोर्समेंट रखें, जिसके लिए अतिरिक्त ज्ञान और कौशल परीक्षाएँ पास करना भी आवश्यक है। स्रोत: Kansas CDL Manual (KDOR); 49 CFR 383.93।"},"27":{"q":"इससे पहले कि कैनसस खतरनाक सामग्री (H) एंडोर्समेंट जारी कर सके, आवेदक को कौन-सी अतिरिक्त संघीय आवश्यकता पूरी करनी होती है?","options":["एक TSA सुरक्षा खतरा मूल्यांकन (पृष्ठभूमि जाँच)","FMCSA से एक दृष्टि छूट","30-दिन की सड़क प्रशिक्षुता","एक एयर ब्रेक कौशल पुनः-परीक्षा"],"explanation":"H (HazMat) एंडोर्समेंट के लिए एक ज्ञान परीक्षा पास करना और एक TSA सुरक्षा खतरा मूल्यांकन, जिसमें फिंगरप्रिंटिंग और पृष्ठभूमि जाँच शामिल है, की आवश्यकता होती है, इससे पहले कि कैनसस इसे जारी करे। स्रोत: Kansas CDL Manual (KDOR); 49 CFR 383.71/1572।"},"28":{"q":"केवल इंट्रास्टेट (कैनसस के भीतर) ड्राइविंग तक सीमित कैनसस CDL प्राप्त करने के लिए न्यूनतम आयु क्या है?","options":["16 वर्ष","17 वर्ष","18 वर्ष","21 वर्ष"],"explanation":"कैनसस के लिए आवश्यक है कि चालक केवल इंट्रास्टेट संचालन के लिए CDL प्राप्त करने हेतु कम से कम 18 वर्ष का हो। स्रोत: Kansas CDL Manual (KDOR); K.S.A. 8-2,129।"},"29":{"q":"इंटरस्टेट ड्राइविंग (राज्य सीमाओं के पार) के लिए या खतरनाक सामग्री के परिवहन के लिए कैनसस CDL प्राप्त करने की न्यूनतम आयु क्या है?","options":["18 वर्ष","19 वर्ष","20 वर्ष","21 वर्ष"],"explanation":"इंटरस्टेट वाणिज्य में CMV चलाने, खतरनाक सामग्री का परिवहन करने, या राज्य सीमाओं के पार यात्रियों का परिवहन करने के लिए चालक को कम से कम 21 वर्ष का होना चाहिए। स्रोत: Kansas CDL Manual (KDOR); 49 CFR 391.11।"},"30":{"q":"कैनसस में एक Commercial Learner's Permit (CLP) पहली बार जारी होने के बाद, आवेदक को CDL कौशल परीक्षा देने के लिए पात्र होने से पहले इसे कितने समय तक रखना होता है?","options":["कम से कम 7 days","कम से कम 14 days","कम से कम 30 days","कम से कम 60 days"],"explanation":"कैनसस द्वारा अपनाया गया संघीय नियम: एक CLP धारक तब तक CDL कौशल परीक्षा देने के लिए पात्र नहीं होता जब तक कि परमिट को न्यूनतम 14 days तक न रखा गया हो। स्रोत: Kansas CDL Manual (KDOR); 49 CFR 383.25।"},"31":{"q":"अभ्यास के लिए वाणिज्यिक मोटर वाहन चलाते समय एक कैनसस CLP धारक को क्या करना होता है?","options":["केवल सूर्योदय और सूर्यास्त के बीच चलाना","एक CDL धारक के साथ रहना जो उनके बगल में अगली सीट पर बैठा हो","ड्राइविंग को घर के 25-mile दायरे तक सीमित रखना","किसी भी प्रकार का कार्गो न ले जाना"],"explanation":"एक कैनसस CLP धारक CMV को केवल तभी संचालित कर सकता है जब वह उस वाहन प्रकार के लिए वैध CDL रखने वाले व्यक्ति के साथ हो, जिसे चालक के बगल में अगली सीट पर बैठा होना चाहिए। स्रोत: Kansas CDL Manual (KDOR); 49 CFR 383.25।"},"32":{"q":"कैनसस द्वारा अपनाए गए संघीय मानकों के तहत, एक Commercial Learner's Permit बिना पुनः-परीक्षा के अधिकतम कितनी अवधि से अधिक के लिए वैध नहीं होना चाहिए?","options":["90 days","6 months","1 year","5 years"],"explanation":"एक CLP प्रारंभिक जारी होने से 1 year से अधिक के लिए जारी नहीं किया जा सकता, जिसके बाद आवेदक को ज्ञान परीक्षाएँ दोबारा देनी पड़ती हैं। स्रोत: Kansas CDL Manual (KDOR); 49 CFR 383.25।"},"33":{"q":"आवेदन करते समय एक कैनसस CDL आवेदक को Division of Vehicles को कौन-से दस्तावेज़ों का सेट प्रस्तुत करना होता है?","options":["पहचान का प्रमाण, Social Security number, कैनसस निवास, और वैध उपस्थिति","केवल एक Social Security कार्ड और एक जन्म प्रमाणपत्र","एक पासपोर्ट और एक वाहन पंजीकरण","रोजगार का प्रमाण और एक HazMat परमिट"],"explanation":"Kansas Department of Revenue, Division of Vehicles के लिए आवश्यक है कि आवेदक पहचान सिद्ध करें, अपना Social Security number प्रदान करें, और कैनसस निवास तथा वैध (कानूनी) उपस्थिति का प्रमाण दिखाएँ। स्रोत: Kansas Department of Revenue, Division of Vehicles (ksrevenue.gov)।"},"34":{"q":"पहली बार के Class A/B आवेदकों के लिए कैनसस द्वारा आवश्यक Entry-Level Driver Training (ELDT) ऐसे प्रशिक्षण संस्थान द्वारा प्रदान किया जाना चाहिए जो:","options":["स्थानीय स्कूल जिले द्वारा अनुमोदित हो","FMCSA Training Provider Registry में सूचीबद्ध हो","कैनसस हाईवे पेट्रोल द्वारा प्रमाणित हो","U.S. Department of Education द्वारा मान्यता प्राप्त हो"],"explanation":"7 फरवरी 2022 से, ELDT को FMCSA Training Provider Registry (TPR) में सूचीबद्ध किसी प्रदाता के माध्यम से पूरा किया जाना चाहिए, इससे पहले कि कैनसस कुछ कौशल/ज्ञान परीक्षाओं की अनुमति दे। स्रोत: Kansas Department of Revenue (dovcdlentry.html); 49 CFR Part 380।"},"35":{"q":"निम्नलिखित में से कौन-सी पहली बार की कार्रवाई कैनसस में संघीय ELDT आवश्यकता को ट्रिगर नहीं करती?","options":["पहली बार Class A CDL प्राप्त करना","Class B CDL को Class A CDL में अपग्रेड करना","पहली बार खतरनाक सामग्री (H) एंडोर्समेंट प्राप्त करना","बिना किसी नए एंडोर्समेंट के मौजूदा Class A CDL का नवीनीकरण करना"],"explanation":"ELDT पहली बार Class A/B जारी करने, Class B-से-A अपग्रेड, और पहली बार के H, P, या S एंडोर्समेंट पर लागू होता है। बिना किसी अपग्रेड या नए एंडोर्समेंट के मौजूदा CDL के नियमित नवीनीकरण के लिए ELDT की आवश्यकता नहीं होती। स्रोत: Kansas Department of Revenue (dovcdlentry.html); 49 CFR Part 380।"},"36":{"q":"एक कैनसस CDL चालक जो केवल कैनसस के भीतर संचालित करता है और चिकित्सा आवश्यकताओं से छूट प्राप्त नहीं है, उसे किस श्रेणी के रूप में स्व-प्रमाणित करना चाहिए?","options":["Non-excepted interstate","Excepted interstate","Non-excepted intrastate","Excepted intrastate"],"explanation":"केवल कैनसस के भीतर संचालन करने वाला चालक जो चिकित्सा प्रमाणपत्र आवश्यकता के अधीन है, 'Non-excepted intrastate' के रूप में स्व-प्रमाणित होता है और उसे एक वर्तमान Medical Examiner's Certificate बनाए रखना चाहिए। स्रोत: Kansas Department of Revenue, Medical Certification (ksrevenue.gov); 49 CFR 383.71।"},"37":{"q":"कौन-सी कैनसस CDL स्व-प्रमाणन श्रेणी के लिए चालक को एक वर्तमान संघीय Medical Examiner's Certificate बनाए रखना और प्रस्तुत करना आवश्यक है?","options":["Excepted interstate","Excepted intrastate","Non-excepted interstate","Restricted farm operator"],"explanation":"Non-excepted interstate (और non-excepted intrastate) के रूप में प्रमाणित होने वाले चालकों को एक वर्तमान Medical Examiner's Certificate बनाए रखना चाहिए; छूट प्राप्त चालक चिकित्सा दस्तावेज़ प्रस्तुत नहीं करते। स्रोत: Kansas Department of Revenue, Medical Certification (ksrevenue.gov); 49 CFR 383.71।"},"38":{"q":"कैनसस/संघीय नियमों के तहत, N एंडोर्समेंट के लिए एक 'टैंक वाहन' आम तौर पर ऐसा होता है जो स्थायी या अस्थायी रूप से जुड़े टैंक में किसी तरल या गैस को ले जाने के लिए डिज़ाइन किया गया हो, जिसकी रेटेड क्षमता कम से कम हो:","options":["100 gallons","500 gallons","1,000 gallons","5,000 gallons"],"explanation":"N (टैंक) एंडोर्समेंट उन वाहनों पर लागू होता है जो 1,000 gallons या उससे अधिक की समग्र रेटेड क्षमता वाले टैंकों में तरल या गैसीय सामग्री ले जाते हैं (119 gallons या उससे अधिक के व्यक्तिगत टैंक)। स्रोत: Kansas CDL Manual (KDOR); 49 CFR 383.5।"},"39":{"q":"एक चालक कैनसस CDL पर खतरनाक सामग्री और टैंक एंडोर्समेंट को संयोजित करना चाहता है। कौन-सा एकल एंडोर्समेंट कोड उस संयोजन का प्रतिनिधित्व करता है?","options":["X","T","P","L"],"explanation":"कैनसस खतरनाक सामग्री (H) और टैंक (N) एंडोर्समेंट के संयोजन का प्रतिनिधित्व करने के लिए 'X' एंडोर्समेंट कोड का उपयोग करता है। स्रोत: K.S.A. 8-2,135; Kansas CDL Manual (KDOR)।"},"40":{"q":"कैनसस में, वह अधिकतम रक्त अल्कोहल सांद्रता (BAC) क्या है जिस पर कोई व्यक्ति कानूनी रूप से एक वाणिज्यिक मोटर वाहन (CMV) संचालित कर सकता है?","options":["0.08% या उससे अधिक सीमा है","0.04% से नीचे कोई भी BAC","0.10% से नीचे कोई भी BAC","0.02% से नीचे कोई भी BAC"],"explanation":"कैनसस 0.04% या उससे अधिक BAC के साथ CMV संचालित करने पर रोक लगाता है; CMV चालकों के लिए कानूनी सीमा 0.04% से नीचे है, जो सामान्य चालकों के लिए 0.08% सीमा की आधी है। स्रोत: Kansas CDL Manual, Section 1 (Driver Disqualifications); कैनसस में अपनाया गया 49 CFR 383.51।"},"41":{"q":"किसी पहले प्रमुख अपराध, जैसे CMV में DUI, के लिए कैनसस CDL धारक को कितने समय के लिए अयोग्य ठहराया जाता है, जब प्लेकार्ड वाली खतरनाक सामग्री का परिवहन नहीं किया जा रहा हो?","options":["60 days","1 year","3 years","6 months"],"explanation":"एक पहला प्रमुख अपराध (DUI, परीक्षण से इनकार, घटनास्थल छोड़ना, किसी अपराध में CMV का उपयोग, आदि) कैनसस में 1-year की अयोग्यता का परिणाम देता है। स्रोत: K.S.A. 8-2,142; Kansas CDL Manual; 49 CFR 383.51।"},"42":{"q":"यदि कोई कैनसस चालक प्लेकार्ड करने योग्य आवश्यक खतरनाक सामग्री का परिवहन करते समय पहला प्रमुख अपराध करता है, तो अयोग्यता कितने समय की होती है?","options":["1 year","3 years","आजीवन","120 days"],"explanation":"प्लेकार्ड वाली खतरनाक सामग्री का परिवहन करने वाले CMV को संचालित करते समय किया गया एक पहला प्रमुख अपराध कैनसस में मानक 1 year के बजाय 3-year की अयोग्यता का परिणाम देता है। स्रोत: K.S.A. 8-2,142; Kansas CDL Manual; 49 CFR 383.51।"},"43":{"q":"CMV में किए गए दूसरे प्रमुख अपराध के लिए कैनसस में अयोग्यता अवधि क्या है?","options":["3 years","10 years","आजीवन","5 years"],"explanation":"एक दूसरा प्रमुख अपराध कैनसस में CDL की आजीवन अयोग्यता का परिणाम देता है। स्रोत: K.S.A. 8-2,142; Kansas CDL Manual; 49 CFR 383.51(b)।"},"44":{"q":"कैनसस के निहित-सहमति (implied-consent) नियमों के तहत, एक CDL धारक जो साँस या रक्त के रासायनिक परीक्षण से इनकार करता है, उसे क्या करने वाला माना जाता है?","options":["एक गंभीर यातायात उल्लंघन","एक प्रमुख अपराध","एक आउट-ऑफ-सर्विस उल्लंघन","एक गैर-रिपोर्ट योग्य अपराध"],"explanation":"वैध रूप से अनुरोधित रासायनिक परीक्षण से इनकार करने को एक प्रमुख अपराध के रूप में वर्गीकृत किया जाता है, जिसमें DUI के समान ही 1-year (या 3-year HazMat) अयोग्यता होती है। स्रोत: K.S.A. 8-2,142; Kansas CDL Manual, Section 1।"},"45":{"q":"प्लेकार्ड वाली खतरनाक सामग्री न ले जाने वाले CMV को चलाते समय रासायनिक परीक्षण से इनकार करने के लिए एक कैनसस CDL धारक को कितने समय के लिए अयोग्य ठहराया जाता है?","options":["90 days","1 year","3 years","आजीवन"],"explanation":"CMV में पहली बार परीक्षण से इनकार करने पर 1-year की CDL अयोग्यता होती है (प्लेकार्ड वाली HazMat का परिवहन करने पर 3 years)। स्रोत: K.S.A. 8-2,142; 49 CFR 383.51।"},"46":{"q":"जब कोई कैनसस CDL चालक 3-year की अवधि के भीतर (CMV में) दो गंभीर यातायात उल्लंघन जमा करता है, तो न्यूनतम अयोग्यता होती है:","options":["30 days","60 days","120 days","1 year"],"explanation":"3 years के भीतर दो गंभीर यातायात उल्लंघन कैनसस में न्यूनतम 60-day की अयोग्यता का परिणाम देते हैं। स्रोत: Kansas CDL Manual, Section 1; 49 CFR 383.51(c)।"},"47":{"q":"जब कोई कैनसस CDL चालक 3-year की अवधि के भीतर (CMV में) तीन गंभीर यातायात उल्लंघन जमा करता है, तो न्यूनतम अयोग्यता होती है:","options":["60 days","90 days","120 days","180 days"],"explanation":"3 years के भीतर तीन गंभीर यातायात उल्लंघन कैनसस में न्यूनतम 120-day की अयोग्यता का परिणाम देते हैं। स्रोत: Kansas CDL Manual, Section 1; 49 CFR 383.51(c)।"},"48":{"q":"निम्नलिखित में से कौन-सा एक कैनसस CDL धारक के लिए 'गंभीर यातायात उल्लंघन' के रूप में गिना जाता है?","options":["गति सीमा से 15 mph या अधिक तेज़ चलाना","गति सीमा से 5 mph तेज़ चलाना","एक पार्किंग उल्लंघन","एक समाप्त पंजीकरण स्टिकर"],"explanation":"गंभीर यातायात उल्लंघनों में गति सीमा से 15 mph या अधिक तेज़ गति, लापरवाह ड्राइविंग, अनुचित या अनियमित लेन परिवर्तन, बहुत करीब से पीछा करना, और किसी घातक दुर्घटना से जुड़े यातायात अपराध शामिल हैं। स्रोत: Kansas CDL Manual, Section 1; 49 CFR 383.51(c)।"},"49":{"q":"कैनसस/संघीय CDL नियमों के तहत, CMV चलाते समय टेक्स्टिंग करना किस प्रकार के अपराध के रूप में वर्गीकृत किया जाता है?","options":["एक प्रमुख अपराध","एक गंभीर यातायात उल्लंघन","एक आउट-ऑफ-सर्विस उल्लंघन","एक रेलमार्ग-क्रॉसिंग उल्लंघन"],"explanation":"CMV चलाते समय टेक्स्टिंग करना, और CMV चलाते समय हैंड-हेल्ड मोबाइल फोन का उपयोग करना, गंभीर यातायात उल्लंघन हैं जो 2-in-3-years (60-day) और 3-in-3-years (120-day) अयोग्यताओं की ओर गिने जाते हैं। स्रोत: Kansas CDL Manual; 49 CFR 383.51(c) और 392.80/392.82।"},"50":{"q":"एक कैनसस CDL चालक के लिए, CMV संचालित करते समय हैंड-हेल्ड मोबाइल टेलीफोन का उपयोग करना किस रूप में माना जाता है:","options":["एक गैर-रिपोर्ट योग्य उल्लंघन","एक गंभीर यातायात उल्लंघन","एक प्रमुख अपराध","एक स्वचालित आजीवन प्रतिबंध"],"explanation":"CMV चलाते समय हैंड-हेल्ड फोन का उपयोग करना 49 CFR 392.82 का उल्लंघन है और एक गंभीर यातायात उल्लंघन है; चालक को एक संघीय नागरिक जुर्माने (up to $2,750) का सामना करना पड़ता है और यह उल्लंघन गंभीर-उल्लंघन अयोग्यताओं की ओर गिना जाता है। स्रोत: Kansas CDL Manual; 49 CFR 392.82, 383.51(c)।"},"51":{"q":"एक कैनसस CDL धारक के रेलमार्ग-राजमार्ग ग्रेड क्रॉसिंग उल्लंघन के पहले दोषसिद्धि के लिए अयोग्यता अवधि क्या है?","options":["30 days से कम नहीं","60 days से कम नहीं","120 days से कम नहीं","180 days से कम नहीं"],"explanation":"एक पहला रेलमार्ग-राजमार्ग ग्रेड क्रॉसिंग उल्लंघन कैनसस में 60 days से कम नहीं की अयोग्यता का परिणाम देता है। स्रोत: Kansas CDL Manual, Section 1; 49 CFR 383.51(d)।"},"52":{"q":"एक कैनसस CDL धारक 3-year की अवधि के भीतर दूसरा रेलमार्ग-राजमार्ग ग्रेड क्रॉसिंग उल्लंघन करता है। न्यूनतम अयोग्यता है:","options":["60 days","90 days","120 days","1 year"],"explanation":"3 years के भीतर दूसरा रेलमार्ग-क्रॉसिंग उल्लंघन 120 days से कम नहीं की अयोग्यता का परिणाम देता है। स्रोत: Kansas CDL Manual, Section 1; 49 CFR 383.51(d)।"},"53":{"q":"एक कैनसस CDL धारक 3-year की अवधि के भीतर तीसरा रेलमार्ग-राजमार्ग ग्रेड क्रॉसिंग उल्लंघन करता है। न्यूनतम अयोग्यता है:","options":["120 days","180 days","1 year से कम नहीं","2 years"],"explanation":"3 years के भीतर तीसरा रेलमार्ग-क्रॉसिंग उल्लंघन 1 year से कम नहीं की अयोग्यता का परिणाम देता है। स्रोत: Kansas CDL Manual, Section 1; 49 CFR 383.51(d)।"},"54":{"q":"एक कैनसस CDL चालक के किसी आउट-ऑफ-सर्विस आदेश के पहले उल्लंघन (गैर-HazMat, गैर-यात्री) के लिए न्यूनतम अयोग्यता क्या है?","options":["60 days से कम नहीं","90 days से कम नहीं","180 days से कम नहीं","1 year से कम नहीं"],"explanation":"एक पहला आउट-ऑफ-सर्विस आदेश उल्लंघन कैनसस में 180 days से कम नहीं (और 1 year से अधिक नहीं) की अयोग्यता का परिणाम देता है। स्रोत: Kansas CDL Manual, Section 1; 49 CFR 383.51(e)।"},"55":{"q":"एक कैनसस CDL चालक (गैर-HazMat, गैर-यात्री) के लिए 10 years के भीतर दूसरे आउट-ऑफ-सर्विस आदेश उल्लंघन के लिए अयोग्यता की सीमा क्या है?","options":["180 days से 1 year","1 से 3 years","2 से 5 years","3 से 5 years"],"explanation":"10 years के भीतर दूसरा आउट-ऑफ-सर्विस आदेश उल्लंघन 2 years से कम नहीं और 5 years से अधिक नहीं की अयोग्यता का परिणाम देता है। स्रोत: Kansas CDL Manual, Section 1; 49 CFR 383.51(e)।"},"56":{"q":"एक कैनसस CDL चालक प्लेकार्ड वाली खतरनाक सामग्री का परिवहन करते समय या यात्रियों को ले जाते समय पहला आउट-ऑफ-सर्विस आदेश उल्लंघन करता है। अयोग्यता है:","options":["60 days से कम नहीं","180 days से कम नहीं, 2 years तक","90 days से कम नहीं, 1 year तक","आजीवन"],"explanation":"प्लेकार्ड वाली HazMat ले जाते समय या यात्रियों को ले जाते समय पहला आउट-ऑफ-सर्विस आदेश उल्लंघन 180 days से कम नहीं और 2 years से अधिक नहीं की अयोग्यता का परिणाम देता है (सामान्य लोड के लिए 1 year तक की तुलना में)। स्रोत: Kansas CDL Manual; 49 CFR 383.51(e)।"},"57":{"q":"कैनसस में, एक CMV चालक जो ड्यूटी पर रहते हुए अपने सिस्टम में किसी भी पता लगाने योग्य मात्रा में अल्कोहल (0.04% से कम भी) के साथ पाया जाता है, वह किसके अधीन होता है?","options":["तत्काल आजीवन अयोग्यता","24 घंटे के लिए आउट ऑफ सर्विस रखा जाना","एक 1-year की अयोग्यता","एक 60-day की अयोग्यता"],"explanation":"किसी भी मापने योग्य या पता लगाने योग्य अल्कोहल (0.04% से नीचे) वाले CMV चालक को 24 घंटे के लिए आउट ऑफ सर्विस रखा जाता है; 0.04% या उससे अधिक का BAC एक प्रमुख अपराध बन जाता है (1-year की अयोग्यता)। स्रोत: Kansas CDL Manual, Section 1; 49 CFR 392.5।"},"58":{"q":"अयोग्यता के अलावा, एक कैनसस/संघीय नागरिक जुर्माना किसी ऐसी ट्रकिंग कंपनी पर कौन-सा अतिरिक्त दंड लगा सकता है जो जानबूझकर किसी चालक को आउट-ऑफ-सर्विस आदेश के दौरान संचालन करने की अनुमति देती है?","options":["$2,750 से $11,000 का जुर्माना","एक समान $500 का जुर्माना","60 days के लिए कंपनी के संचालन प्राधिकार की हानि","कंपनी पर कोई दंड लागू नहीं होता"],"explanation":"एक नियोक्ता जो जानबूझकर किसी चालक को आउट-ऑफ-सर्विस आदेश का उल्लंघन करने की अनुमति देता है या आवश्यक करता है, वह चालक की अयोग्यता और जुर्माने के अतिरिक्त $2,750 से $11,000 के नागरिक जुर्माने के अधीन होता है। स्रोत: Kansas CDL Manual; 49 CFR 383.53(b)।"},"59":{"q":"एक कैनसस CDL धारक को एक प्रमुख अपराध के लिए दोषी ठहराया जाता है और बाद में, वर्षों बाद, दूसरे प्रमुख अपराध के लिए दोषी ठहराया जाता है। एक आजीवन अयोग्यता के बाद, पुनर्बहाली केवल तभी संभव हो सकती है:","options":["1 year के बाद","5 years के बाद","न्यूनतम 10 years के बाद, यदि शर्तें पूरी होती हैं","यह कभी संभव नहीं है"],"explanation":"दो प्रमुख अपराधों के लिए एक आजीवन अयोग्यता को, FMCSA द्वारा अपनाए गए नियमों के तहत, न्यूनतम 10 years तक घटाया जा सकता है यदि चालक निर्धारित शर्तें पूरी करता है; कुछ आजीवन प्रतिबंध (उदाहरण के लिए, दवाओं के निर्माण/वितरण के लिए CMV का उपयोग करना) स्थायी होते हैं। स्रोत: Kansas CDL Manual; 49 CFR 383.51(b)।"},"60":{"q":"कैनसस में, जब यात्रियों को ले जा रही स्कूल बस किसी रेलरोड ग्रेड क्रॉसिंग के पास पहुँचती है, तो चालक को निकटतम रेल से कितनी दूरी पर रुकना चाहिए?","options":["निकटतम रेल से 50 feet के भीतर परंतु 15 feet से कम नहीं","निकटतम रेल से 25 feet के भीतर परंतु 5 feet से कम नहीं","निकटतम रेल से 75 feet के भीतर परंतु 25 feet से कम नहीं","निकटतम रेल से 100 feet के भीतर परंतु 50 feet से कम नहीं"],"explanation":"कैनसस के अनुसार कुछ वाहनों को निकटतम रेल से 50 feet के भीतर परंतु 15 feet से कम नहीं की दूरी पर रुकना आवश्यक है तथा क्रॉस करने से पहले देखना और सुनना आवश्यक है। स्रोत: K.S.A. 8-1551; Kansas CDL Manual (KDOR)।"},"61":{"q":"कैनसस कानून के तहत, खतरनाक-सामग्री (hazardous-materials) प्लैकार्ड प्रदर्शित करने वाले व्यावसायिक वाहन को, जिसे रेलरोड क्रॉसिंग पर रुकना आवश्यक है, निकटतम रेल से कितनी दूरी के भीतर पूर्ण रूप से रुकना चाहिए?","options":["10 feet से अधिक निकट नहीं और 30 feet से अधिक दूर नहीं","15 feet से अधिक निकट नहीं और 50 feet से अधिक दूर नहीं","20 feet से अधिक निकट नहीं और 60 feet से अधिक दूर नहीं","5 feet से अधिक निकट नहीं और 25 feet से अधिक दूर नहीं"],"explanation":"प्लैकार्ड लगे HazMat वाहनों को निकटतम रेल से 50 feet के भीतर परंतु 15 feet से कम नहीं की दूरी पर रुकना चाहिए और केवल तभी आगे बढ़ना चाहिए जब सुरक्षित हो। स्रोत: K.S.A. 8-1551; Kansas CDL Manual (KDOR)।"},"62":{"q":"कैनसस का 'Move Over' कानून 1 जुलाई, 2025 से प्रभावी रूप से विस्तारित किया गया। वर्तमान कानून किसी रुके हुए वाहन के पास पहुँचने वाले चालक से क्या करने की अपेक्षा करता है?","options":["केवल पुलिस, अग्निशमन और एम्बुलेंस वाहनों के लिए लेन बदलें (move over)","केवल आपातकालीन वाहनों और टो ट्रकों के लिए लेन बदलें (move over)","चमकती या हज़ार्ड लाइट प्रदर्शित करने वाले किसी भी स्थिर वाहन के लिए लेन बदलें (move over), न कि केवल आपातकालीन वाहनों के लिए","केवल तभी लेन बदलें (move over) जब कोई अधिकारी वाहन के बाहर खड़ा हो"],"explanation":"Senate Bill 8 (1 जुलाई, 2025 से प्रभावी) ने K.S.A. 8-1530 का विस्तार किया, ताकि चालकों को चमकती/हज़ार्ड लाइट प्रदर्शित करने वाले किसी भी स्थिर वाहन के लिए लेन बदलनी (move over) या गति धीमी करनी पड़े। स्रोत: K.S.A. 8-1530; Kansas SB 8 (2025)।"},"63":{"q":"कैनसस के ऐसे राजमार्ग पर जहाँ चालक की दिशा में दो या अधिक लेन हों, Move Over कानून सक्रिय चेतावनी लाइट वाले स्थिर वाहन के पास से गुजरते समय क्या अपेक्षा करता है?","options":["हमेशा पूरी तरह रुकें जब तक वाहन हट न जाए","गुजरते समय लगातार हॉर्न बजाएँ","सामान्य गति बनाए रखें परंतु हज़ार्ड लाइट चालू करें","यदि सुरक्षित रूप से किया जा सके तो रुके हुए वाहन से सटी हुई लेन के अलावा किसी अन्य लेन में बदल जाएँ"],"explanation":"K.S.A. 8-1530(b) के अनुसार बहु-लेन सड़कों पर चालकों को, यदि सुरक्षित हो, तो गैर-सटी हुई (non-adjacent) लेन में बदलना आवश्यक है; यदि संभव न हो, तो गति धीमी करें और उचित सावधानी के साथ आगे बढ़ें। स्रोत: K.S.A. 8-1530; Kansas CDL Manual (KDOR)।"},"64":{"q":"कैनसस के Move Over कानून के तहत, यदि चेतावनी-लाइट वाले रुके हुए वाहन से दूर लेन बदलना असुरक्षित या असंभव हो, तो चालक को क्या करना चाहिए?","options":["यात्रा लेन में रुक जाएँ और प्रतीक्षा करें","गति कम करें और सड़क, मौसम तथा यातायात की स्थितियों के अनुरूप सुरक्षित गति बनाए रखें","निर्धारित (posted) गति सीमा पर चलते रहें","शोल्डर पर गाड़ी ले जाएँ और रुक जाएँ"],"explanation":"जब लेन बदलना संभव न हो या असुरक्षित हो, तो K.S.A. 8-1530(b) के अनुसार चालक को उचित सावधानी के साथ आगे बढ़ना, गति कम करना और सुरक्षित गति बनाए रखना आवश्यक है। स्रोत: K.S.A. 8-1530।"},"65":{"q":"Secretary of Transportation द्वारा निर्धारित, कैनसस में किसी विभाजित बहु-लेन (interstate) राजमार्ग पर अधिकतम निर्धारित (posted) गति सीमा क्या है?","options":["70 mph","65 mph","75 mph","80 mph"],"explanation":"कैनसस विभाजित बहु-लेन राजमार्गों पर अधिकतम सीमा 75 mph निर्धारित करता है, जैसा कि Secretary of Transportation द्वारा निर्दिष्ट और पोस्ट किया गया है। स्रोत: K.S.A. 8-1558।"},"66":{"q":"क्या कैनसस अपने interstate मार्गों पर ट्रकों/CMV के लिए कारों की तुलना में अलग, कम राज्यव्यापी अधिकतम गति सीमा निर्धारित करता है?","options":["हाँ - ट्रक राज्यव्यापी रूप से 65 mph तक सीमित हैं जबकि कारें 75 mph तक जा सकती हैं","हाँ - ट्रक सभी interstate मार्गों पर 60 mph तक सीमित हैं","हाँ - ट्रक राज्यव्यापी रूप से रात में 55 mph तक सीमित हैं","नहीं - कैनसस में ट्रकों और कारों पर वही अधिकतम निर्धारित (posted) सीमा लागू होती है"],"explanation":"कैनसस ट्रकों के लिए कोई अलग राज्यव्यापी गति सीमा नहीं लगाता; वही निर्धारित (posted) अधिकतम सीमा सभी वाहनों पर लागू होती है जब तक कि संकेत अन्यथा न कहें। स्रोत: K.S.A. 8-1558; KDOT।"},"67":{"q":"K.S.A. 8-1558 के तहत, कैनसस के किसी काउंटी या टाउनशिप राजमार्ग पर अधिकतम वैध गति सीमा क्या है?","options":["55 mph","45 mph","65 mph","60 mph"],"explanation":"कैनसस काउंटी या टाउनशिप राजमार्गों पर अधिकतम सीमा 55 mph, अन्य (गैर-बहु-लेन) राजमार्गों पर 65 mph, और शहरी जिलों में 30 mph निर्धारित करता है। स्रोत: K.S.A. 8-1558।"},"68":{"q":"K.S.A. 8-1558 के तहत, कैनसस में किसी शहरी जिले (urban district) में अधिकतम वैध गति सीमा क्या है, जब तक कि अन्यथा पोस्ट न किया गया हो?","options":["25 mph","35 mph","30 mph","20 mph"],"explanation":"किसी शहरी जिले में वैधानिक अधिकतम सीमा 30 mph है, जब तक कि कोई भिन्न सीमा पोस्ट न की गई हो। स्रोत: K.S.A. 8-1558।"},"69":{"q":"कैनसस की किसी दो-लेन (अविभाजित) सड़क पर, चमकती लाल लाइट वाली रुकी हुई स्कूल बस से मिलने वाले चालक को क्या करना चाहिए?","options":["20 mph तक गति धीमी करें और सावधानी से गुजरें","दूर वाली लेन में जाएँ और बस के आगे बढ़ते रहें","केवल तभी रुकें जब बच्चे स्पष्ट रूप से सड़क पार कर रहे हों","बस तक पहुँचने से पहले रुकें और तब तक आगे न बढ़ें जब तक लाल लाइट चमकना बंद न कर दे या बस न चले"],"explanation":"चमकती लाल लाइट वाली स्कूल बस से मिलने वाले या उसे ओवरटेक करने वाले चालकों को उस तक पहुँचने से पहले रुकना चाहिए और तब तक रुके रहना चाहिए जब तक लाइट बंद न हो जाए या बस न चले। स्रोत: K.S.A. 8-1556।"},"70":{"q":"अलग-अलग मार्गमार्गों (roadways) वाले कैनसस के किसी विभाजित राजमार्ग पर, बच्चों को चढ़ाने/उतारने वाली स्कूल बस के लिए रुकने का अपवाद क्या है?","options":["बस से भिन्न मार्गमार्ग (roadway) पर चल रहे चालक को रुकने की आवश्यकता नहीं है","बस के सबसे निकट वाली लेन में चल रहे चालक को रुकने की आवश्यकता नहीं है","कोई अपवाद लागू नहीं होता; सभी चालकों को हमेशा रुकना चाहिए","यदि बस 100 feet से अधिक दूर हो तो चालक आगे बढ़ सकता है"],"explanation":"K.S.A. 8-1556 के अनुसार अलग-अलग मार्गमार्गों वाले राजमार्ग पर चल रहे चालक को किसी भिन्न मार्गमार्ग (roadway) पर स्थित स्कूल बस के लिए रुकने की आवश्यकता नहीं है (या ऐसे नियंत्रित-पहुँच लोडिंग ज़ोन में जहाँ पैदल यात्री सड़क पार नहीं कर सकते)। स्रोत: K.S.A. 8-1556।"},"71":{"q":"कैनसस के स्कूल-बस अलग-मार्गमार्ग अपवाद के तहत, किस परिदृश्य में अब भी यातायात की हर दिशा को रुकना आवश्यक है?","options":["एक विभाजित राजमार्ग जहाँ बस मध्यवर्ती पट्टी (median) के पार विपरीत मार्गमार्ग पर हो","एक अविभाजित दो-लेन सड़क जहाँ दिशाओं के बीच कोई भौतिक पृथक्करण न हो","एक नियंत्रित-पहुँच राजमार्ग जहाँ बस लोडिंग ज़ोन में हो और पैदल यात्री सड़क पार न कर सकें","एक अवरोधक (barrier) द्वारा भौतिक रूप से अलग किए गए दो मार्गमार्ग"],"explanation":"यह अपवाद केवल वहीं लागू होता है जहाँ अलग-अलग मार्गमार्ग (SEPARATE roadways) हों। बिना किसी पृथक्करण वाली अविभाजित सड़क पर, दोनों दिशाओं का यातायात रुकना चाहिए। स्रोत: K.S.A. 8-1556।"},"72":{"q":"कैनसस में, चमकती लाल लाइट वाली रुकी हुई स्कूल बस को गैर-कानूनी रूप से पास करने के लिए मूल जुर्माना निम्न में से कौन-सा है?","options":["$75, बिना किसी वृद्धि के","$150, केवल स्कूल ज़ोन में दोगुना","हर अपराध के लिए सपाट $500","$315, बार-बार किए जाने वाले अपराधों के लिए बढ़ते जुर्माने के साथ"],"explanation":"कैनसस की एकसमान जुर्माना अनुसूची स्कूल बस को गैर-कानूनी रूप से पास करने के लिए $315 मूल जुर्माना निर्धारित करती है, जिसमें बाद के उल्लंघनों के लिए बढ़ते जुर्माने होते हैं। स्रोत: K.S.A. 8-2118।"},"73":{"q":"जब कोई कैनसस CDL चालक किसी विभाजित राजमार्ग के शोल्डर पर व्यावसायिक वाहन रोकता है, तो सबसे पीछे वाला परावर्ती (reflective) चेतावनी त्रिकोण कहाँ रखा जाना चाहिए?","options":["वाहन के पीछे लगभग 200 feet, आने वाले यातायात की ओर","वाहन के पीछे लगभग 50 feet","वाहन के पीछे लगभग 500 feet","वाहन के पीछे लगभग 150 feet"],"explanation":"किसी विभाजित/एकमार्गी (one-way) राजमार्ग पर, त्रिकोण आने वाले यातायात की ओर 10 feet, 100 feet और 200 feet पर रखे जाते हैं। स्रोत: Kansas CDL Manual (KDOR); 49 CFR 392.22।"},"74":{"q":"एक कैनसस CDL चालक किसी एकमार्गी (one-way) या विभाजित राजमार्ग पर रुकता है। आने वाले यातायात की ओर तीनों परावर्ती त्रिकोणों का सही स्थान क्या है?","options":["पीछे की ओर 10 feet, 50 feet और 150 feet","पीछे की ओर 10 feet, 100 feet और 200 feet","पीछे की ओर 25 feet, 100 feet और 250 feet","पीछे की ओर 5 feet, 75 feet और 175 feet"],"explanation":"विभाजित/एकमार्गी सड़कों पर, त्रिकोणों को आने वाले यातायात की ओर 10, 100 और 200 feet पर रखें। स्रोत: Kansas CDL Manual (KDOR); 49 CFR 392.22।"},"75":{"q":"किसी कैनसस दो-लेन, दो-तरफा सड़क पर CMV रोकने के बाद, चालक को कितनी जल्दी आवश्यक आपातकालीन चेतावनी उपकरण लगाने चाहिए?","options":["रुकने के 30 minutes के भीतर","रुकने के 1 hour के भीतर","रुकने के 10 minutes के भीतर","केवल यदि 2 hours से अधिक समय तक रुके रहें"],"explanation":"राजमार्ग या शोल्डर पर रुकने के 10 minutes के भीतर आपातकालीन चेतावनी उपकरण रखे जाने चाहिए। स्रोत: Kansas CDL Manual (KDOR); 49 CFR 392.22।"},"76":{"q":"किसी कैनसस दो-लेन, दो-तरफा सड़क पर, रुकने के बाद CMV चालक को तीन चेतावनी त्रिकोण कहाँ रखने चाहिए?","options":["एक वाहन के पीछे 10 feet के भीतर, एक लगभग 100 feet पीछे, और एक वाहन के लगभग 100 feet आगे","तीनों वाहन के पीछे 10 feet के भीतर","एक 200 feet पीछे और दो वाहन के आगे","एक 50 feet पीछे और दो वाहन के किनारों पर"],"explanation":"दो-तरफा सड़क पर, एक त्रिकोण पीछे 10 feet पर, एक लगभग 100 feet पीछे, और एक लगभग 100 feet आगे रखें। स्रोत: Kansas CDL Manual (KDOR); 49 CFR 392.22।"},"77":{"q":"जब कोई कैनसस CDL बस चालक किसी क्रॉसिंग पर रेलरोड पटरियों को पार करता है, तो बस का कोई भी हिस्सा पटरियों पर होने के दौरान चालक को क्या नहीं करना चाहिए?","options":["बस को निचले गियर में रखें","प्रवेश से पहले देखें और सुनें","पटरियों को पार करते समय गियर बदलें (शिफ्ट करें)","दरवाज़ा बंद रखें"],"explanation":"चालकों को रेलरोड पटरियों को ऐसे गियर में पार करना चाहिए जिसमें शिफ्टिंग की आवश्यकता न पड़े, और वाहन का कोई भी हिस्सा पटरियों पर होने के दौरान गियर नहीं बदलना चाहिए। स्रोत: Kansas CDL Manual (KDOR)।"},"78":{"q":"कौन-सा रूटिंग तथ्य कैनसस में व्यावसायिक संचालन के लिए वास्तव में विशिष्ट है?","options":["कैनसस के सभी interstate मार्ग टोल-मुक्त हैं और उनमें कोई व्यावसायिक मार्ग नहीं है","I-35, I-335, I-470 और I-70 का अधिकांश भाग टोल Kansas Turnpike बनाता है, जहाँ जुड़वाँ 53-foot ट्रेलरों की अनुमति है","कैनसस हर interstate से 40 feet से अधिक लंबे सभी ट्रकों पर प्रतिबंध लगाता है","कैनसस सभी ट्रकों को केवल US (गैर-interstate) राजमार्गों का उपयोग करने के लिए आवश्यक करता है"],"explanation":"Kansas Turnpike (KTA), जो I-35/I-335/I-470/I-70 के साथ लगभग 236 miles लंबा है, एक टोल रोड है जो जुड़वाँ 53-foot ट्रेलरों की अनुमति देती है। स्रोत: KDOT; Kansas Turnpike Authority।"},"79":{"q":"कौन-सी कैनसस एजेंसी ओवरसाइज़/ओवरवेट परमिट जारी करती है और K-TRIPS प्रणाली के माध्यम से ट्रक रूटिंग को मंजूरी देती है?","options":["Kansas Department of Revenue (KDOR)","Kansas Highway Patrol लाइसेंसिंग प्रभाग","The Federal Motor Carrier Safety Administration","Kansas Department of Transportation (KDOT)"],"explanation":"KDOT, Kansas Truck Routing and Intelligent Permitting System (K-TRIPS) के माध्यम से ओवरसाइज़/ओवरवेट परमिट और रूटिंग का प्रबंधन करता है। स्रोत: KDOT Commercial Vehicle Information।"},"80":{"q":"कौन-सी कैनसस राज्य एजेंसी Commercial Driver's Licenses (CDLs) जारी करती है?","options":["The Federal Motor Carrier Safety Administration","The Kansas Department of Transportation (KDOT)","The Kansas Department of Revenue, Division of Vehicles","The Kansas Highway Patrol"],"explanation":"कैनसस में CDL, Kansas Department of Revenue (KDOR), Division of Vehicles द्वारा जारी किया जाता है, जो Kansas CDL manual भी प्रकाशित करता है। KDOT सड़कों और परमिट का काम संभालता है परंतु चालक लाइसेंसिंग का नहीं। स्रोत: Kansas DOR Division of Vehicles CDL page (ksrevenue.gov/dovcdl.html)।"},"81":{"q":"इससे पहले कि कोई कैनसस आवेदक CDL skills test दे सके, ज्ञान (knowledge) और कौशल (skills) दोनों परीक्षाएँ पास करनी होती हैं। Kansas CDL manual के अनुसार CDL या CLP प्राप्त करने के लिए आपको किन दो सामान्य प्रकार की परीक्षाओं को पास करना आवश्यक है?","options":["केवल एक लिखित परीक्षा और एक दृष्टि (vision) परीक्षा","केवल एक चिकित्सा जाँच और एक पृष्ठभूमि जाँच","एक रोड साइन परीक्षा और एक रक्षात्मक-ड्राइविंग पाठ्यक्रम","ज्ञान परीक्षाएँ (knowledge tests) और कौशल परीक्षाएँ (skills tests)"],"explanation":"Kansas CDL manual कहता है: 'CDL या CLP प्राप्त करने के लिए, आपको ज्ञान और कौशल परीक्षाएँ पास करनी होंगी।' दृष्टि और चिकित्सा प्रमाणन अलग आवश्यकताएँ हैं। स्रोत: Kansas CDL Manual, Section 1.1, 'Commercial Driver License Tests'।"},"82":{"q":"Kansas CDL skills test में तीन खंड होते हैं जिन्हें एक निर्धारित क्रम में लिया जाना चाहिए। कौन-सा क्रम सही है?","options":["ऑन-रोड ड्राइविंग, फिर वाहन निरीक्षण, फिर बेसिक वाहन नियंत्रण","वाहन निरीक्षण, फिर बेसिक वाहन नियंत्रण, फिर ऑन-रोड ड्राइविंग","वाहन निरीक्षण, फिर ऑन-रोड ड्राइविंग, फिर बेसिक वाहन नियंत्रण","बेसिक वाहन नियंत्रण, फिर ऑन-रोड ड्राइविंग, फिर वाहन निरीक्षण"],"explanation":"Kansas CDL manual कहता है कि skills test के तीन खंड होते हैं—वाहन निरीक्षण, बेसिक वाहन नियंत्रण, और ऑन-रोड ड्राइविंग—और आपको उन्हें उसी क्रम में लेना होगा तथा अगले पर जाने से पहले प्रत्येक को पास करना होगा। स्रोत: Kansas CDL Manual, Section 1.1.2, 'Skills Tests'।"},"83":{"q":"जिस प्रकार के वाणिज्य (commerce) में वे संचालन करते हैं, उसे घोषित करते समय किसी कैनसस CDL आवेदक को कितनी स्व-प्रमाणन (self-certification) श्रेणियों में से चुनना आवश्यक है?","options":["पाँच","तीन","चार","दो"],"explanation":"कैनसस CDL आवेदकों/धारकों को वाणिज्य की चार श्रेणियों में से किसी एक के लिए स्व-प्रमाणन करना आवश्यक है। स्रोत: Kansas CDL Manual, Section 1.2 ('the four types of commerce you must self-certify') और Kansas DOR Medical Certification Information page।"},"84":{"q":"निम्नलिखित में से कौन-सी एक चार कैनसस CDL स्व-प्रमाणन (self-certification) श्रेणियों में से है?","options":["Provisional Intrastate","Non-excepted Interstate","Restricted Interstate","Exempt Federal"],"explanation":"चार कैनसस स्व-प्रमाणन श्रेणियाँ हैं: Non-excepted Interstate, Excepted Interstate, Non-excepted Intrastate, और Excepted Intrastate। 'Restricted,' 'Provisional,' और 'Exempt Federal' श्रेणियाँ नहीं हैं। स्रोत: Kansas DOR Medical Certification Information page; Kansas CDL Manual Section 1.2।"},"85":{"q":"एक कैनसस चालक जो 'Non-excepted Interstate' के रूप में स्व-प्रमाणन करता है, उसे 'certified' चिकित्सा स्थिति बनाए रखने के लिए क्या करना चाहिए?","options":["हर समय कैब में अपने फिजिकल की एक पेपर प्रति रखें","प्रतिवर्ष एक अतिरिक्त एयर ब्रेक ज्ञान परीक्षा पास करें","एक वर्तमान medical examiner's certificate (DOT medical card) बनाए रखें","अपना CDL हर चार वर्ष के बजाय हर वर्ष नवीनीकृत करें"],"explanation":"Non-excepted interstate चालकों को एक संघीय medical examiner's certificate (49 CFR 391.45) प्रदान करना और चालू रखना आवश्यक है, अन्यथा वे 'not-certified' हो जाते हैं और CDL खो सकते हैं। स्रोत: Kansas CDL Manual, Section 1.2, Medical Documentation Requirements।"},"86":{"q":"2 जून, 2025 से प्रभावी, किसी कैनसस CDL धारक के medical examiner's certificate (MEC) को Division of Vehicles तक कैसे पहुँचना चाहिए?","options":["चालक द्वारा Topeka में KDOR P.O. Box को डाक से भेजा जाए","चालक के नियोक्ता द्वारा KDOR को फैक्स किया जाए","चालक द्वारा किसी भी license exam station पर स्वयं पहुँचाया जाए","National Registry of Certified Medical Examiners से इलेक्ट्रॉनिक रूप से"],"explanation":"6/2/2025 से प्रभावी, कैनसस अब चालक द्वारा प्रस्तुत MEC स्वीकार नहीं करता और न ही उन्हें मैन्युअल रूप से दर्ज कर सकता है; प्रमाणित डेटा National Registry of Certified Medical Examiners से इलेक्ट्रॉनिक रूप से आना चाहिए (परीक्षक उसे दर्ज करता है)। स्रोत: Kansas DOR Medical Certification Information page (ksrevenue.gov/dovmedcertfaq.html)।"},"87":{"q":"जून 2025 की कैनसस प्रक्रिया के तहत, किसी प्रमाणित चिकित्सा परीक्षक (certified medical examiner) के पास एक नया MEC National Registry में दर्ज करने के लिए कितना समय होता है?","options":["तुरंत, चालक के कार्यालय छोड़ने से पहले","अगले कैलेंडर दिन की मध्यरात्रि तक","परीक्षा के 10 business days के भीतर","परीक्षा के 30 days के भीतर"],"explanation":"कैनसस का कहना है कि चिकित्सा परीक्षक के पास MEC को National Registry में दर्ज करने के लिए अगले दिन की मध्यरात्रि तक का समय होता है, जिससे कैनसस इसे इलेक्ट्रॉनिक रूप से प्राप्त करता है। स्रोत: Kansas DOR Medical Certification Information page।"},"88":{"q":"कैनसस में पहली बार CDL आवेदन करने वालों के लिए, संघीय Entry-Level Driver Training (ELDT) आवश्यकता कब पूरी की जानी चाहिए?","options":["CDL जारी होने के 30 days के भीतर","केवल पहली चलती (moving) उल्लंघन के बाद","CDL skills test देने से पहले","पहली बार CDL नवीनीकृत करने से पहले"],"explanation":"ELDT (7 फरवरी, 2022 से प्रभावी) के लिए FMCSA-पंजीकृत प्रदाता से सैद्धांतिक (theory) और बिहाइंड-द-व्हील प्रशिक्षण आवश्यक है, जो आवेदक के CDL skills test देने से पहले पूरा किया जाना चाहिए। यह संघीय मानक कैनसस में लागू होता है। स्रोत: FMCSA ELDT rule (49 CFR Part 380, Subpart F); FMCSA Training Provider Registry।"},"89":{"q":"किसी प्रवेश-स्तरीय (entry-level) कैनसस CDL आवेदक को आवश्यक ELDT प्रशिक्षण ऐसे प्रदाता से प्राप्त करना चाहिए जो कहाँ सूचीबद्ध हो?","options":["Kansas DOR approved-schools list पर","Kansas Highway Patrol carrier roster पर","National Registry of Certified Medical Examiners पर","FMCSA Training Provider Registry (TPR) पर"],"explanation":"ELDT ऐसे स्कूल द्वारा प्रदान किया जाना चाहिए जो FMCSA Training Provider Registry (TPR) पर सूचीबद्ध हो; राज्य द्वारा skills testing की अनुमति देने से पहले इसकी पूर्णता FMCSA को इलेक्ट्रॉनिक रूप से रिपोर्ट की जाती है। स्रोत: FMCSA Entry-Level Driver Training, Training Provider Registry।"},"90":{"q":"पहली बार निम्नलिखित में से कौन-सा एंडोर्समेंट प्राप्त करने पर परीक्षण से पहले ELDT प्रशिक्षण आवश्यकता शुरू हो जाती है?","options":["केवल एयर ब्रेक क्लीयरेंस","Passenger (P), School Bus (S), या Hazardous Materials (H)","केवल Doubles/Triples (T)","केवल Tank (N)"],"explanation":"ELDT पहली बार CDL आवेदन करने वालों, Class B-से-A अपग्रेड, और पहली बार P, S, या H एंडोर्समेंट पर लागू होता है। Doubles/Triples और Tank एंडोर्समेंट स्वयं में ELDT को शुरू नहीं करते। स्रोत: FMCSA ELDT applicability (49 CFR Part 380, Subpart F)।"},"91":{"q":"कैनसस में किसी मौजूदा Class B CDL को Class A CDL में अपग्रेड करने के लिए संघीय ELDT नियम के तहत किस अतिरिक्त चरण की आवश्यकता होती है?","options":["कुछ अतिरिक्त नहीं; अपग्रेड स्वचालित है","पहले कम से कम पाँच वर्ष तक Class B CDL रखना","केवल सामान्य ज्ञान परीक्षा (general knowledge test) फिर से देना","skills test से पहले Class A अपग्रेड ELDT पूरा करना"],"explanation":"Class B-से-Class A अपग्रेड ELDT द्वारा कवर किए गए संचालनों में से एक है, इसलिए चालक को Class A skills test देने से पहले किसी TPR-सूचीबद्ध प्रदाता से अपग्रेड प्रशिक्षण कार्यक्रम पूरा करना होगा। स्रोत: FMCSA ELDT rule (49 CFR Part 380, Subpart F)।"},"92":{"q":"किसी कैनसस आवेदक को CLP जारी होने के बाद, CDL skills test देने के योग्य होने से पहले उन्हें कितने समय तक प्रतीक्षा करनी चाहिए?","options":["कम से कम 30 days","कम से कम 60 days","कम से कम 14 days","कम से कम 7 days"],"explanation":"एक CLP धारक को CDL skills test देने से पहले कम से कम 14 days तक परमिट रखना आवश्यक है। यह संघीय आवश्यकता कैनसस में लागू की जाती है। स्रोत: 49 CFR 383.25; Kansas CDL applicant guidance।"},"93":{"q":"एक मानक कैनसस CDL को कितनी बार नवीनीकृत किया जाना चाहिए?","options":["हर 6 years","हर 8 years","हर 2 years","हर 4 years"],"explanation":"कैनसस CDL एक 4-year चक्र पर जारी किए जाते हैं और हर चार वर्ष में नवीनीकृत किए जाने चाहिए, भले ही कुछ गैर-व्यावसायिक कैनसस लाइसेंसों के लिए 6-year चक्र का उपयोग किया जाता हो। स्रोत: Kansas DOR Division of Vehicles licensing information।"},"94":{"q":"इंट्रास्टेट (केवल कैनसस के भीतर) संचालन के लिए कैनसस CDL प्राप्त करने की न्यूनतम आयु क्या है?","options":["18 वर्ष","19 वर्ष","21 वर्ष","16 वर्ष"],"explanation":"इंट्रास्टेट संचालन के लिए कैनसस CDL 18 वर्ष की आयु में जारी किया जा सकता है; इंटरस्टेट संचालन (और hazmat) के लिए 21 वर्ष की आयु आवश्यक है। स्रोत: Kansas CDL Manual; FMCSA driver-qualification rules (49 CFR 391.11)।"},"95":{"q":"कैनसस CDL के साथ इंटरस्टेट वाणिज्य में commercial motor vehicle संचालित करने की न्यूनतम आयु क्या है?","options":["25 वर्ष","21 वर्ष","18 वर्ष","23 वर्ष"],"explanation":"इंटरस्टेट CMV संचालन, और खतरनाक सामग्री ढोने के लिए, चालक का कम से कम 21 वर्ष का होना आवश्यक है। 18-20 वर्ष के चालक इंट्रास्टेट संचालन तक सीमित हैं। स्रोत: FMCSA driver-qualification rules (49 CFR 391.11); Kansas CDL guidance।"},"96":{"q":"दस्तावेज़ों का कौन-सा समूह सबसे अच्छी तरह दर्शाता है कि किसी कैनसस आवेदक को CLP/CDL के लिए आवेदन करने हेतु क्या प्रदान करना चाहिए?","options":["केवल एक पासपोर्ट, बिना निवास के किसी प्रमाण की आवश्यकता के","पहचान/जन्म तिथि का प्रमाण, Social Security number, वैध उपस्थिति (lawful presence), और कैनसस निवास के दो प्रमाण","एक हाई-स्कूल डिप्लोमा और एक नियोक्ता संदर्भ पत्र","केवल एक वर्तमान कैनसस गैर-व्यावसायिक लाइसेंस और एक फोटो"],"explanation":"कैनसस को पहचान/जन्म तिथि का प्रमाण, Social Security number का प्रमाण, वैध उपस्थिति (lawful presence) का प्रमाण, और कैनसस निवास (भौतिक पते) को सिद्ध करने वाले दो दस्तावेज़ आवश्यक हैं; आवेदकों के पास पहले से एक कैनसस गैर-व्यावसायिक चालक लाइसेंस भी होना चाहिए। स्रोत: Kansas DOR Division of Vehicles application requirements।"},"97":{"q":"शुल्कों पर एक कैनसस प्रक्रिया प्रश्न: CDL शुल्कों के बारे में कौन-सा कथन आवेदकों को सिखाने के लिए सटीक है?","options":["CDL शुल्क कैनसस क़ानून द्वारा स्थायी रूप से निर्धारित है और कभी नहीं बदलता","कैनसस CDL या उसके एंडोर्समेंट के लिए कोई शुल्क नहीं लेता","CDL शुल्क FMCSA द्वारा संघीय रूप से निर्धारित किए जाते हैं और हर राज्य में समान हैं","CDL और एंडोर्समेंट शुल्क कैनसस द्वारा निर्धारित किए जाते हैं और बदल सकते हैं, इसलिए आवेदकों को वर्तमान राशियों की पुष्टि KDOR से करनी चाहिए"],"explanation":"CDL, एंडोर्समेंट, और CLP शुल्क राज्य द्वारा स्थापित किए जाते हैं और परिवर्तन के अधीन हैं; आवेदकों को किसी निर्धारित आँकड़े पर भरोसा करने के बजाय वर्तमान राशियों की पुष्टि Kansas DOR से करनी चाहिए। शुल्क राज्य-निर्धारित होते हैं, संघीय रूप से एकसमान नहीं। स्रोत: Kansas DOR Division of Vehicles fee schedule guidance।"}},"ar":{"0":{"q":"على الطرق السريعة في كانساس، ما هو الحد الأقصى للعرض الخارجي الإجمالي للمركبة أو حمولتها بدون تصريح؟","options":["8 أقدام (96 إنشًا)","8 1/2 أقدام (102 إنش)","9 أقدام (108 إنشات)","10 أقدام (120 إنشًا)"],"explanation":"تحدد المادة K.S.A. 8-1902 العرض الخارجي الإجمالي لأي مركبة أو حمولتها بـ 8 1/2 أقدام (102 إنش). ويذكر دليل CDL في كانساس ودورية كانساس للطرق السريعة المعيار ذاته للحد الأقصى للعرض."},"1":{"q":"ما هو الحد الأقصى العام لارتفاع المركبة، بما في ذلك حمولتها، على الطرق السريعة في كانساس؟","options":["13 قدمًا و6 إنشات","14 قدمًا","14 قدمًا و6 إنشات","15 قدمًا"],"explanation":"تحدد المادة K.S.A. 8-1904 الحد الأقصى لارتفاع المركبة (بما في ذلك الحمولة) بـ 14 قدمًا. وتؤكد دورية كانساس للطرق السريعة أن 14 قدمًا هو الحد القانوني للارتفاع."},"2":{"q":"تسمح كانساس لنوع واحد من الحمولة بتجاوز حد الارتفاع البالغ 14 قدمًا وتثبيتها حتى 14 1/2 قدمًا. ما هي هذه الحمولة؟","options":["القطن المكبوس","بالات التبن ذات الشكل الأسطواني","عوارض الفولاذ الإنشائية","حاويات الشحن"],"explanation":"تسمح المادة K.S.A. 8-1904 لمركبة تنقل بالات تبن ذات شكل أسطواني بأن تُحمَّل حتى 14 1/2 قدمًا؛ ويكون المشغّل مسؤولاً عن أي ضرر إذا اصطدمت الحمولة بجسر علوي."},"3":{"q":"ما هو الحد الأقصى لطول مركبة آلية واحدة (مثل شاحنة مستقيمة)، بما في ذلك حمولتها، على الطرق السريعة في كانساس؟","options":["40 قدمًا","45 قدمًا","48 قدمًا","53 قدمًا"],"explanation":"تحدد المادة K.S.A. 8-1904 طول مركبة آلية واحدة، بما في ذلك الحمولة، بـ 45 قدمًا كأقصى بُعد إجمالي."},"4":{"q":"في مجموعة مكوّنة من جرار شاحنة ونصف مقطورة، ما هو الحد الأقصى لطول نصف المقطورة المسموح به في كانساس؟","options":["48 قدمًا","53 قدمًا","57 قدمًا","59 1/2 قدمًا"],"explanation":"تنص المادة K.S.A. 8-1904 على أن نصف المقطورة المُشغَّلة في مجموعة مع جرار شاحنة يجب ألا يتجاوز طولها 59 1/2 قدمًا."},"5":{"q":"ما هو الحد الأقصى للوزن الإجمالي المسموح به على أي محور مفرد من محاور المركبة على الطرق السريعة في كانساس بدون تصريح؟","options":["18,000 رطل","20,000 رطل","22,000 رطل","24,000 رطل"],"explanation":"تحدد المادة K.S.A. 8-1908 الوزن الإجمالي على أي محور واحد بـ 20,000 رطل (وعلى أي عجلة واحدة بـ 10,000 رطل)."},"6":{"q":"ما هو الحد الأقصى للوزن الإجمالي المسموح به على مجموعة محاور مترادفة في كانساس بدون تصريح؟","options":["32,000 رطل","34,000 رطل","36,000 رطل","40,000 رطل"],"explanation":"تحدد المادة K.S.A. 8-1908 الوزن الإجمالي على المحاور المترادفة بـ 34,000 رطل، بما يطابق المعيار الفيدرالي."},"7":{"q":"ما هو الحد الأقصى للوزن الإجمالي على أي عجلة مفردة من عجلات المركبة بموجب قانون كانساس؟","options":["8,000 رطل","10,000 رطل","12,000 رطل","17,000 رطل"],"explanation":"تنص المادة K.S.A. 8-1908 على أن الوزن الإجمالي على أي عجلة من عجلات المركبة يجب ألا يتجاوز 10,000 رطل."},"8":{"q":"على شبكة الطرق السريعة بين الولايات في كانساس، ما هو الحد الأقصى للوزن الإجمالي للمركبة المسموح به بدون تصريح؟","options":["73,280 رطلًا","80,000 رطل","85,500 رطلًا","90,000 رطل"],"explanation":"بموجب المادة K.S.A. 8-1909، لا يجوز لجدول الأوزان بحسب تباعد المحاور أن يجيز أكثر من 80,000 رطل كوزن إجمالي على شبكة الطرق بين الولايات، بما يتوافق مع القانون الفيدرالي."},"9":{"q":"على الطرق السريعة لولاية كانساس والطرق الأمريكية التي ليست جزءًا من شبكة الطرق بين الولايات، إلى أي حد أقصى يمكن لجدول تباعد المحاور أن يسمح بوزن إجمالي؟","options":["80,000 رطل","85,500 رطلًا","90,000 رطل","94,000 رطل"],"explanation":"يسمح جدول تباعد المحاور في المادة K.S.A. 8-1909 بوزن إجمالي يصل إلى 85,500 رطل على طرق كانساس والطرق الأمريكية (غير الطرق بين الولايات)، وهو أعلى من سقف 80,000 رطل المعتمد للطرق بين الولايات."},"10":{"q":"تحدد كانساس الحد الأقصى للوزن الإجمالي على مجموعة من محورين متتاليين أو أكثر بشكل أساسي باستخدام أي طريقة؟","options":["سقف وزن ثابت لكل مقطورة","جدول أوزان بحسب تباعد المحاور (معادلة الجسر)","عدد الإطارات فقط","الوزن المسجَّل للشاحنة فقط"],"explanation":"تستخدم المادة K.S.A. 8-1909 جدول أوزان يستند إلى المسافة بين المحاور وعددها، وهو صيغة كانساس من معادلة الجسر الفيدرالية، لتحديد الحد الأقصى للوزن على مجموعة من المحاور المتتالية."},"11":{"q":"بموجب مفهوم الجسر/تباعد المحاور في كانساس، كيف يمكن لمركبة أن تحمل قانونيًا وزنًا إجماليًا أكبر على مجموعة من المحاور؟","options":["بزيادة ضغط الإطارات","بمباعدة المحاور أكثر وإضافة محاور","بتقليل طول المقطورة","بخفض ارتفاع أرضية المقطورة"],"explanation":"يسمح جدول تباعد المحاور في المادة K.S.A. 8-1909 (معادلة الجسر) بوزن إجمالي أكبر كلما زادت المسافة بين المحاور وزاد عددها، وذلك لحماية الجسور."},"12":{"q":"الحمولة التي تتجاوز حدود الحجم أو الوزن القانونية في كانساس ولا يمكن تقليلها (حمولة غير قابلة للتجزئة) تتطلب ماذا قبل أن يُسمح لها بالسير؟","options":["لا شيء، إذا كان السير نهارًا","تصريح حجم/وزن زائد من KDOT","رسالة من جهة الشحن","إعفاء فيدرالي من DOT فقط"],"explanation":"تشترط Kansas DOT الحصول على تصريح حجم/وزن زائد للحمولات غير القابلة للتجزئة التي تتجاوز الحدود القانونية؛ وتُستخرج التصاريح عبر نظام K-TRIPS التابع لـ KDOT."},"13":{"q":"ما هو النظام المعتمد في كانساس للتقدّم بطلب الحصول على تصاريح الحجم/الوزن الزائد؟","options":["IRP Online","K-TRIPS (نظام كانساس لتوجيه الشاحنات والترخيص الذكي)","IFTA Web","CDLIS"],"explanation":"تُصدر KDOT تصاريح الحجم/الوزن الزائد عبر نظام K-TRIPS (نظام كانساس لتوجيه الشاحنات والترخيص الذكي)؛ يقوم مقدّمو الطلبات بالتسجيل وتقديم تفاصيل المركبة والحمولة والمسار عبر الإنترنت."},"14":{"q":"تصريح الحجم/الوزن الزائد القياسي لرحلة واحدة في كانساس يكون عادةً صالحًا لأي مدة؟","options":["24 ساعة","3 أيام","7 أيام","30 يومًا"],"explanation":"تكون تصاريح KDOT للحجم/الوزن الزائد لرحلة واحدة صالحة عادةً لمدة سبعة أيام من تاريخ الإصدار."},"15":{"q":"يقتصر تحريك الحمولة المصرَّح بها ذات الحجم الزائد في كانساس عادةً على أي وقت من اليوم؟","options":["أي وقت، ليلًا أو نهارًا","من نصف ساعة قبل شروق الشمس إلى نصف ساعة بعد غروبها","فقط بين منتصف الليل والساعة 6 صباحًا","فقط في أيام الأسبوع خلال ساعات العمل"],"explanation":"تقصر شروط تصريح KDOT تحريك الحمولات ذات الحجم الزائد عادةً على المدة من نصف ساعة قبل شروق الشمس إلى نصف ساعة بعد غروبها، بما في ذلك عطلات نهاية الأسبوع والعطلات الرسمية، مع استثناءات مذكورة في التصريح."},"16":{"q":"عند أي عرض تصبح المركبة أو الحمولة \"زائدة الحجم\" في كانساس بحيث تتطلب تصريحًا؟","options":["أكثر من 8 أقدام","أكثر من 8 أقدام و6 إنشات","أكثر من 10 أقدام","أكثر من 12 قدمًا"],"explanation":"بما أن المادة K.S.A. 8-1902 تحدد العرض القانوني بـ 8 1/2 أقدام (8 أقدام و6 إنشات)، فإن أي مركبة أو حمولة أعرض من 8 أقدام و6 إنشات تُعدّ زائدة الحجم وتتطلب تصريحًا من KDOT."},"17":{"q":"بموجب تصريح الوزن الزائد الاعتيادي في كانساس (KAR 36-1-37)، ما هو الحد الأقصى للوزن المسموح به على محور مفرد؟","options":["20,000 رطل","22,000 رطل","24,000 رطل","26,000 رطل"],"explanation":"ترفع حدود تصريح الوزن الزائد في كانساس بموجب KAR 36-1-37 الحد الأقصى للمحور المفرد غير الدافع إلى 22,000 رطل (والمحاور المترادفة إلى 45,000 رطل)، أي فوق الحد القانوني البالغ 20,000 رطل."},"18":{"q":"تقدّم كانساس تصريحًا سنويًا خاصًا للوزن الزائد للحمولات القابلة للتجزئة من السلع الزراعية والمستلزمات والوقود الحيوي. ما هو الحد الأقصى للوزن الإجمالي له، وأين لا يُسمح به؟","options":["80,000 رطل؛ ليس على طرق المقاطعات","90,000 رطل؛ ليس على شبكة الطرق بين الولايات","100,000 رطل؛ ليس داخل المدن","85,500 رطلًا؛ ليس على الجسور"],"explanation":"تسمح كانساس بتصريح سنوي للوزن الزائد للحمولات القابلة للتجزئة من المدخلات الزراعية والسلع والماشية والوقود الحيوي حتى 90,000 رطل بستة محاور على الأقل، ولا يجوز لهذه المركبات أن تعمل على شبكة الطرق بين الولايات."},"19":{"q":"في كانساس، يُحظر على المركبة التي تعمل بوزن يتجاوز 85,500 رطل السير في أي ظرف؟","options":["عند هطول المطر","عندما يكون سطح الطريق مغطى بالجليد أو الثلج المتراكم أو الثلج المنجرف","خلال موسم الحصاد","ضمن مسافة 50 ميلًا من المدينة"],"explanation":"تحظر المادة K.S.A. 8-1919 على المركبات التي تعمل بوزن يتجاوز 85,500 رطل السير عندما يكون سطح الطريق مغطى بالجليد أو الثلج المتراكم أو الثلج المنجرف."},"20":{"q":"في كانساس، أي فئة من CDL مطلوبة لتشغيل مركبة مفردة بمعدل وزن إجمالي للمركبة يبلغ 26,001 رطلًا أو أكثر، حيث لا تتجاوز أي وحدة مقطورة 10,000 رطل من معدل الوزن الإجمالي للمركبة؟","options":["الفئة A","الفئة B","الفئة C","الفئة D"],"explanation":"تعرّف كانساس CDL من الفئة B بأنها أي مركبة مفردة بمعدل وزن إجمالي يبلغ 26,001 رطلًا أو أكثر، أو مركبة من هذا القبيل تقطر وحدة لا يتجاوز معدل وزنها الإجمالي 10,000 رطل. المصدر: دليل CDL في كانساس (KDOR) والمادة K.S.A. 8-2,128."},"21":{"q":"ما هو الحد الأدنى لمعدل الوزن الإجمالي للمجموعة الذي يحدد CDL من الفئة A في كانساس عندما تتجاوز الوحدة المقطورة 10,000 رطل؟","options":["18,000 رطل","26,001 رطلًا","33,000 رطل","10,001 رطل"],"explanation":"تشمل CDL من الفئة A في كانساس أي مجموعة من المركبات بمعدل وزن إجمالي للمجموعة يبلغ 26,001 رطلًا أو أكثر، شريطة أن يكون معدل الوزن الإجمالي للوحدة (الوحدات) المقطورة أكثر من 10,000 رطل. المصدر: دليل CDL في كانساس (KDOR)؛ المادة K.S.A. 8-2,128."},"22":{"q":"يَنقل سائق كمية من المواد الخطرة تستوجب وضع اللوحات التحذيرية في شاحنة فان بمعدل وزن إجمالي أقل من 26,001 رطلًا. أي مزيج من فئة CDL والتظهير في كانساس ينطبق؟","options":["الفئة A بدون تظهير","الفئة B مع تظهير N","الفئة C مع تظهير H","الفئة D مع تظهير P"],"explanation":"إذا كانت المركبة لا تستوفي تعريفات الوزن للفئة A أو B لكنها تنقل مواد خطرة بكميات تستوجب اللوحات التحذيرية (أو تحمل 16 راكبًا فأكثر)، فإن كانساس تشترط CDL من الفئة C، إضافةً إلى تظهير H للمواد الخطرة. المصدر: دليل CDL في كانساس (KDOR)؛ 49 CFR 383.91."},"23":{"q":"على CDL في كانساس، ماذا يخوّل تظهير \"N\" السائق أن يفعل؟","options":["تشغيل مركبات الصهاريج","نقل المواد الخطرة","قطر المقطورات المزدوجة والثلاثية","قيادة حافلة مدرسية"],"explanation":"في كانساس، يسمح تظهير \"N\" بتشغيل مركبات الصهاريج. المصدر: المادة K.S.A. 8-2,135؛ دليل CDL في كانساس (KDOR)."},"24":{"q":"أي رمز تظهير على CDL في كانساس مطلوب لقطر المقطورات المزدوجة والثلاثية؟","options":["P","H","T","S"],"explanation":"يخوّل تظهير \"T\" قطر المقطورات المزدوجة والثلاثية؛ ويُحصَل عليه باجتياز اختبار معرفي فقط (دون اختبار مهارات منفصل). المصدر: المادة K.S.A. 8-2,135؛ دليل CDL في كانساس (KDOR)."},"25":{"q":"مركبة مصممة لنقل 16 شخصًا أو أكثر، بما في ذلك السائق. أي تظهير CDL في كانساس مطلوب (في غياب استثناء الحافلة المدرسية)؟","options":["N (صهريج)","P (ركاب)","T (مزدوجة/ثلاثية)","H (مواد خطرة)"],"explanation":"يُطلب تظهير \"P\" (الركاب) للمركبات المصممة لنقل 16 شخصًا أو أكثر بما في ذلك السائق، ويتطلب اجتياز اختبار معرفي واختبار مهارات معًا. المصدر: دليل CDL في كانساس (KDOR)؛ 49 CFR 383.93."},"26":{"q":"للحصول على تظهير الحافلة المدرسية (S) في كانساس، أي تظهير آخر يجب أن يحمله السائق أيضًا؟","options":["H (المواد الخطرة)","N (مركبة الصهريج)","P (الركاب)","T (المزدوجة/الثلاثية)"],"explanation":"تشترط كانساس على السائقين أن يحملوا أولًا تظهير \"P\" (الركاب) قبل إضافة تظهير \"S\" (الحافلة المدرسية)، الذي يتطلب أيضًا اجتياز اختبارات معرفية ومهارية إضافية. المصدر: دليل CDL في كانساس (KDOR)؛ 49 CFR 383.93."},"27":{"q":"قبل أن تتمكن كانساس من إصدار تظهير المواد الخطرة (H)، يجب على مقدّم الطلب أن يستكمل أي شرط فيدرالي إضافي؟","options":["تقييم التهديد الأمني من TSA (تحقق من الخلفية)","إعفاء بصري من FMCSA","تدريب ميداني على الطريق لمدة 30 يومًا","إعادة اختبار مهارات الفرامل الهوائية"],"explanation":"يتطلب تظهير H (المواد الخطرة) اجتياز اختبار معرفي وكذلك تقييم التهديد الأمني من TSA، الذي يشمل أخذ البصمات والتحقق من الخلفية، قبل أن تصدره كانساس. المصدر: دليل CDL في كانساس (KDOR)؛ 49 CFR 383.71/1572."},"28":{"q":"ما هو الحد الأدنى للعمر للحصول على CDL في كانساس مقيّد بالقيادة داخل الولاية فقط؟","options":["16 عامًا","17 عامًا","18 عامًا","21 عامًا"],"explanation":"تشترط كانساس أن يكون عمر السائق 18 عامًا على الأقل للحصول على CDL للتشغيل داخل الولاية فقط. المصدر: دليل CDL في كانساس (KDOR)؛ المادة K.S.A. 8-2,129."},"29":{"q":"ما هو الحد الأدنى للعمر للحصول على CDL في كانساس للقيادة بين الولايات (عبر حدود الولايات) أو لنقل المواد الخطرة؟","options":["18 عامًا","19 عامًا","20 عامًا","21 عامًا"],"explanation":"يجب أن يكون عمر السائق 21 عامًا على الأقل لقيادة مركبة تجارية في التجارة بين الولايات، أو نقل المواد الخطرة، أو نقل الركاب عبر حدود الولايات. المصدر: دليل CDL في كانساس (KDOR)؛ 49 CFR 391.11."},"30":{"q":"بعد إصدار تصريح المتعلّم التجاري (CLP) لأول مرة في كانساس، كم يجب أن يحتفظ به مقدّم الطلب قبل أن يصبح مؤهلًا لإجراء اختبار مهارات CDL؟","options":["7 أيام على الأقل","14 يومًا على الأقل","30 يومًا على الأقل","60 يومًا على الأقل"],"explanation":"القاعدة الفيدرالية المعتمدة في كانساس: لا يكون حامل CLP مؤهلًا لإجراء اختبار مهارات CDL إلا بعد الاحتفاظ بالتصريح لمدة 14 يومًا كحد أدنى. المصدر: دليل CDL في كانساس (KDOR)؛ 49 CFR 383.25."},"31":{"q":"ما الذي يجب على حامل CLP في كانساس فعله أثناء قيادة مركبة تجارية للتدريب؟","options":["القيادة فقط بين الشروق والغروب","أن يرافقه حامل CDL يجلس في المقعد الأمامي بجانبه","قصر القيادة على نطاق 25 ميلًا من المنزل","عدم حمل أي شحنة من أي نوع"],"explanation":"لا يجوز لحامل CLP في كانساس تشغيل مركبة تجارية إلا عندما يرافقه شخص يحمل CDL صالحًا لنوع المركبة، ويجب أن يجلس في المقعد الأمامي بجانب السائق. المصدر: دليل CDL في كانساس (KDOR)؛ 49 CFR 383.25."},"32":{"q":"بموجب المعايير الفيدرالية المعتمدة في كانساس، يجب ألا يكون تصريح المتعلّم التجاري صالحًا لأكثر من أي مدة قصوى دون إعادة الاختبار؟","options":["90 يومًا","6 أشهر","سنة واحدة","5 سنوات"],"explanation":"يجوز إصدار CLP لمدة لا تتجاوز سنة واحدة من الإصدار الأولي دون أن يُطلب من مقدّم الطلب إعادة الاختبارات المعرفية. المصدر: دليل CDL في كانساس (KDOR)؛ 49 CFR 383.25."},"33":{"q":"أي مجموعة من المستندات يجب على مقدّم طلب CDL في كانساس تقديمها إلى قسم المركبات عند التقديم؟","options":["إثبات الهوية، ورقم الضمان الاجتماعي، والإقامة في كانساس، والوجود القانوني","فقط بطاقة الضمان الاجتماعي وشهادة الميلاد","جواز سفر وتسجيل مركبة","إثبات التوظيف وتصريح المواد الخطرة"],"explanation":"يشترط قسم المركبات بإدارة الإيرادات في كانساس على مقدّمي الطلبات إثبات الهوية، وتقديم رقم الضمان الاجتماعي، وإظهار إثبات الإقامة في كانساس والوجود القانوني (الشرعي). المصدر: قسم المركبات بإدارة الإيرادات في كانساس (ksrevenue.gov)."},"34":{"q":"تدريب السائق المبتدئ (ELDT) الذي تشترطه كانساس لمقدّمي الطلبات للفئة A/B لأول مرة يجب أن تقدّمه جهة تدريب تكون:","options":["معتمدة من المنطقة التعليمية المحلية","مدرجة في سجل مزوّدي التدريب التابع لـ FMCSA","معتمدة من دورية كانساس للطرق السريعة","معتمدة من وزارة التعليم الأمريكية"],"explanation":"منذ 7 فبراير 2022، يجب استكمال ELDT عبر مزوّد مدرج في سجل مزوّدي التدريب (TPR) التابع لـ FMCSA قبل أن تسمح كانساس بإجراء بعض اختبارات المهارات/المعرفة. المصدر: إدارة الإيرادات في كانساس (dovcdlentry.html)؛ 49 CFR Part 380."},"35":{"q":"أي من الإجراءات التالية التي تُتخذ لأول مرة لا يستوجب اشتراط ELDT الفيدرالي في كانساس؟","options":["الحصول على CDL من الفئة A لأول مرة","ترقية CDL من الفئة B إلى الفئة A","الحصول على تظهير المواد الخطرة (H) لأول مرة","تجديد CDL قائم من الفئة A دون أي تظهيرات جديدة"],"explanation":"ينطبق ELDT على إصدار الفئة A/B لأول مرة، والترقية من الفئة B إلى A، وتظهيرات H أو P أو S لأول مرة. أما التجديد الاعتيادي لـ CDL قائم دون ترقية أو تظهير جديد فلا يتطلب ELDT. المصدر: إدارة الإيرادات في كانساس (dovcdlentry.html)؛ 49 CFR Part 380."},"36":{"q":"سائق CDL في كانساس يعمل داخل كانساس فقط وليس معفًى من المتطلبات الطبية ينبغي أن يقدّم إقرارًا ذاتيًا بأي فئة؟","options":["غير معفى بين الولايات","معفى بين الولايات","غير معفى داخل الولاية","معفى داخل الولاية"],"explanation":"السائق الذي يعمل داخل كانساس حصرًا والخاضع لاشتراط الشهادة الطبية يقدّم إقرارًا ذاتيًا بأنه \"غير معفى داخل الولاية\" ويجب أن يحتفظ بشهادة فاحص طبي سارية. المصدر: إدارة الإيرادات في كانساس، الإقرار الطبي (ksrevenue.gov)؛ 49 CFR 383.71."},"37":{"q":"أي فئة من فئات الإقرار الذاتي لـ CDL في كانساس تستوجب على السائق الاحتفاظ بشهادة فاحص طبي فيدرالية سارية وتقديمها؟","options":["معفى بين الولايات","معفى داخل الولاية","غير معفى بين الولايات","مشغّل مزرعة مقيَّد"],"explanation":"يجب على السائقين الذين يقدّمون إقرارًا بأنهم غير معفيين بين الولايات (وغير معفيين داخل الولاية) الاحتفاظ بشهادة فاحص طبي سارية؛ أما السائقون المعفون فلا يقدّمون مستندات طبية. المصدر: إدارة الإيرادات في كانساس، الإقرار الطبي (ksrevenue.gov)؛ 49 CFR 383.71."},"38":{"q":"بموجب القواعد الفيدرالية/قواعد كانساس، \"مركبة الصهريج\" لأغراض تظهير N هي عمومًا تلك المصممة لنقل سائل أو غاز في صهريج مثبَّت بشكل دائم أو مؤقت بسعة مقدَّرة لا تقل عن:","options":["100 غالون","500 غالون","1,000 غالون","5,000 غالون"],"explanation":"ينطبق تظهير N (الصهريج) على المركبات التي تنقل مواد سائلة أو غازية في صهاريج بسعة مقدَّرة إجمالية تبلغ 1,000 غالون أو أكثر (صهاريج فردية سعة 119 غالونًا أو أكثر). المصدر: دليل CDL في كانساس (KDOR)؛ 49 CFR 383.5."},"39":{"q":"يرغب سائق في الجمع بين تظهيري المواد الخطرة والصهريج على CDL في كانساس. أي رمز تظهير مفرد يمثّل هذا الجمع؟","options":["X","T","P","L"],"explanation":"تستخدم كانساس رمز التظهير \"X\" لتمثيل الجمع بين تظهيري المواد الخطرة (H) والصهريج (N). المصدر: المادة K.S.A. 8-2,135؛ دليل CDL في كانساس (KDOR)."},"40":{"q":"في كانساس، ما هو الحد الأقصى لتركيز الكحول في الدم (BAC) الذي يجوز عنده قانونيًا للشخص تشغيل مركبة تجارية (CMV)؟","options":["0.08% أو أعلى هو الحد","أي BAC أقل من 0.04%","أي BAC أقل من 0.10%","أي BAC أقل من 0.02%"],"explanation":"تحظر كانساس تشغيل مركبة تجارية بتركيز كحول في الدم يبلغ 0.04% أو أكثر؛ والحد القانوني لسائقي المركبات التجارية هو أقل من 0.04%، أي نصف حد 0.08% المقرر للسائقين العاديين. المصدر: دليل CDL في كانساس، القسم 1 (حالات حرمان السائق)؛ 49 CFR 383.51 كما اعتُمدت في كانساس."},"41":{"q":"كم تبلغ مدة حرمان حامل CDL في كانساس عند ارتكاب مخالفة كبرى أولى، مثل القيادة تحت تأثير الكحول في مركبة تجارية، عند عدم نقل مواد خطرة تستوجب اللوحات التحذيرية؟","options":["60 يومًا","سنة واحدة","3 سنوات","6 أشهر"],"explanation":"تؤدي المخالفة الكبرى الأولى (القيادة تحت تأثير الكحول، رفض الاختبار، مغادرة مكان الحادث، استخدام مركبة تجارية في جناية، إلخ) إلى الحرمان لمدة سنة واحدة في كانساس. المصدر: المادة K.S.A. 8-2,142؛ دليل CDL في كانساس؛ 49 CFR 383.51."},"42":{"q":"إذا ارتكب سائق في كانساس مخالفة كبرى أولى أثناء نقل مواد خطرة تستوجب اللوحات التحذيرية، فكم تبلغ مدة الحرمان؟","options":["سنة واحدة","3 سنوات","مدى الحياة","120 يومًا"],"explanation":"تؤدي المخالفة الكبرى الأولى أثناء تشغيل مركبة تجارية تنقل مواد خطرة تستوجب اللوحات التحذيرية إلى الحرمان لمدة 3 سنوات في كانساس بدلًا من سنة واحدة المعتادة. المصدر: المادة K.S.A. 8-2,142؛ دليل CDL في كانساس؛ 49 CFR 383.51."},"43":{"q":"ما هي مدة الحرمان في كانساس لمخالفة كبرى ثانية تُرتكب في مركبة تجارية؟","options":["3 سنوات","10 سنوات","مدى الحياة","5 سنوات"],"explanation":"تؤدي المخالفة الكبرى الثانية إلى الحرمان من CDL مدى الحياة في كانساس. المصدر: المادة K.S.A. 8-2,142؛ دليل CDL في كانساس؛ 49 CFR 383.51(b)."},"44":{"q":"بموجب قواعد الموافقة الضمنية في كانساس، يُعامَل حامل CDL الذي يرفض اختبارًا كيميائيًا للنفس أو الدم على أنه ارتكب ماذا؟","options":["مخالفة مرورية خطيرة","مخالفة كبرى","مخالفة أمر خارج الخدمة","مخالفة غير واجبة الإبلاغ"],"explanation":"يُصنَّف رفض اختبار كيميائي مطلوب بصورة قانونية على أنه مخالفة كبرى، ويترتب عليه الحرمان ذاته لمدة سنة (أو 3 سنوات للمواد الخطرة) كما في القيادة تحت تأثير الكحول. المصدر: المادة K.S.A. 8-2,142؛ دليل CDL في كانساس، القسم 1."},"45":{"q":"كم تبلغ مدة حرمان حامل CDL في كانساس لرفضه اختبارًا كيميائيًا أثناء قيادة مركبة تجارية لا تحمل مواد خطرة تستوجب اللوحات التحذيرية؟","options":["90 يومًا","سنة واحدة","3 سنوات","مدى الحياة"],"explanation":"يؤدي رفض الاختبار الأول في مركبة تجارية إلى الحرمان من CDL لمدة سنة واحدة (3 سنوات في حال نقل مواد خطرة تستوجب اللوحات التحذيرية). المصدر: المادة K.S.A. 8-2,142؛ 49 CFR 383.51."},"46":{"q":"عندما يجمع سائق CDL في كانساس مخالفتين مروريتين خطيرتين خلال فترة 3 سنوات (في مركبة تجارية)، يكون الحد الأدنى للحرمان:","options":["30 يومًا","60 يومًا","120 يومًا","سنة واحدة"],"explanation":"تؤدي مخالفتان مروريتان خطيرتان خلال 3 سنوات إلى حرمان لا يقل عن 60 يومًا في كانساس. المصدر: دليل CDL في كانساس، القسم 1؛ 49 CFR 383.51(c)."},"47":{"q":"عندما يجمع سائق CDL في كانساس ثلاث مخالفات مرورية خطيرة خلال فترة 3 سنوات (في مركبة تجارية)، يكون الحد الأدنى للحرمان:","options":["60 يومًا","90 يومًا","120 يومًا","180 يومًا"],"explanation":"تؤدي ثلاث مخالفات مرورية خطيرة خلال 3 سنوات إلى حرمان لا يقل عن 120 يومًا في كانساس. المصدر: دليل CDL في كانساس، القسم 1؛ 49 CFR 383.51(c)."},"48":{"q":"أي مما يلي يُعدّ \"مخالفة مرورية خطيرة\" لحامل CDL في كانساس؟","options":["القيادة بسرعة 15 mph أو أكثر فوق حد السرعة","القيادة بسرعة 5 mph فوق حد السرعة","مخالفة وقوف","ملصق تسجيل منتهي الصلاحية"],"explanation":"تشمل المخالفات المرورية الخطيرة تجاوز السرعة بمقدار 15 mph أو أكثر فوق الحد، والقيادة المتهورة، وتغيير المسارات بشكل غير صحيح أو غير منتظم، والاقتراب المفرط من المركبة الأمامية، والمخالفات المرورية المرتبطة بحادث مميت. المصدر: دليل CDL في كانساس، القسم 1؛ 49 CFR 383.51(c)."},"49":{"q":"بموجب قواعد CDL الفيدرالية/قواعد كانساس، تُصنَّف قيادة مركبة تجارية أثناء كتابة الرسائل النصية على أنها أي نوع من المخالفات؟","options":["مخالفة كبرى","مخالفة مرورية خطيرة","مخالفة أمر خارج الخدمة","مخالفة معبر سكة حديد"],"explanation":"تُعدّ كتابة الرسائل النصية أثناء قيادة مركبة تجارية، واستخدام هاتف محمول يدوي أثناء قيادتها، مخالفتين مروريتين خطيرتين تُحتسبان ضمن الحرمان لمدة 60 يومًا (مخالفتان خلال 3 سنوات) و120 يومًا (ثلاث مخالفات خلال 3 سنوات). المصدر: دليل CDL في كانساس؛ 49 CFR 383.51(c) و392.80/392.82."},"50":{"q":"بالنسبة لسائق CDL في كانساس، يُعامَل استخدام هاتف محمول يدوي أثناء تشغيل مركبة تجارية على أنه:","options":["مخالفة غير واجبة الإبلاغ","مخالفة مرورية خطيرة","مخالفة كبرى","حظر تلقائي مدى الحياة"],"explanation":"تنتهك قيادة مركبة تجارية أثناء استخدام هاتف يدوي المادة 49 CFR 392.82 وتُعدّ مخالفة مرورية خطيرة؛ ويواجه السائق غرامة مدنية فيدرالية (تصل إلى $2,750) وتُحتسب المخالفة ضمن حالات الحرمان للمخالفات الخطيرة. المصدر: دليل CDL في كانساس؛ 49 CFR 392.82، 383.51(c)."},"51":{"q":"ما هي مدة الحرمان لإدانة حامل CDL في كانساس الأولى بمخالفة معبر سكة حديد مع الطريق السريع؟","options":["لا تقل عن 30 يومًا","لا تقل عن 60 يومًا","لا تقل عن 120 يومًا","لا تقل عن 180 يومًا"],"explanation":"تؤدي مخالفة معبر سكة حديد مع الطريق السريع الأولى إلى حرمان لا يقل عن 60 يومًا في كانساس. المصدر: دليل CDL في كانساس، القسم 1؛ 49 CFR 383.51(d)."},"52":{"q":"يرتكب حامل CDL في كانساس مخالفة معبر سكة حديد مع الطريق السريع ثانية خلال فترة 3 سنوات. الحد الأدنى للحرمان هو:","options":["60 يومًا","90 يومًا","120 يومًا","سنة واحدة"],"explanation":"تؤدي مخالفة معبر سكة الحديد الثانية خلال 3 سنوات إلى حرمان لا يقل عن 120 يومًا. المصدر: دليل CDL في كانساس، القسم 1؛ 49 CFR 383.51(d)."},"53":{"q":"يرتكب حامل CDL في كانساس مخالفة معبر سكة حديد مع الطريق السريع ثالثة خلال فترة 3 سنوات. الحد الأدنى للحرمان هو:","options":["120 يومًا","180 يومًا","لا تقل عن سنة واحدة","سنتان"],"explanation":"تؤدي مخالفة معبر سكة الحديد الثالثة خلال 3 سنوات إلى حرمان لا يقل عن سنة واحدة. المصدر: دليل CDL في كانساس، القسم 1؛ 49 CFR 383.51(d)."},"54":{"q":"ما هو الحد الأدنى للحرمان لمخالفة سائق CDL في كانساس الأولى لأمر خارج الخدمة (غير المواد الخطرة، وغير الركاب)؟","options":["لا تقل عن 60 يومًا","لا تقل عن 90 يومًا","لا تقل عن 180 يومًا","لا تقل عن سنة واحدة"],"explanation":"تؤدي مخالفة أمر خارج الخدمة الأولى إلى حرمان لا يقل عن 180 يومًا (ولا يزيد عن سنة واحدة) في كانساس. المصدر: دليل CDL في كانساس، القسم 1؛ 49 CFR 383.51(e)."},"55":{"q":"ما هو نطاق الحرمان لمخالفة أمر خارج الخدمة ثانية خلال 10 سنوات لسائق CDL في كانساس (غير المواد الخطرة، وغير الركاب)؟","options":["من 180 يومًا إلى سنة واحدة","من سنة إلى 3 سنوات","من سنتين إلى 5 سنوات","من 3 إلى 5 سنوات"],"explanation":"تؤدي مخالفة أمر خارج الخدمة الثانية خلال 10 سنوات إلى حرمان لا يقل عن سنتين ولا يزيد عن 5 سنوات. المصدر: دليل CDL في كانساس، القسم 1؛ 49 CFR 383.51(e)."},"56":{"q":"يرتكب سائق CDL في كانساس مخالفة أمر خارج الخدمة أولى أثناء نقل مواد خطرة تستوجب اللوحات التحذيرية أو نقل ركاب. يكون الحرمان:","options":["لا يقل عن 60 يومًا","لا يقل عن 180 يومًا، حتى سنتين","لا يقل عن 90 يومًا، حتى سنة واحدة","مدى الحياة"],"explanation":"تؤدي مخالفة أمر خارج الخدمة الأولى أثناء نقل مواد خطرة تستوجب اللوحات التحذيرية أو نقل ركاب إلى حرمان لا يقل عن 180 يومًا ولا يزيد عن سنتين (مقابل ما يصل إلى سنة واحدة للحمولات العادية). المصدر: دليل CDL في كانساس؛ 49 CFR 383.51(e)."},"57":{"q":"في كانساس، سائق مركبة تجارية يُوجَد لديه أي كمية يمكن الكشف عنها من الكحول في جسمه (حتى لو كانت أقل من 0.04%) أثناء أدائه للخدمة يكون عرضة لماذا؟","options":["حرمان فوري مدى الحياة","الإيقاف عن الخدمة لمدة 24 ساعة","حرمان لمدة سنة واحدة","حرمان لمدة 60 يومًا"],"explanation":"يُوقَف سائق المركبة التجارية الذي لديه أي كمية قابلة للقياس أو الكشف من الكحول (أقل من 0.04%) عن الخدمة لمدة 24 ساعة؛ أما تركيز الكحول في الدم البالغ 0.04% أو أكثر فيصبح مخالفة كبرى (حرمان لمدة سنة واحدة). المصدر: دليل CDL في كانساس، القسم 1؛ 49 CFR 392.5."},"58":{"q":"إلى جانب الحرمان، ما هي العقوبة الإضافية التي يمكن أن تفرضها غرامة مدنية فيدرالية/في كانساس على شركة نقل تسمح عن علم لسائق بالعمل أثناء سريان أمر خارج الخدمة؟","options":["غرامة من $2,750 إلى $11,000","غرامة ثابتة قدرها $500","فقدان تصريح تشغيل الشركة لمدة 60 يومًا","لا تنطبق أي عقوبة على الشركة"],"explanation":"يكون رب العمل الذي يسمح عن علم لسائق بمخالفة أمر خارج الخدمة أو يطلب منه ذلك عرضة لغرامة مدنية من $2,750 إلى $11,000، إضافةً إلى حرمان السائق وغرامته. المصدر: دليل CDL في كانساس؛ 49 CFR 383.53(b)."},"59":{"q":"يُدان حامل CDL في كانساس بمخالفة كبرى، ثم يُدان لاحقًا، بعد سنوات، بمخالفة كبرى ثانية. بعد الحرمان مدى الحياة، قد يكون رد الاعتبار ممكنًا فقط:","options":["بعد سنة واحدة","بعد 5 سنوات","بعد 10 سنوات كحد أدنى، إذا استُوفيت الشروط","لا يكون ممكنًا أبدًا"],"explanation":"يجوز، بموجب القواعد المعتمدة من FMCSA، تخفيض الحرمان مدى الحياة لمخالفتين كبريين إلى 10 سنوات كحد أدنى إذا استكمل السائق الشروط المقررة؛ وبعض حالات الحظر مدى الحياة (مثل استخدام مركبة تجارية لتصنيع/توزيع المخدرات) دائمة. المصدر: دليل CDL في كانساس؛ 49 CFR 383.51(b)."},"60":{"q":"في كانساس، عندما تقترب حافلة مدرسية تقل ركابًا من تقاطع سكة حديد على مستوى الطريق، على أي مسافة من أقرب قضيب يجب على السائق أن يتوقف؟","options":["في حدود 50 قدمًا ولكن ليس أقل من 15 قدمًا من أقرب قضيب","في حدود 25 قدمًا ولكن ليس أقل من 5 أقدام من أقرب قضيب","في حدود 75 قدمًا ولكن ليس أقل من 25 قدمًا من أقرب قضيب","في حدود 100 قدم ولكن ليس أقل من 50 قدمًا من أقرب قضيب"],"explanation":"تُلزم كانساس مركبات معينة بالتوقف في حدود 50 قدمًا ولكن ليس أقل من 15 قدمًا من أقرب قضيب، والنظر والإصغاء قبل العبور. المصدر: K.S.A. 8-1551؛ دليل CDL لكانساس (KDOR)."},"61":{"q":"بموجب قانون كانساس، يجب على المركبة التجارية التي تحمل لافتات المواد الخطرة والتي يُطلب منها التوقف عند تقاطع سكة حديد أن تتوقف توقفًا تامًا ضمن أي مسافة من أقرب قضيب؟","options":["ليس أقرب من 10 أقدام وليس أبعد من 30 قدمًا","ليس أقرب من 15 قدمًا وليس أبعد من 50 قدمًا","ليس أقرب من 20 قدمًا وليس أبعد من 60 قدمًا","ليس أقرب من 5 أقدام وليس أبعد من 25 قدمًا"],"explanation":"يجب على مركبات HazMat التي تحمل لافتات أن تتوقف في حدود 50 قدمًا ولكن ليس أقل من 15 قدمًا من أقرب قضيب، وألا تتابع السير إلا عندما يكون ذلك آمنًا. المصدر: K.S.A. 8-1551؛ دليل CDL لكانساس (KDOR)."},"62":{"q":"جرى توسيع قانون 'Move Over' في كانساس اعتبارًا من 1 يوليو 2025. ماذا يُلزم القانون الحالي السائق الذي يقترب من مركبة متوقفة بأن يفعل؟","options":["التحول إلى مسار آخر فقط لمركبات الشرطة والإطفاء والإسعاف","التحول إلى مسار آخر فقط لمركبات الطوارئ وشاحنات السحب","التحول إلى مسار آخر لأي مركبة ثابتة تعرض أضواءً وامضة أو أضواء تحذير، وليس فقط لمركبات الطوارئ","التحول إلى مسار آخر فقط عندما يقف ضابط خارج المركبة"],"explanation":"وسّع مشروع قانون مجلس الشيوخ رقم 8 (الساري اعتبارًا من 1 يوليو 2025) المادة K.S.A. 8-1530 بحيث يجب على السائقين التحول إلى مسار آخر أو تخفيف السرعة لأي مركبة ثابتة تعرض أضواءً وامضة/تحذيرية. المصدر: K.S.A. 8-1530؛ مشروع قانون مجلس الشيوخ رقم 8 لكانساس (2025)."},"63":{"q":"على طريق سريع في كانساس به مساران أو أكثر في اتجاه السائق، ماذا يُلزم قانون Move Over به عند المرور بمركبة ثابتة تعمل أضواؤها التحذيرية؟","options":["التوقف توقفًا تامًا دائمًا حتى تغادر المركبة","إطلاق البوق باستمرار أثناء المرور","الحفاظ على السرعة العادية مع تشغيل أضواء التحذير","التحول إلى مسار غير مجاور للمركبة المتوقفة إذا أمكن القيام بذلك بأمان"],"explanation":"تُلزم المادة K.S.A. 8-1530(b) السائقين على الطرق متعددة المسارات بالتحول إلى مسار غير مجاور إذا كان ذلك آمنًا؛ وإذا تعذّر ذلك، فعليهم تخفيف السرعة والمتابعة بحذر واجب. المصدر: K.S.A. 8-1530؛ دليل CDL لكانساس (KDOR)."},"64":{"q":"بموجب قانون Move Over في كانساس، إذا كان تغيير المسار بعيدًا عن مركبة متوقفة تعمل أضواؤها التحذيرية غير آمن أو متعذرًا، فماذا يجب على السائق أن يفعل؟","options":["التوقف في مسار السير والانتظار","تخفيف السرعة والحفاظ على سرعة آمنة لظروف الطريق والطقس والمرور","المتابعة بالسرعة القصوى المحددة باللافتات","الانحراف إلى الكتف والتوقف"],"explanation":"عندما يكون تغيير المسار متعذرًا أو غير آمن، تُلزم المادة K.S.A. 8-1530(b) السائق بالمتابعة بحذر واجب وتخفيف السرعة والحفاظ على سرعة آمنة. المصدر: K.S.A. 8-1530."},"65":{"q":"ما هي السرعة القصوى المحددة باللافتات على طريق سريع متعدد المسارات منفصل (طريق بين الولايات) في كانساس، كما حددها وزير النقل؟","options":["70 mph","65 mph","75 mph","80 mph"],"explanation":"تحدد كانساس الحد الأقصى على الطرق السريعة متعددة المسارات المنفصلة بـ 75 mph على النحو المعيّن والمعلن باللافتات من قبل وزير النقل. المصدر: K.S.A. 8-1558."},"66":{"q":"هل تحدد كانساس حدًا أقصى منفصلًا وأدنى للسرعة على مستوى الولاية للشاحنات/المركبات التجارية مقارنةً بالسيارات على طرقها بين الولايات؟","options":["نعم - تُقيَّد الشاحنات بـ 65 mph على مستوى الولاية بينما يجوز للسيارات السير بـ 75 mph","نعم - تُقيَّد الشاحنات بـ 60 mph على جميع الطرق بين الولايات","نعم - تُقيَّد الشاحنات بـ 55 mph ليلًا على مستوى الولاية","لا - ينطبق الحد الأقصى نفسه المحدد باللافتات على الشاحنات والسيارات في كانساس"],"explanation":"لا تفرض كانساس حدًا منفصلًا لسرعة الشاحنات على مستوى الولاية؛ ينطبق الحد الأقصى نفسه المحدد باللافتات على جميع المركبات ما لم تنص اللافتات على خلاف ذلك. المصدر: K.S.A. 8-1558؛ KDOT."},"67":{"q":"بموجب المادة K.S.A. 8-1558، ما هو الحد الأقصى القانوني للسرعة على طريق مقاطعة أو بلدة في كانساس؟","options":["55 mph","45 mph","65 mph","60 mph"],"explanation":"تحدد كانساس الحد الأقصى على طرق المقاطعات أو البلدات بـ 55 mph، وعلى الطرق الأخرى (غير متعددة المسارات) بـ 65 mph، و30 mph في المناطق الحضرية. المصدر: K.S.A. 8-1558."},"68":{"q":"بموجب المادة K.S.A. 8-1558، ما هو الحد الأقصى القانوني للسرعة في منطقة حضرية في كانساس ما لم يُحدد خلاف ذلك باللافتات؟","options":["25 mph","35 mph","30 mph","20 mph"],"explanation":"الحد الأقصى القانوني في المنطقة الحضرية هو 30 mph ما لم يُحدد حد مختلف باللافتات. المصدر: K.S.A. 8-1558."},"69":{"q":"على طريق في كانساس ذي مسارين (غير مقسّم)، ماذا يجب على السائق الذي يقابل حافلة مدرسية متوقفة تعمل أضواؤها الحمراء الوامضة أن يفعل؟","options":["تخفيف السرعة إلى 20 mph والمرور بحذر","التحول إلى المسار البعيد والمتابعة بمحاذاة الحافلة","التوقف فقط إذا كان الأطفال يعبرون بشكل ظاهر","التوقف قبل الوصول إلى الحافلة وعدم المتابعة حتى تتوقف الأضواء الحمراء عن الوميض أو تتحرك الحافلة"],"explanation":"يجب على السائقين الذين يقابلون أو يتجاوزون حافلة مدرسية تعمل أضواؤها الحمراء الوامضة أن يتوقفوا قبل الوصول إليها وأن يبقوا متوقفين حتى تتوقف الأضواء أو تتحرك الحافلة. المصدر: K.S.A. 8-1556."},"70":{"q":"على طريق سريع مقسّم في كانساس بطرق منفصلة، ما هو الاستثناء من التوقف لحافلة مدرسية تقوم بتحميل الأطفال؟","options":["السائق الموجود على طريق مختلف عن طريق الحافلة لا يلزمه التوقف","السائق في المسار الأقرب للحافلة لا يلزمه التوقف","لا ينطبق أي استثناء؛ يجب على جميع السائقين التوقف دائمًا","يجوز للسائق المتابعة إذا كانت الحافلة على بُعد أكثر من 100 قدم"],"explanation":"تنص المادة K.S.A. 8-1556 على أن السائق الموجود على طريق سريع بطرق منفصلة لا يلزمه التوقف لحافلة مدرسية على طريق مختلف (أو في منطقة تحميل ذات وصول محكوم لا يمكن للمشاة العبور فيها). المصدر: K.S.A. 8-1556."},"71":{"q":"بموجب استثناء الطريق المنفصل للحافلة المدرسية في كانساس، أي سيناريو لا يزال يتطلب توقف المرور في جميع الاتجاهات؟","options":["طريق سريع مقسّم تكون فيه الحافلة على الطريق المقابل عبر جزيرة وسطية","طريق غير مقسّم ذو مسارين دون فصل مادي بين الاتجاهين","طريق سريع ذو وصول محكوم تكون فيه الحافلة في منطقة تحميل ولا يمكن للمشاة العبور","طريقان مفصولان ماديًا بحاجز"],"explanation":"ينطبق الاستثناء فقط حيث توجد طرق منفصلة. على طريق غير مقسّم دون فصل، يجب أن يتوقف المرور في كلا الاتجاهين. المصدر: K.S.A. 8-1556."},"72":{"q":"في كانساس، الغرامة الأساسية لتجاوز حافلة مدرسية متوقفة بشكل غير قانوني وأضواؤها الحمراء وامضة هي أي مما يلي؟","options":["$75، دون أي تصعيد","$150، تُضاعَف فقط في المناطق المدرسية","$500 ثابتة لكل مخالفة","$315، مع غرامات متصاعدة للمخالفات المتكررة"],"explanation":"يحدد جدول الغرامات الموحد في كانساس غرامة أساسية قدرها $315 لتجاوز حافلة مدرسية بشكل غير قانوني، مع غرامات متصاعدة للمخالفات اللاحقة. المصدر: K.S.A. 8-2118."},"73":{"q":"عندما يوقف سائق CDL في كانساس مركبة تجارية على كتف طريق سريع مقسّم، أين ينبغي وضع مثلث التحذير العاكس الأبعد إلى الخلف؟","options":["على بُعد نحو 200 قدم خلف المركبة باتجاه المرور القادم","على بُعد نحو 50 قدمًا خلف المركبة","على بُعد نحو 500 قدم خلف المركبة","على بُعد نحو 150 قدمًا خلف المركبة"],"explanation":"على طريق سريع مقسّم/أحادي الاتجاه، تُوضع المثلثات على بُعد 10 أقدام و100 قدم و200 قدم باتجاه المرور القادم. المصدر: دليل CDL لكانساس (KDOR)؛ 49 CFR 392.22."},"74":{"q":"يتوقف سائق CDL في كانساس على طريق سريع أحادي الاتجاه أو مقسّم. ما هو الوضع الصحيح للمثلثات العاكسة الثلاثة جميعها باتجاه المرور القادم؟","options":["10 أقدام و50 قدمًا و150 قدمًا إلى الخلف","10 أقدام و100 قدم و200 قدم إلى الخلف","25 قدمًا و100 قدم و250 قدمًا إلى الخلف","5 أقدام و75 قدمًا و175 قدمًا إلى الخلف"],"explanation":"على الطرق المقسّمة/أحادية الاتجاه، ضع المثلثات على بُعد 10 و100 و200 قدم باتجاه المرور القادم. المصدر: دليل CDL لكانساس (KDOR)؛ 49 CFR 392.22."},"75":{"q":"بعد توقف مركبة تجارية على طريق في كانساس ذي مسارين واتجاهين، خلال كم من الوقت يجب على السائق وضع أجهزة التحذير من الطوارئ المطلوبة؟","options":["خلال 30 دقيقة من التوقف","خلال ساعة واحدة من التوقف","خلال 10 دقائق من التوقف","فقط إذا توقف لأكثر من ساعتين"],"explanation":"يجب وضع أجهزة التحذير من الطوارئ خلال 10 دقائق من التوقف على طريق سريع أو كتف. المصدر: دليل CDL لكانساس (KDOR)؛ 49 CFR 392.22."},"76":{"q":"على طريق في كانساس ذي مسارين واتجاهين، أين ينبغي لسائق المركبة التجارية أن يضع المثلثات التحذيرية الثلاثة بعد التوقف؟","options":["واحد في حدود 10 أقدام من الخلف، وواحد على بُعد نحو 100 قدم خلف المركبة، وواحد على بُعد نحو 100 قدم أمامها","الثلاثة جميعها في حدود 10 أقدام من خلف المركبة","واحد على بُعد 200 قدم خلف المركبة واثنان أمامها","واحد على بُعد 50 قدمًا خلف المركبة واثنان على جانبي المركبة"],"explanation":"على طريق ذي اتجاهين، ضع مثلثًا على بُعد 10 أقدام إلى الخلف، وواحدًا على بُعد نحو 100 قدم إلى الخلف، وواحدًا على بُعد نحو 100 قدم إلى الأمام. المصدر: دليل CDL لكانساس (KDOR)؛ 49 CFR 392.22."},"77":{"q":"عندما يعبر سائق حافلة CDL في كانساس قضبان سكة الحديد عند تقاطع، ما الذي يجب على السائق ألا يفعله بينما أي جزء من الحافلة على القضبان؟","options":["إبقاء الحافلة في ترس منخفض","النظر والإصغاء قبل الدخول","تغيير التروس (نقل السرعة) أثناء عبور القضبان","إبقاء الباب مغلقًا"],"explanation":"يجب على السائقين عبور قضبان سكة الحديد في ترس لا يستلزم نقل السرعة، ويجب ألا يغيّروا التروس بينما أي جزء من المركبة على القضبان. المصدر: دليل CDL لكانساس (KDOR)."},"78":{"q":"أي حقيقة متعلقة بالمسارات تتميز بها العمليات التجارية في كانساس بشكل حقيقي؟","options":["جميع الطرق بين الولايات في كانساس مجانية دون رسوم ولا توجد بها مسارات تجارية","يشكّل جزء كبير من I-35 وI-335 وI-470 وI-70 الطريق ذا الرسوم Kansas Turnpike، حيث يُسمح بالمقطورات المزدوجة بطول 53 قدمًا","تحظر كانساس جميع الشاحنات التي يزيد طولها عن 40 قدمًا من كل طريق بين الولايات","تُلزم كانساس جميع الشاحنات باستخدام الطرق الأمريكية (غير الطرق بين الولايات) فقط"],"explanation":"الطريق ذو الرسوم Kansas Turnpike (KTA)، بطول نحو 236 ميلًا على طول I-35/I-335/I-470/I-70، طريق رسوم يسمح بالمقطورات المزدوجة بطول 53 قدمًا. المصدر: KDOT؛ هيئة Kansas Turnpike."},"79":{"q":"أي وكالة في كانساس تصدر تصاريح المركبات ذات الأبعاد/الأوزان الزائدة وتعتمد مسارات الشاحنات من خلال نظام K-TRIPS؟","options":["وزارة الإيرادات في كانساس (KDOR)","قسم الترخيص في دورية الطرق السريعة في كانساس","الإدارة الفيدرالية لسلامة الناقلين بالمركبات الآلية","وزارة النقل في كانساس (KDOT)"],"explanation":"تدير KDOT تصاريح المركبات ذات الأبعاد/الأوزان الزائدة والمسارات من خلال نظام توجيه الشاحنات والترخيص الذكي في كانساس (K-TRIPS). المصدر: معلومات المركبات التجارية لدى KDOT."},"80":{"q":"أي وكالة حكومية في كانساس تصدر رخص القيادة التجارية (CDLs)؟","options":["الإدارة الفيدرالية لسلامة الناقلين بالمركبات الآلية","وزارة النقل في كانساس (KDOT)","وزارة الإيرادات في كانساس، قسم المركبات","دورية الطرق السريعة في كانساس"],"explanation":"في كانساس، تصدر رخصة CDL من قبل وزارة الإيرادات في كانساس (KDOR)، قسم المركبات، التي تنشر أيضًا دليل CDL لكانساس. تتولى KDOT الطرق والتصاريح ولكن ليس ترخيص السائقين. المصدر: صفحة CDL لقسم المركبات لدى Kansas DOR (ksrevenue.gov/dovcdl.html)."},"81":{"q":"قبل أن يتمكن مقدم الطلب في كانساس من إجراء اختبار مهارات CDL، يجب اجتياز اختباري المعرفة والمهارات معًا. ما هما النوعان العامان من الاختبارات اللذان ينص دليل CDL لكانساس على وجوب اجتيازهما للحصول على CDL أو CLP؟","options":["اختبار تحريري واختبار نظر فقط","فحص طبي وتدقيق في السوابق فقط","اختبار إشارات الطريق ودورة قيادة دفاعية","اختبارات المعرفة واختبارات المهارات"],"explanation":"ينص دليل CDL لكانساس على: 'للحصول على CDL أو CLP، يجب اجتياز اختبارات المعرفة والمهارات.' أما فحص النظر والشهادة الطبية فهما متطلبان منفصلان. المصدر: دليل CDL لكانساس، القسم 1.1، 'اختبارات رخصة القيادة التجارية.'"},"82":{"q":"يتكون اختبار مهارات CDL في كانساس من ثلاثة أجزاء يجب إجراؤها بترتيب محدد. أي تسلسل هو الصحيح؟","options":["القيادة على الطريق، ثم فحص المركبة، ثم التحكم الأساسي بالمركبة","فحص المركبة، ثم التحكم الأساسي بالمركبة، ثم القيادة على الطريق","فحص المركبة، ثم القيادة على الطريق، ثم التحكم الأساسي بالمركبة","التحكم الأساسي بالمركبة، ثم القيادة على الطريق، ثم فحص المركبة"],"explanation":"ينص دليل CDL لكانساس على أن اختبار المهارات يتكون من ثلاثة أجزاء - فحص المركبة، والتحكم الأساسي بالمركبة، والقيادة على الطريق - ويجب إجراؤها بهذا الترتيب واجتياز كل منها قبل الانتقال إلى التالي. المصدر: دليل CDL لكانساس، القسم 1.1.2، 'اختبارات المهارات.'"},"83":{"q":"من كم فئة للتصديق الذاتي يجب على مقدم طلب CDL في كانساس أن يختار عند إعلان نوع التجارة التي يعمل فيها؟","options":["خمس","ثلاث","أربع","اثنتين"],"explanation":"تُلزم كانساس مقدمي طلبات/حاملي CDL بالتصديق الذاتي على واحدة من أربع فئات من التجارة. المصدر: دليل CDL لكانساس، القسم 1.2 ('أنواع التجارة الأربعة التي يجب أن تصدّق عليها ذاتيًا') وصفحة معلومات الشهادة الطبية لدى Kansas DOR."},"84":{"q":"أي مما يلي هو إحدى فئات التصديق الذاتي الأربع لـ CDL في كانساس؟","options":["بين الولايات المؤقت","بين الولايات غير المستثنى","بين الولايات المقيّد","فيدرالي معفى"],"explanation":"فئات التصديق الذاتي الأربع في كانساس هي: بين الولايات غير المستثنى، وبين الولايات المستثنى، وداخل الولاية غير المستثنى، وداخل الولاية المستثنى. أما 'المقيّد' و'المؤقت' و'الفيدرالي المعفى' فليست فئات. المصدر: صفحة معلومات الشهادة الطبية لدى Kansas DOR؛ دليل CDL لكانساس القسم 1.2."},"85":{"q":"ماذا يجب على السائق في كانساس الذي يصدّق ذاتيًا بأنه 'بين الولايات غير مستثنى' أن يفعل للحفاظ على حالة طبية 'مصدّقة'؟","options":["حمل نسخة ورقية من فحصه البدني في الكابينة في جميع الأوقات","اجتياز اختبار معرفة إضافي للمكابح الهوائية سنويًا","الحفاظ على شهادة فاحص طبي سارية (بطاقة DOT الطبية)","تجديد رخصة CDL كل سنة بدلًا من كل أربع سنوات"],"explanation":"يجب على السائقين بين الولايات غير المستثنين تقديم شهادة فاحص طبي فيدرالية والحفاظ على سريانها (49 CFR 391.45)، وإلا أصبحوا 'غير مصدّقين' وقد يفقدون رخصة CDL. المصدر: دليل CDL لكانساس، القسم 1.2، متطلبات التوثيق الطبي."},"86":{"q":"اعتبارًا من 2 يونيو 2025، كيف يجب أن تصل شهادة الفاحص الطبي (MEC) لحامل CDL في كانساس إلى قسم المركبات؟","options":["أن يرسلها السائق بالبريد إلى صندوق بريد KDOR في توبيكا","أن يرسلها صاحب عمل السائق بالفاكس إلى KDOR","أن يسلّمها السائق باليد إلى أي محطة فحص للرخص","إلكترونيًا من السجل الوطني للفاحصين الطبيين المعتمدين"],"explanation":"اعتبارًا من 2/6/2025، لم تعد كانساس تقبل شهادات MEC المقدمة من السائق ولم يعد بإمكانها إدخالها يدويًا؛ يجب أن تأتي البيانات المصدّقة إلكترونيًا من السجل الوطني للفاحصين الطبيين المعتمدين (يدخلها الفاحص). المصدر: صفحة معلومات الشهادة الطبية لدى Kansas DOR (ksrevenue.gov/dovmedcertfaq.html)."},"87":{"q":"بموجب عملية كانساس لشهر يونيو 2025، كم من الوقت لدى الفاحص الطبي المعتمد لإدخال شهادة MEC جديدة في السجل الوطني؟","options":["فورًا، قبل أن يغادر السائق المكتب","حتى منتصف ليل اليوم التقويمي التالي","خلال 10 أيام عمل من الفحص","خلال 30 يومًا من الفحص"],"explanation":"تشير كانساس إلى أن لدى الفاحص الطبي مهلة حتى منتصف ليل اليوم التالي لإدخال شهادة MEC في السجل الوطني، الذي تتلقاها كانساس منه بعد ذلك إلكترونيًا. المصدر: صفحة معلومات الشهادة الطبية لدى Kansas DOR."},"88":{"q":"بالنسبة لمقدمي طلبات CDL لأول مرة في كانساس، متى يجب استكمال متطلب التدريب الفيدرالي للسائق المبتدئ (ELDT)؟","options":["خلال 30 يومًا بعد إصدار رخصة CDL","فقط بعد أول مخالفة سير","قبل إجراء اختبار مهارات CDL","قبل تجديد رخصة CDL لأول مرة"],"explanation":"يتطلب ELDT (الساري اعتبارًا من 7 فبراير 2022) تدريبًا نظريًا وعمليًا خلف المقود من مزود مسجّل لدى FMCSA، يُستكمل قبل أن يتمكن مقدم الطلب من إجراء اختبار مهارات CDL. ينطبق هذا المعيار الفيدرالي في كانساس. المصدر: قاعدة ELDT لدى FMCSA (49 CFR Part 380, Subpart F)؛ سجل مزودي التدريب لدى FMCSA."},"89":{"q":"يجب على مقدم طلب CDL المبتدئ في كانساس الحصول على تدريب ELDT المطلوب من مزود مُدرج أين؟","options":["على قائمة المدارس المعتمدة لدى Kansas DOR","على سجل الناقلين لدى دورية الطرق السريعة في كانساس","على السجل الوطني للفاحصين الطبيين المعتمدين","على سجل مزودي التدريب (TPR) لدى FMCSA"],"explanation":"يجب أن يُقدَّم ELDT من مدرسة مُدرجة على سجل مزودي التدريب (TPR) لدى FMCSA؛ ويُبلَّغ عن إتمامه إلكترونيًا إلى FMCSA قبل أن تسمح الولاية باختبار المهارات. المصدر: تدريب السائق المبتدئ لدى FMCSA، سجل مزودي التدريب."},"90":{"q":"الحصول على أي من المصادقات التالية لأول مرة يُفعّل متطلب تدريب ELDT قبل الاختبار؟","options":["تصريح المكابح الهوائية فقط","الركاب (P) أو الحافلة المدرسية (S) أو المواد الخطرة (H)","المزدوجة/الثلاثية (T) فقط","الصهريج (N) فقط"],"explanation":"ينطبق ELDT على مقدمي طلبات CDL لأول مرة، والترقية من الفئة B إلى A، ومصادقات P أو S أو H لأول مرة. أما مصادقات المزدوجة/الثلاثية والصهريج فلا تُفعّل ELDT بمفردها. المصدر: نطاق تطبيق ELDT لدى FMCSA (49 CFR Part 380, Subpart F)."},"91":{"q":"ترقية رخصة CDL من الفئة B الحالية إلى الفئة A في كانساس تتطلب أي خطوة إضافية بموجب قاعدة ELDT الفيدرالية؟","options":["لا شيء إضافي؛ الترقية تلقائية","الاحتفاظ برخصة CDL من الفئة B لمدة خمس سنوات على الأقل أولًا","إعادة اجتياز اختبار المعرفة العامة فقط","استكمال تدريب ELDT للترقية إلى الفئة A قبل اختبار المهارات"],"explanation":"الترقية من الفئة B إلى الفئة A هي إحدى العمليات المشمولة بـ ELDT، لذا يجب على السائق استكمال برنامج تدريب الترقية من مزود مُدرج على TPR قبل إجراء اختبار مهارات الفئة A. المصدر: قاعدة ELDT لدى FMCSA (49 CFR Part 380, Subpart F)."},"92":{"q":"بعد إصدار تصريح CLP لمقدم طلب في كانساس، كم يجب أن ينتظر قبل أن يصبح مؤهلًا لإجراء اختبار مهارات CDL؟","options":["30 يومًا على الأقل","60 يومًا على الأقل","14 يومًا على الأقل","7 أيام على الأقل"],"explanation":"يجب على حامل تصريح CLP الاحتفاظ بالتصريح لمدة 14 يومًا على الأقل قبل إجراء اختبار مهارات CDL. يُطبَّق هذا المتطلب الفيدرالي في كانساس. المصدر: 49 CFR 383.25؛ إرشادات مقدمي طلبات CDL في كانساس."},"93":{"q":"كم مرة يجب تجديد رخصة CDL القياسية في كانساس؟","options":["كل 6 سنوات","كل 8 سنوات","كل سنتين","كل 4 سنوات"],"explanation":"تُصدر رخص CDL في كانساس على دورة مدتها 4 سنوات ويجب تجديدها كل أربع سنوات، بصرف النظر عن دورة الـ 6 سنوات المستخدمة لبعض الرخص غير التجارية في كانساس. المصدر: معلومات الترخيص لدى قسم المركبات في Kansas DOR."},"94":{"q":"ما هو الحد الأدنى للسن للحصول على رخصة CDL في كانساس للعمل داخل الولاية (داخل كانساس فقط)؟","options":["18 عامًا","19 عامًا","21 عامًا","16 عامًا"],"explanation":"يجوز إصدار رخصة CDL في كانساس للعمل داخل الولاية عند سن 18؛ أما العمل بين الولايات (والمواد الخطرة) فيتطلب سن 21. المصدر: دليل CDL لكانساس؛ قواعد تأهيل السائقين لدى FMCSA (49 CFR 391.11)."},"95":{"q":"ما هو الحد الأدنى للسن لتشغيل مركبة تجارية آلية في التجارة بين الولايات برخصة CDL من كانساس؟","options":["25 عامًا","21 عامًا","18 عامًا","23 عامًا"],"explanation":"يتطلب تشغيل المركبة التجارية الآلية بين الولايات، ونقل المواد الخطرة، أن يكون عمر السائق 21 عامًا على الأقل. ويقتصر السائقون من 18 إلى 20 عامًا على العمل داخل الولاية. المصدر: قواعد تأهيل السائقين لدى FMCSA (49 CFR 391.11)؛ إرشادات CDL في كانساس."},"96":{"q":"أي مجموعة من المستندات تعكس على أفضل وجه ما يجب على مقدم الطلب في كانساس تقديمه للتقدم بطلب CLP/CDL؟","options":["جواز سفر فقط، دون اشتراط إثبات الإقامة","إثبات الهوية/تاريخ الميلاد، ورقم الضمان الاجتماعي، والوجود القانوني، وإثباتان للإقامة في كانساس","شهادة الثانوية العامة وخطاب توصية من صاحب عمل","فقط رخصة كانساس غير تجارية سارية وصورة فوتوغرافية"],"explanation":"تشترط كانساس إثبات الهوية/تاريخ الميلاد، وإثبات رقم الضمان الاجتماعي، وإثبات الوجود القانوني، ومستندين يثبتان الإقامة في كانساس (العنوان الفعلي)؛ كما يجب على مقدمي الطلبات أن يكونوا حاملين بالفعل لرخصة قيادة غير تجارية في كانساس. المصدر: متطلبات الطلب لدى قسم المركبات في Kansas DOR."},"97":{"q":"سؤال عن العملية في كانساس حول الرسوم: أي عبارة عن رسوم CDL دقيقة لتعليم مقدمي الطلبات؟","options":["رسم CDL محدد بشكل دائم بموجب قانون كانساس ولا يتغير أبدًا","لا تفرض كانساس أي رسم على CDL أو مصادقاتها","رسوم CDL تُحدَّد فيدراليًا من قبل FMCSA وهي متطابقة في كل ولاية","رسوم CDL والمصادقات تحددها كانساس ويمكن أن تتغير، لذا ينبغي على مقدمي الطلبات التأكد من المبالغ الحالية لدى KDOR"],"explanation":"تُحدَّد رسوم CDL والمصادقات وCLP من قبل الولاية وهي قابلة للتغيير؛ وينبغي على مقدمي الطلبات التحقق من المبالغ الحالية لدى Kansas DOR بدلًا من الاعتماد على رقم ثابت. الرسوم تحددها الولاية وليست موحدة فيدراليًا. المصدر: إرشادات جدول الرسوم لدى قسم المركبات في Kansas DOR."}}};
